window.TRIVIA_DATA = [{"id":"TOS-001","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who is the captain of the USS Enterprise NCC-1701 during the five-year mission?","answers":{"A":"Christopher Pike","B":"James T. Kirk","C":"Robert April","D":"Willard Decker"},"correct":"B","explanation":"James T. Kirk commands the Enterprise throughout the original series' five-year mission (2265-2270), taking over from Christopher Pike."},{"id":"TOS-002","series":"TOS","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Mr. Spock is half human and half Vulcan.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Spock's father Sarek is Vulcan and his mother Amanda Grayson is human, as established in the episode 'Journey to Babel.'"},{"id":"TOS-003","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What is the registry number of Captain Kirk's USS Enterprise?","answers":{"A":"NCC-1864","B":"NX-01","C":"NCC-1701","D":"NCC-1701-A"},"correct":"C","explanation":"The original Enterprise carries registry NCC-1701. The NCC-1701-A is the refit Enterprise commissioned at the end of 'Star Trek IV: The Voyage Home.'"},{"id":"TOS-004","series":"TOS","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Dr. Leonard McCoy is nicknamed 'Bones.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kirk affectionately calls Chief Medical Officer Leonard H. McCoy 'Bones' throughout the series, a nickname derived from the old term 'sawbones' for a doctor."},{"id":"TOS-005","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the Enterprise's chief engineer?","answers":{"A":"Hikaru Sulu","B":"Pavel Chekov","C":"Montgomery Scott","D":"Kevin Riley"},"correct":"C","explanation":"Lt. Commander Montgomery 'Scotty' Scott is the Scottish chief engineer of the Enterprise, played by James Doohan."},{"id":"TOS-006","series":"TOS","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"Vulcans greet others with the phrase 'Live long and prosper.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Vulcan salute is accompanied by 'Live long and prosper,' first used by Spock in the episode 'Amok Time' (1967)."},{"id":"TOS-007","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who is the Enterprise's communications officer?","answers":{"A":"Janice Rand","B":"Christine Chapel","C":"Nyota Uhura","D":"Marla McGivers"},"correct":"C","explanation":"Lt. Uhura serves as communications officer, played by Nichelle Nichols. Her first name 'Nyota' was made canon in the 2009 film."},{"id":"TOS-008","series":"TOS","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"The USS Enterprise is a Constitution-class starship.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The original Enterprise NCC-1701 is a Constitution-class heavy cruiser, the same class as the USS Constellation, Defiant, Exeter, and Intrepid."},{"id":"TOS-009","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who is the helmsman of the Enterprise?","answers":{"A":"Pavel Chekov","B":"Hikaru Sulu","C":"Kevin Riley","D":"DePaul"},"correct":"B","explanation":"Lt. Hikaru Sulu serves as the Enterprise's helmsman, played by George Takei. His first name 'Hikaru' was first given in the novel 'The Entropy Effect' and canonized in 'Star Trek VI.'"},{"id":"TOS-010","series":"TOS","difficulty":"easy","type":"true_false","category":"Quotes & Catchphrases","question":"Dr. McCoy frequently says, 'I'm a doctor, not a...'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"McCoy delivers many variations of 'I'm a doctor, not a (bricklayer/escalator/mechanic/etc.)' throughout the series, becoming one of his signature catchphrases."},{"id":"TOS-011","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the name of Spock's species?","answers":{"A":"Romulan","B":"Vulcan","C":"Andorian","D":"Tellarite"},"correct":"B","explanation":"Spock is Vulcan on his father's side. Vulcans suppress emotion in favor of pure logic, a discipline founded by the philosopher Surak."},{"id":"TOS-012","series":"TOS","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"Klingons are enemies of the Federation during the original series era.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Klingon Empire is a major adversary of the Federation throughout TOS, with peace only achieved after the events of 'Star Trek VI: The Undiscovered Country.'"},{"id":"TOS-013","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is Captain Kirk's middle name?","answers":{"A":"Thomas","B":"Tiberius","C":"Theodore","D":"Tobias"},"correct":"B","explanation":"James Tiberius Kirk's middle name was first revealed in the animated episode 'Bem' and confirmed in 'Star Trek VI: The Undiscovered Country.'"},{"id":"TOS-014","series":"TOS","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"The Enterprise's primary weapons are phasers and photon torpedoes.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Throughout TOS, the Enterprise uses phasers as her energy weapons and photon torpedoes as her ordnance, a configuration that becomes the Starfleet standard."},{"id":"TOS-015","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What small, furry creatures multiply rapidly in 'The Trouble with Tribbles'?","answers":{"A":"Sehlats","B":"Targs","C":"Tribbles","D":"Le-matyas"},"correct":"C","explanation":"Tribbles are small fluffy creatures that reproduce at an alarming rate when fed, overrunning Space Station K-7 in the classic episode 'The Trouble with Tribbles.'"},{"id":"TOS-016","series":"TOS","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Pavel Chekov is the Enterprise's navigator and is from Russia.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Ensign Pavel Andreievich Chekov, played by Walter Koenig, is a proudly Russian navigator who joined the series in season 2."},{"id":"TOS-017","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Villains & Antagonists","question":"What is the name of the genetically engineered superhuman in 'Space Seed'?","answers":{"A":"Khan Noonien Singh","B":"Garth of Izar","C":"Harry Mudd","D":"Anton Karidian"},"correct":"A","explanation":"Khan Noonien Singh, a product of late-20th-century genetic engineering, is found in suspended animation aboard the SS Botany Bay and later returns in 'Star Trek II: The Wrath of Khan.'"},{"id":"TOS-018","series":"TOS","difficulty":"easy","type":"true_false","category":"Quotes & Catchphrases","question":"Spock's traditional Vulcan farewell includes the hand gesture known as the Vulcan salute.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The split-fingered Vulcan salute was created by Leonard Nimoy, who based it on a Jewish priestly blessing he saw as a child. It accompanies 'Live long and prosper.'"},{"id":"TOS-019","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"What rank does James T. Kirk hold during the five-year mission?","answers":{"A":"Commander","B":"Captain","C":"Commodore","D":"Admiral"},"correct":"B","explanation":"Kirk holds the rank of Captain throughout the five-year mission. He is later promoted to Rear Admiral between the events of TOS and 'Star Trek: The Motion Picture.'"},{"id":"TOS-020","series":"TOS","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"The transporter is used to beam crew members between the ship and planet surfaces.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The transporter dematerializes a subject into an energy pattern and rematerializes them at the destination, and is the Enterprise's primary means of short-range crew transfer."},{"id":"TOS-021","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Planets & Locations","question":"What is Spock's home planet?","answers":{"A":"Andoria","B":"Vulcan","C":"Tellar Prime","D":"Rigel V"},"correct":"B","explanation":"Spock was born on Vulcan, a hot desert world orbiting the star 40 Eridani A. His birthplace is depicted in episodes like 'Amok Time' and 'Journey to Babel.'"},{"id":"TOS-022","series":"TOS","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Lt. Uhura speaks Swahili and her name comes from a Swahili word meaning 'freedom.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"'Uhuru' is Swahili for 'freedom'; the name was suggested to Gene Roddenberry by Nichelle Nichols. Uhura speaks Swahili in 'The Man Trap.'"},{"id":"TOS-023","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Quotes & Catchphrases","question":"Which phrase is most associated with Mr. Spock?","answers":{"A":"Make it so.","B":"Engage.","C":"Fascinating.","D":"Set phasers to stun."},"correct":"C","explanation":"Spock's understated 'Fascinating' is his go-to response to unusual phenomena throughout the series, reflecting his Vulcan intellectual curiosity."},{"id":"TOS-024","series":"TOS","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"Vulcans have green blood because their blood is copper-based rather than iron-based.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Vulcan blood uses copper-based hemocyanin instead of iron-based hemoglobin, giving it a green color. This was first established in TOS and referenced in many episodes."},{"id":"TOS-025","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who plays Captain James T. Kirk?","answers":{"A":"Leonard Nimoy","B":"DeForest Kelley","C":"William Shatner","D":"James Doohan"},"correct":"C","explanation":"Canadian actor William Shatner portrayed Captain James T. Kirk across the original series, the animated series, and the first seven feature films."},{"id":"TOS-026","series":"TOS","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"Warp drive allows starships to travel faster than the speed of light.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Warp drive creates a subspace field that distorts space-time, allowing the Enterprise to exceed light speed. Maximum safe cruising speed in TOS is around warp 6 to warp 8."},{"id":"TOS-027","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"Which episode introduces Khan Noonien Singh?","answers":{"A":"The Doomsday Machine","B":"Space Seed","C":"Mirror, Mirror","D":"The Enterprise Incident"},"correct":"B","explanation":"Khan and his followers are discovered in cryogenic sleep aboard the SS Botany Bay in the season 1 episode 'Space Seed,' setting up the events of 'Star Trek II.'"},{"id":"TOS-028","series":"TOS","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Scotty often refers to the Enterprise as a 'she.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Following Starfleet and naval tradition, Scotty consistently refers to the Enterprise with feminine pronouns and treats her with deep personal affection."},{"id":"TOS-029","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"What organization does the Enterprise serve?","answers":{"A":"United Earth Space Probe Agency","B":"Starfleet","C":"The Klingon Defense Force","D":"The Maquis"},"correct":"B","explanation":"The Enterprise is a Starfleet vessel operating under the United Federation of Planets. Starfleet is the Federation's combined exploration, scientific, and defense service."},{"id":"TOS-030","series":"TOS","difficulty":"easy","type":"true_false","category":"Quotes & Catchphrases","question":"The original series opening narration includes the phrase 'to boldly go where no man has gone before.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kirk's iconic opening monologue ends with 'to boldly go where no man has gone before.' TNG later updated this to 'no one has gone before.'"},{"id":"TOS-031","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who plays Mr. Spock in the original series?","answers":{"A":"Mark Lenard","B":"Leonard Nimoy","C":"Walter Koenig","D":"George Takei"},"correct":"B","explanation":"Leonard Nimoy created the iconic role of Spock, playing him across TOS, TAS, the original cast films, and reprising the role in the 2009 reboot and 'Star Trek Into Darkness.'"},{"id":"TOS-032","series":"TOS","difficulty":"easy","type":"true_false","category":"Villains & Antagonists","question":"Romulans are biologically related to Vulcans.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Balance of Terror,' the Romulans are revealed to share common ancestry with Vulcans, having branched off thousands of years earlier and rejected Surak's teachings of logic."},{"id":"TOS-033","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Planets & Locations","question":"What is the capital planet of the United Federation of Planets?","answers":{"A":"Vulcan","B":"Earth","C":"Andoria","D":"Tellar Prime"},"correct":"B","explanation":"Earth, and specifically San Francisco, serves as the headquarters of Starfleet Command and the seat of the Federation Council."},{"id":"TOS-034","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The City on the Edge of Forever,' what is the name of the social worker Kirk falls in love with in 1930s Earth?","answers":{"A":"Edith Keeler","B":"Areel Shaw","C":"Carol Marcus","D":"Janice Lester"},"correct":"A","explanation":"Edith Keeler, played by Joan Collins, runs a 1930s soup kitchen. Kirk must allow her to die in a traffic accident to preserve the timeline, as her pacifist movement would have delayed U.S. entry into WWII."},{"id":"TOS-035","series":"TOS","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"Vulcan pon farr, the mating drive, occurs every seven years.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Pon farr afflicts Vulcan males every seven years, as established in 'Amok Time.' Spock must return to Vulcan to mate or die."},{"id":"TOS-036","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Mirror, Mirror,' how can you tell Mirror Spock apart from the prime universe Spock?","answers":{"A":"A scar across his face","B":"A goatee/beard","C":"An eyepatch","D":"A shaved head"},"correct":"B","explanation":"Mirror Spock sports a goatee, which became such an iconic visual shorthand that 'evil twin with a goatee' is now a widely recognized trope."},{"id":"TOS-037","series":"TOS","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"'The Menagerie' is the only two-part episode in the original series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"'The Menagerie, Parts I and II' is TOS's only two-part episode. It cleverly incorporates footage from the original unaired pilot 'The Cage' featuring Captain Pike."},{"id":"TOS-038","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"In 'The Doomsday Machine,' what is the planet killer made of?","answers":{"A":"Tritanium","B":"Pure neutronium","C":"Duranium","D":"Latinum"},"correct":"B","explanation":"Spock's scans determine the doomsday machine's hull is composed of solid neutronium, making it virtually indestructible to the Enterprise's weapons."},{"id":"TOS-039","series":"TOS","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Spock's father, Sarek, is the Vulcan ambassador to the Federation.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Sarek, played by Mark Lenard, is a distinguished Vulcan ambassador. He is introduced in 'Journey to Babel' and appears in later TNG episodes as well."},{"id":"TOS-040","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Amok Time,' who is Spock's betrothed?","answers":{"A":"T'Pol","B":"T'Pring","C":"T'Pau","D":"Saavik"},"correct":"B","explanation":"T'Pring is the Vulcan female bonded to Spock as a child. She invokes the kal-if-fee challenge, forcing Spock and Kirk to fight."},{"id":"TOS-041","series":"TOS","difficulty":"medium","type":"true_false","category":"Ships & Technology","question":"Khan's ship from 'Space Seed' is named the SS Botany Bay.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The SS Botany Bay is a DY-100-class sleeper ship that left Earth in 1996 carrying Khan and his fellow Augments fleeing the Eugenics Wars."},{"id":"TOS-042","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"What does the Vulcan philosophical principle IDIC stand for?","answers":{"A":"Infinite Duty in Constant Crisis","B":"Infinite Diversity in Infinite Combinations","C":"Individual Devotion to Inner Calm","D":"Intuition, Discipline, Intellect, Compassion"},"correct":"B","explanation":"IDIC, 'Infinite Diversity in Infinite Combinations,' is a core Vulcan philosophical principle, first referenced on screen in 'Is There in Truth No Beauty?'"},{"id":"TOS-043","series":"TOS","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Who Mourns for Adonais?,' the Enterprise encounters the Greek god Apollo.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The crew encounters Apollo on the planet Pollux IV, the last surviving member of a powerful alien race that ancient Greeks worshipped as gods."},{"id":"TOS-044","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"What name was given to the planet killer's commanding officer who rammed his shuttlecraft into it?","answers":{"A":"Commodore Matt Decker","B":"Commodore Stocker","C":"Captain Tracey","D":"Commodore Wesley"},"correct":"A","explanation":"Commodore Matt Decker, commander of the USS Constellation, sacrifices himself by piloting a shuttle into the planet killer's maw in 'The Doomsday Machine.'"},{"id":"TOS-045","series":"TOS","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"The Organians forced peace between the Federation and the Klingon Empire.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Errand of Mercy,' the seemingly primitive Organians reveal themselves as energy beings of immense power and impose the Organian Peace Treaty between the two powers."},{"id":"TOS-046","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"Where are Khan and his followers exiled at the end of 'Space Seed'?","answers":{"A":"Rura Penthe","B":"Ceti Alpha V","C":"Tantalus V","D":"Elba II"},"correct":"B","explanation":"Kirk maroons Khan on Ceti Alpha V at the conclusion of 'Space Seed.' Years later in 'Wrath of Khan,' Khan recounts how the neighboring planet Ceti Alpha VI exploded, devastating the world."},{"id":"TOS-047","series":"TOS","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"Captain Christopher Pike was severely injured by delta ray exposure during a training accident.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'The Menagerie,' it is established that Pike was exposed to delta radiation while rescuing cadets from a baffle plate rupture aboard an old J-class training vessel, leaving him paralyzed and disfigured."},{"id":"TOS-048","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"Who plays Nurse Christine Chapel?","answers":{"A":"Grace Lee Whitney","B":"Majel Barrett","C":"Bibi Besch","D":"Kim Cattrall"},"correct":"B","explanation":"Majel Barrett played Nurse Chapel as well as Number One in 'The Cage' and later voiced the Enterprise computer. She was married to Gene Roddenberry."},{"id":"TOS-049","series":"TOS","difficulty":"medium","type":"true_false","category":"Ships & Technology","question":"The Klingon D7-class battle cruiser is the primary Klingon warship encountered in TOS.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The D7 battle cruiser, designed by Matt Jefferies, is the iconic Klingon warship of the TOS era, appearing in episodes like 'Elaan of Troyius' and 'Day of the Dove.'"},{"id":"TOS-050","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Arena,' what reptilian species' captain does Kirk fight in single combat?","answers":{"A":"Cardassian","B":"Gorn","C":"Tholian","D":"Saurian"},"correct":"B","explanation":"Kirk battles the Gorn captain on a barren planet, with both crews observing. The Metrons, the powerful race that arranged the duel, set up the contest after the Gorn destroyed a Federation outpost on Cestus III."},{"id":"TOS-051","series":"TOS","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Kirk has a brother named George Samuel Kirk who appears in the series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kirk's brother Sam appears (deceased) in 'Operation: Annihilate!' He died from neural parasites on Deneva, leaving behind a widow and son. William Shatner played Sam in flashback/dead form."},{"id":"TOS-052","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Quotes & Catchphrases","question":"Which famous TOS line is most closely associated with Scotty?","answers":{"A":"She cannae take much more, Captain!","B":"Make it so!","C":"I'll be in my ready room.","D":"Set course for the neutral zone."},"correct":"A","explanation":"Scotty's exasperated engineering warnings about the ship's structural limits became one of his signature catchphrases throughout TOS and the films."},{"id":"TOS-053","series":"TOS","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"Captain Pike was the original captain of the Enterprise before Kirk.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Captain Christopher Pike commanded the Enterprise for over a decade before turning her over to Kirk. His era is depicted in 'The Cage,' 'The Menagerie,' and later in 'Strange New Worlds.'"},{"id":"TOS-054","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"In 'The Devil in the Dark,' what is the Horta made of?","answers":{"A":"Carbon","B":"Silicon","C":"Liquid metal","D":"Pure energy"},"correct":"B","explanation":"The Horta is a silicon-based life form on Janus VI. Initially attacking miners who were unknowingly destroying her eggs, she communicates with Spock via a mind meld, etching 'NO KILL I' in stone."},{"id":"TOS-055","series":"TOS","difficulty":"medium","type":"true_false","category":"Crossovers & Connections","question":"Sarek, Spock's father, also appears in 'Star Trek: The Next Generation.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Mark Lenard reprised his role as Sarek in the TNG episodes 'Sarek' and 'Unification, Part I,' bridging the two series."},{"id":"TOS-056","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Balance of Terror,' what is significant about the Romulan encounter?","answers":{"A":"It is the first peace treaty between the Federation and Romulans","B":"It is the first time the Federation sees a Romulan face-to-face","C":"It marks the Romulans joining the Federation","D":"It introduces Romulan ale"},"correct":"B","explanation":"Although the Earth-Romulan War occurred a century earlier, 'Balance of Terror' depicts the first visual contact with Romulans, revealing their physical resemblance to Vulcans."},{"id":"TOS-057","series":"TOS","difficulty":"medium","type":"true_false","category":"Quotes & Catchphrases","question":"The exact line 'Beam me up, Scotty' is never actually spoken in any episode of the original series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Despite its fame, the precise phrase 'Beam me up, Scotty' was never uttered in TOS. Variations like 'Scotty, beam us up' and 'Beam us up, Mr. Scott' do appear."},{"id":"TOS-058","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"Who is the recurring rogue/conman who appears in 'Mudd's Women' and 'I, Mudd'?","answers":{"A":"Cyrano Jones","B":"Harcourt Fenton Mudd","C":"Garth of Izar","D":"Kor"},"correct":"B","explanation":"Harcourt Fenton 'Harry' Mudd, played by Roger C. Carmel, is a lovable rogue who appears in 'Mudd's Women,' 'I, Mudd,' and the animated 'Mudd's Passion.'"},{"id":"TOS-059","series":"TOS","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"The Tholians construct a geometric energy web around the Enterprise in 'The Tholian Web.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Two Tholian ships weave a glowing energy web around the Enterprise after Kirk vanishes into an interphase zone, a slow-motion siege that gives the episode its name."},{"id":"TOS-060","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Trouble with Tribbles,' what grain were the tribbles eating?","answers":{"A":"Plomeek","B":"Quadrotriticale","C":"Saurian wheat","D":"Klingon barley"},"correct":"B","explanation":"The tribbles feasted on quadrotriticale, a four-lobed hybrid wheat-rye grain meant for Sherman's Planet. Klingons had poisoned the supply, which the tribbles helped expose by dying upon contact."},{"id":"TOS-061","series":"TOS","difficulty":"medium","type":"true_false","category":"Crossovers & Connections","question":"'Star Trek: Deep Space Nine' revisited 'The Trouble with Tribbles' in the episode 'Trials and Tribble-ations.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The DS9 30th-anniversary episode 'Trials and Tribble-ations' digitally inserted DS9 cast members into footage from the original 'Trouble with Tribbles' episode."},{"id":"TOS-062","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Ships & Technology","question":"What test does every Starfleet command cadet famously fail except Kirk?","answers":{"A":"The Kessik Maneuver","B":"The Kobayashi Maru","C":"The Picard Maneuver","D":"The Sulu Solution"},"correct":"B","explanation":"The Kobayashi Maru is a no-win simulation. Kirk reprogrammed it to allow victory, earning a commendation for original thinking, as revealed in 'Star Trek II: The Wrath of Khan.'"},{"id":"TOS-063","series":"TOS","difficulty":"medium","type":"true_false","category":"Starfleet Ranks & Protocol","question":"The Prime Directive forbids Starfleet personnel from interfering with the natural development of pre-warp civilizations.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Starfleet's General Order 1, the Prime Directive, is invoked many times in TOS, notably in episodes like 'A Private Little War' and 'The Apple.'"},{"id":"TOS-064","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What is Sulu's hobby that he shows off in 'The Naked Time'?","answers":{"A":"Painting","B":"Fencing","C":"Botany","D":"Piano"},"correct":"B","explanation":"Under the influence of the inhibition-stripping water-borne contaminant in 'The Naked Time,' Sulu strips to the waist and chases crewmates around the ship with a fencing foil, imagining himself as a swashbuckler."},{"id":"TOS-065","series":"TOS","difficulty":"medium","type":"true_false","category":"Villains & Antagonists","question":"The Klingons appearing in the original series have smooth foreheads rather than the ridged appearance seen in later series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"TOS-era Klingons had smooth foreheads due to budget limitations. The discrepancy was later canonically explained as the result of a 22nd-century Augment virus in Enterprise episodes 'Affliction' and 'Divergence.'"},{"id":"TOS-066","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"What is the name of the space station where 'The Trouble with Tribbles' takes place?","answers":{"A":"Deep Space 9","B":"Space Station K-7","C":"Regula I","D":"Starbase 11"},"correct":"B","explanation":"Space Station K-7, near Sherman's Planet and the Klingon border, hosts the diplomatic incident, the brawl, and the tribble infestation in the classic episode."},{"id":"TOS-067","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of Spock's mother?","answers":{"A":"T'Pau","B":"Amanda Grayson","C":"Perrin","D":"T'Lar"},"correct":"B","explanation":"Amanda Grayson, played by Jane Wyatt in TOS and the films, is Spock's human mother. She first appears in 'Journey to Babel.'"},{"id":"TOS-068","series":"TOS","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'The Enterprise Incident,' Spock pretends to defect to the Romulans to steal their cloaking device.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kirk and Spock execute a covert Federation operation to steal a Romulan cloaking device. Spock romances the Romulan commander as part of the ruse."},{"id":"TOS-069","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Menagerie,' to what planet does Spock illegally transport the disabled Captain Pike?","answers":{"A":"Rigel VII","B":"Talos IV","C":"Vulcan","D":"Janus VI"},"correct":"B","explanation":"Spock hijacks the Enterprise to bring Pike to Talos IV, the one planet under General Order 7 with a death penalty. The illusion-casting Talosians give Pike a happy mental life with Vina."},{"id":"TOS-070","series":"TOS","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"The Klingon word 'qapla'' translates as 'success.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"'qapla'' is the Klingon word for 'success,' used as a farewell or congratulation. It is distinct from 'quv' (honor) and 'batlh' (honor, with implications of dignity)."},{"id":"TOS-071","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"Who served as the Enterprise's first officer during 'The Cage' (the original pilot)?","answers":{"A":"Mr. Spock","B":"Number One","C":"Jose Tyler","D":"Philip Boyce"},"correct":"B","explanation":"'Number One,' played by Majel Barrett, served as Pike's first officer in 'The Cage.' Footage of her appears in 'The Menagerie,' and she was later named Una Chin-Riley in 'Strange New Worlds.'"},{"id":"TOS-072","series":"TOS","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'The Galileo Seven,' Spock commands a shuttle crew stranded on a planet, his first command experience.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Spock leads the shuttle crew on Taurus II against hostile giant ape-like aliens. The episode is a defining moment showing Spock learning that logical command must sometimes incorporate intuition."},{"id":"TOS-073","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"In 'Star Trek II: The Wrath of Khan,' what device does Khan steal and try to use as a weapon?","answers":{"A":"The Doomsday Machine","B":"The Genesis Device","C":"The Omega Particle","D":"The Guardian of Forever"},"correct":"B","explanation":"The Genesis Device, developed by Dr. Carol Marcus and her son David, is designed to instantly terraform dead worlds. Khan seizes it from Regula I station to use against Kirk."},{"id":"TOS-074","series":"TOS","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Kirk's son David Marcus is killed by Klingons in 'Star Trek III: The Search for Spock.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"David is murdered on the Genesis planet by one of Commander Kruge's Klingons, while protecting Saavik and the regenerated young Spock."},{"id":"TOS-075","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"In 'Star Trek IV: The Voyage Home,' what species must the crew bring forward in time to save Earth?","answers":{"A":"Bottlenose dolphins","B":"Humpback whales","C":"Blue whales","D":"Bald eagles"},"correct":"B","explanation":"The crew time-travels to 1986 San Francisco to retrieve two humpback whales (George and Gracie), the only species that can answer the destructive probe threatening Earth."},{"id":"TOS-076","series":"TOS","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Spock's Brain,' Spock's brain is literally removed and used to operate a planet's life-support systems.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The infamous season 3 opener has Kara surgically remove Spock's brain to serve as the controller of an underground complex on Sigma Draconis VI. McCoy operates a remote-control device to walk Spock's body."},{"id":"TOS-077","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Villains & Antagonists","question":"What Klingon, played by John Colicos, debuts as the Klingon governor in 'Errand of Mercy' and decades later returns on 'Deep Space Nine'?","answers":{"A":"Kang","B":"Kor","C":"Koloth","D":"Kruge"},"correct":"B","explanation":"Kor, played by John Colicos, debuts as the Klingon governor in 'Errand of Mercy.' Colicos reprised the role decades later in 'Star Trek: Deep Space Nine.'"},{"id":"TOS-078","series":"TOS","difficulty":"hard","type":"true_false","category":"Crossovers & Connections","question":"In 'Star Trek VI: The Undiscovered Country,' the Klingon moon Praxis explodes, triggering a crisis that leads to a peace treaty.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The explosion of Praxis, the Klingons' primary energy production facility, cripples the Empire and leads to the Khitomer Accords, which the conspirators try to derail by assassinating Chancellor Gorkon."},{"id":"TOS-079","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"Which TOS race, a founding member of the Federation, is known for being gruff and argumentative?","answers":{"A":"Andorians","B":"Tellarites","C":"Bolians","D":"Vulcans"},"correct":"B","explanation":"Tellarites, one of the four founding species of the Federation alongside Humans, Vulcans, and Andorians, are characterized as gruff and argumentative. They appear notably in 'Journey to Babel.'"},{"id":"TOS-080","series":"TOS","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"The pacifist Halkans, who refuse to share dilithium with the Federation, appear in 'Mirror, Mirror.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Both the prime and Mirror Universe storylines of 'Mirror, Mirror' revolve around negotiating with the Halkans for dilithium mining rights, which they refuse on ethical grounds."},{"id":"TOS-081","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"Which yeoman, played by Grace Lee Whitney, appeared in early season 1 episodes and later in 'Star Trek IV' and 'Star Trek VI'?","answers":{"A":"Tonia Barrows","B":"Janice Rand","C":"Mira Romaine","D":"Martha Landon"},"correct":"B","explanation":"Yeoman Janice Rand appeared in season 1 of TOS and returned in 'The Motion Picture,' 'The Voyage Home,' 'The Undiscovered Country,' and on 'Voyager' as Commander Rand."},{"id":"TOS-082","series":"TOS","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"The Guardian of Forever is a time portal introduced in 'The City on the Edge of Forever.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Guardian of Forever is a sentient, ring-shaped portal capable of showing and accessing any moment in history. McCoy accidentally goes through and alters the timeline before Kirk and Spock follow him."},{"id":"TOS-083","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Planets & Locations","question":"On what planet does Khan's expedition find itself stranded between 'Space Seed' and 'Wrath of Khan,' after a catastrophic event?","answers":{"A":"Ceti Alpha V, after Ceti Alpha VI explodes","B":"Tarsus IV, after a famine","C":"Nimbus III, after civil war","D":"Rura Penthe, after a prison break"},"correct":"A","explanation":"Six months after the Botany Bay survivors settled on Ceti Alpha V, the sixth planet exploded, shifting Ceti Alpha V's orbit and turning it into a hellish wasteland, as Khan describes to Chekov in 'Wrath of Khan.'"},{"id":"TOS-084","series":"TOS","difficulty":"hard","type":"true_false","category":"Starfleet Ranks & Protocol","question":"Starfleet's General Order 7, in effect during TOS, forbids contact with Talos IV under penalty of death.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"General Order 7 makes Talos IV the only world to which travel is punishable by death, a fact central to the trial in 'The Menagerie.'"},{"id":"TOS-085","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'A Piece of the Action,' the Iotians model their society on what 20th-century Earth book left by a previous starship?","answers":{"A":"A book on Nazi Germany","B":"A book on Chicago Mobs of the Twenties","C":"A book on the Roman Empire","D":"A book on the American Revolution"},"correct":"B","explanation":"The Iotians, a culturally imitative people, modeled their entire civilization on a book about 1920s Chicago gangsters accidentally left behind by the USS Horizon a century earlier."},{"id":"TOS-086","series":"TOS","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"The USS Defiant, lost in 'The Tholian Web,' is the same ship that later appears on 'Star Trek: Enterprise' in the Mirror Universe two-parter 'In a Mirror, Darkly.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Constitution-class USS Defiant slipped through an interphase rift in 'The Tholian Web' and traveled back in time to the Mirror Universe, where it was captured by Mirror humans in 'In a Mirror, Darkly.'"},{"id":"TOS-087","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"Carol Marcus, Kirk's former lover and David's mother, is a leading scientist on what project?","answers":{"A":"Project Pathfinder","B":"The Genesis Project","C":"Project Daedalus","D":"Project Khitomer"},"correct":"B","explanation":"Dr. Carol Marcus heads the Genesis Project, developing a terraforming device on Regula I that becomes central to 'Star Trek II: The Wrath of Khan.'"},{"id":"TOS-088","series":"TOS","difficulty":"hard","type":"true_false","category":"Quotes & Catchphrases","question":"Spock's final words to Kirk in 'The Wrath of Khan' are 'I have been, and always shall be, your friend. Live long and prosper.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"After sacrificing himself to repair the warp drive in the irradiated engine room, Spock delivers this famous farewell to Kirk through the glass partition in one of Trek's most iconic scenes."},{"id":"TOS-089","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Corbomite Maneuver,' what alien commander first appears as a fearsome ogre but is revealed to be a small child-like being?","answers":{"A":"Trelane","B":"Balok","C":"Charlie X","D":"Gary Mitchell"},"correct":"B","explanation":"Balok, commander of the First Federation flagship Fesarius, projects a terrifying image but is actually a small humanoid played by Clint Howard. The episode introduces Kirk's 'corbomite' bluff tactic."},{"id":"TOS-090","series":"TOS","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"Kolinahr is the Vulcan discipline by which one purges all remaining emotions to achieve pure logic.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kolinahr is first depicted in 'Star Trek: The Motion Picture,' where Spock undergoes the ritual on Vulcan but fails to complete it after sensing V'Ger's consciousness."},{"id":"TOS-091","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Villains & Antagonists","question":"In 'Whom Gods Destroy,' what former Starfleet captain, now in an asylum on Elba II, has gained the power to change his appearance?","answers":{"A":"Ron Tracey","B":"Garth of Izar","C":"Matt Decker","D":"John Christopher"},"correct":"B","explanation":"Garth of Izar, a once-legendary Starfleet captain studied at the Academy, is committed to the Elba II asylum after acquiring cellular shape-shifting abilities and going insane."},{"id":"TOS-092","series":"TOS","difficulty":"hard","type":"true_false","category":"Crossovers & Connections","question":"In 'Star Trek III: The Search for Spock,' the USS Enterprise is destroyed by Kirk's self-destruct command.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kirk activates the auto-destruct to take out boarding Klingons. The Enterprise NCC-1701 burns up in the Genesis planet's atmosphere, a moment Kirk describes as 'the most painful sight of my life.'"},{"id":"TOS-093","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"By what year (Earth calendar) is the United Federation of Planets officially founded in established canon?","answers":{"A":"2063","B":"2151","C":"2161","D":"2245"},"correct":"C","explanation":"The Federation is founded in 2161, following the events of 'Star Trek: Enterprise.' The five-year mission of Kirk's Enterprise runs from 2265 to 2270."},{"id":"TOS-094","series":"TOS","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Saavik, who appears in 'The Wrath of Khan,' 'The Search for Spock,' and 'The Voyage Home,' is described as being part Romulan in some sources.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Although the films present her as Vulcan, scripts and novels established Saavik as half-Romulan. The reference was cut from the final theatrical versions but persists in supplemental materials."},{"id":"TOS-095","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Journey to Babel,' what is the diplomatic conference about?","answers":{"A":"The Khitomer Accords","B":"Whether to admit Coridan into the Federation","C":"Dilithium mining on Halka","D":"The Romulan Neutral Zone"},"correct":"B","explanation":"The Enterprise transports ambassadors, including Sarek, to a Federation council session on the admission of Coridan, a dilithium-rich world whose membership is opposed by several parties."},{"id":"TOS-096","series":"TOS","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'The Conscience of the King,' Kirk investigates a Shakespearean actor he suspects is the genocidal Kodos the Executioner.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Anton Karidian, leader of a traveling Shakespearean company, is suspected of being Kodos, who ordered the massacre of 4,000 colonists on Tarsus IV when Kirk was a teenager and a witness."},{"id":"TOS-097","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"What is the name of the doomed sister ship discovered derelict in 'The Doomsday Machine'?","answers":{"A":"USS Defiant","B":"USS Constellation","C":"USS Exeter","D":"USS Intrepid"},"correct":"B","explanation":"The Constitution-class USS Constellation, commanded by Commodore Matt Decker, is found gutted after an encounter with the planet killer. Decker uses her to ram and disable the machine."},{"id":"TOS-098","series":"TOS","difficulty":"hard","type":"true_false","category":"Quotes & Catchphrases","question":"Kirk's eulogy for Spock in 'The Wrath of Khan' includes the line, 'Of all the souls I have encountered in my travels, his was the most... human.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kirk delivers this eulogy during Spock's funeral aboard the Enterprise before his torpedo casket is launched toward the newly formed Genesis planet."},{"id":"TOS-099","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"Which TOS-era Klingon captain reappears decades later on 'Deep Space Nine' alongside Kor and Kang in the episode 'Blood Oath'?","answers":{"A":"Kruge","B":"Koloth","C":"Chang","D":"Gowron"},"correct":"B","explanation":"Koloth, originally seen in 'The Trouble with Tribbles,' reunites with Kor and Kang on DS9 in 'Blood Oath' to fulfill an oath of vengeance against the Albino."},{"id":"TOS-100","series":"TOS","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"In 'Star Trek II: The Wrath of Khan,' Spock transfers his katra (living spirit) into Dr. McCoy before sacrificing himself.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Just before entering the radiation-flooded engine room, Spock performs a mind meld on McCoy and says 'Remember,' depositing his katra into Bones. This sets up the plot of 'Star Trek III: The Search for Spock.'"},{"id":"TOS-101","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Which actor originated the role of Captain James T. Kirk in The Original Series?","answers":{"A":"Leonard Nimoy","B":"DeForest Kelley","C":"William Shatner","D":"James Doohan"},"correct":"C","explanation":"William Shatner played Kirk across all three TOS seasons (1966-1969) and reprised the role in seven feature films, ending with Star Trek: Generations (1994)."},{"id":"TOS-102","series":"TOS","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"Klingons in The Original Series have smooth foreheads, without the cranial ridges featured in later series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Original budget constraints produced ridgeless Klingons; the franchise later canonized this in Enterprise's 'Affliction'/'Divergence' (2005) via an Augment virus that affected one generation of Klingons."},{"id":"TOS-103","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"Besides phasers, what is the Enterprise's primary directed-energy/explosive weapon?","answers":{"A":"Disruptor cannons","B":"Photon torpedoes","C":"Tricobalt devices","D":"Plasma mortars"},"correct":"B","explanation":"Photon torpedoes are the Enterprise's standard heavy munition throughout TOS. Disruptors are Klingon/Romulan weapons; tricobalt devices appear much later in Voyager-era stories."},{"id":"TOS-104","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Naked Time,' a contagion strips away inhibitions. What memorable behavior does Sulu exhibit?","answers":{"A":"Sings opera in Engineering","B":"Confesses his love for Uhura","C":"Strips to the waist and roams the corridors with a fencing foil","D":"Cries uncontrollably on the bridge"},"correct":"C","explanation":"Sulu's shirtless fencing scene became one of TOS's most iconic comedic moments; George Takei was an avid fencer in real life and reportedly relished the chance to perform it."},{"id":"TOS-105","series":"TOS","difficulty":"medium","type":"true_false","category":"Quotes & Catchphrases","question":"Dr. McCoy's recurring exasperated catchphrase begins 'I'm a doctor, not a...'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"McCoy uses this construction across many episodes, completing it with 'bricklayer,' 'engineer,' 'mechanic,' 'escalator,' and more. The format has been parodied across the entire franchise."},{"id":"TOS-106","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"In 'Mirror, Mirror,' how do Kirk and the landing party first visually distinguish the mirror-universe Spock from their own?","answers":{"A":"He wears Vulcan ceremonial robes","B":"He has a goatee/beard","C":"His ears are noticeably pointier","D":"He has a scar across his face"},"correct":"B","explanation":"Mirror-Spock's neatly trimmed goatee became the most enduring visual shorthand for an evil counterpart in pop culture, originating the 'evil goatee' trope."},{"id":"TOS-107","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"In 'The Doomsday Machine,' what is the ultimate fate of the USS Constellation?","answers":{"A":"It is captured by Klingons","B":"It escapes to deep space at maximum warp","C":"It is salvaged and refit by the Enterprise","D":"Kirk overloads its impulse engines and rams it down the planet-killer's maw, destroying the weapon"},"correct":"D","explanation":"After Commodore Decker's earlier suicide run only stunned the machine, Kirk used the gutted Constellation as a much larger antimatter bomb, finally destroying the planet-killer."},{"id":"TOS-108","series":"TOS","difficulty":"hard","type":"true_false","category":"Crossovers & Connections","question":"The TOS episode 'Plato's Stepchildren' featured one of the first scripted interracial kisses on American network television.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The 1968 episode shows Kirk and Uhura forced to kiss by telekinetic aliens. NBC affiliates were anxious about Southern markets, but the scene aired nationally without significant boycott."},{"id":"TOS-109","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"Which figure from Earth mythology, revealed to be a powerful alien, demands worship from the Enterprise crew on Pollux IV?","answers":{"A":"Zeus","B":"Apollo","C":"Hermes","D":"Ares"},"correct":"B","explanation":"In 'Who Mourns for Adonais?' Apollo claims to be the last of the ancient 'gods' (advanced aliens who visited Earth in antiquity) and demands the crew's devotion before they finally outwit him."},{"id":"TOS-110","series":"TOS","difficulty":"hard","type":"true_false","category":"Timeline & History","question":"TOS originally places the Eugenics Wars and Khan Noonien Singh's tyrannical rule of Earth in the 1990s.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Space Seed,' Khan is described as having ruled more than a quarter of Earth from 1992 to 1996. Later productions retconned these wars as covert, but the explicit dating is preserved in dialogue and in Wrath of Khan."},{"id":"TOS-111","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What handheld device does the Enterprise crew use to scan and analyze their surroundings?","answers":{"A":"Tricorder","B":"PADD","C":"Hyperspanner","D":"Isolinear chip"},"correct":"A","explanation":"The tricorder is the multipurpose handheld sensor-recorder used throughout TOS for scientific, medical, and engineering scans; McCoy carries a specialized medical version."},{"id":"TOS-112","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What crystalline mineral powers the warp engines of the Enterprise?","answers":{"A":"Latinum","B":"Dilithium","C":"Trilithium","D":"Topaline"},"correct":"B","explanation":"Dilithium crystals regulate the matter/antimatter reaction that powers warp drive, making them a critical and much-sought resource throughout TOS, as in 'Mirror, Mirror' and 'Elaan of Troyius.'"},{"id":"TOS-113","series":"TOS","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Dr. McCoy is the Enterprise's chief medical officer.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Leonard 'Bones' McCoy serves as the Enterprise's chief medical officer throughout the five-year mission, running sickbay with Nurse Chapel's assistance."},{"id":"TOS-114","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What small flip-open device does the crew use for ship-to-shore voice communication?","answers":{"A":"Communicator","B":"Combadge","C":"Subspace transceiver","D":"Viewscreen"},"correct":"A","explanation":"The handheld flip communicator is the standard personal communication device of the TOS era; its flip-open design famously inspired later clamshell mobile phones."},{"id":"TOS-115","series":"TOS","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Spock serves as both the Enterprise's first officer and its science officer.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Spock holds the dual role of first officer and chief science officer under Captain Kirk, the second-in-command who also runs the ship's scientific operations."},{"id":"TOS-116","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Quotes & Catchphrases","question":"Which short order does Kirk most famously give to take the Enterprise to warp?","answers":{"A":"Engage.","B":"Punch it.","C":"Ahead warp factor one.","D":"Hit it."},"correct":"C","explanation":"Kirk's typical command to go to warp is a variation of 'Ahead, warp factor one' (or a higher factor). 'Engage' is Captain Picard's signature line in The Next Generation."},{"id":"TOS-117","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the typical color of Vulcan skin tone often associated with their copper-based blood?","answers":{"A":"Blue","B":"A greenish or yellowish tint","C":"Bright red","D":"Grey"},"correct":"B","explanation":"Because Vulcan blood is copper-based and green, Vulcans are often depicted with a slightly greenish or yellowish complexion, a detail referenced in TOS makeup and dialogue."},{"id":"TOS-118","series":"TOS","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"Andorians are a blue-skinned species with antennae, and they are among the founding members of the Federation.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Andorians, blue-skinned humanoids with cranial antennae, are one of the Federation's founding species and appear in TOS in 'Journey to Babel' as part of the diplomatic delegation."},{"id":"TOS-119","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who plays Dr. Leonard 'Bones' McCoy in The Original Series?","answers":{"A":"James Doohan","B":"DeForest Kelley","C":"Walter Koenig","D":"Mark Lenard"},"correct":"B","explanation":"DeForest Kelley portrayed Dr. McCoy across all three TOS seasons and the original-cast films, completing the central Kirk-Spock-McCoy trio."},{"id":"TOS-120","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What setting allows a phaser to incapacitate a target without killing it?","answers":{"A":"Overload","B":"Stun","C":"Disrupt","D":"Wide beam"},"correct":"B","explanation":"Phasers can be set to 'stun' to render a target unconscious without lethal harm, a setting Kirk frequently orders to minimize casualties."},{"id":"TOS-121","series":"TOS","difficulty":"easy","type":"true_false","category":"Planets & Locations","question":"Starfleet Command and Starfleet Academy are located in San Francisco on Earth.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Starfleet Command and Starfleet Academy are based in San Francisco, a fact established across TOS and the original-cast films, including 'Star Trek IV: The Voyage Home.'"},{"id":"TOS-122","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who created Star Trek and is often called 'The Great Bird of the Galaxy'?","answers":{"A":"Gene L. Coon","B":"Gene Roddenberry","C":"Rick Berman","D":"D.C. Fontana"},"correct":"B","explanation":"Gene Roddenberry created Star Trek and served as showrunner of TOS; the affectionate nickname 'The Great Bird of the Galaxy' is even referenced in dialogue in the episode 'The Man Trap.'"},{"id":"TOS-123","series":"TOS","difficulty":"easy","type":"true_false","category":"Quotes & Catchphrases","question":"Spock often describes illogical human behavior as 'highly illogical.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"'Highly illogical' is one of Spock's signature observations throughout TOS, reflecting his Vulcan reliance on logic when confronted with emotional human conduct."},{"id":"TOS-124","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What is the name of the very first regular TOS episode broadcast on NBC in 1966?","answers":{"A":"The Cage","B":"Where No Man Has Gone Before","C":"The Man Trap","D":"Charlie X"},"correct":"C","explanation":"'The Man Trap,' featuring the salt-draining creature, was the first TOS episode aired on September 8, 1966, even though it was not the first produced."},{"id":"TOS-125","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Timeline & History","question":"Approximately which decades does the Enterprise's famous five-year mission span?","answers":{"A":"2151 to 2156","B":"2233 to 2238","C":"2265 to 2270","D":"2364 to 2369"},"correct":"C","explanation":"The five-year mission depicted in TOS runs roughly from 2265 to 2270 in established Star Trek chronology, placing the series in the 23rd century."},{"id":"TOS-126","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Where No Man Has Gone Before,' what happens to Kirk's friend Gary Mitchell after the ship crosses the galactic barrier?","answers":{"A":"He is killed instantly","B":"He develops godlike psionic powers","C":"He is transformed into a Vulcan","D":"He ages rapidly into an old man"},"correct":"B","explanation":"After the Enterprise crosses the galactic barrier, Lt. Cmdr. Gary Mitchell gains rapidly growing telekinetic and telepathic powers, becoming a god-like threat Kirk must stop."},{"id":"TOS-127","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"In 'The Squire of Gothos,' the mischievous, powerful being Trelane turns out to be what?","answers":{"A":"An immortal Greek god","B":"A child of a non-corporeal species","C":"A Romulan spy in disguise","D":"A malfunctioning android"},"correct":"B","explanation":"Trelane, who toys with the crew on the planet Gothos, is revealed at the end to be a child of energy-based parents who scold him and apologize for his behavior."},{"id":"TOS-128","series":"TOS","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"In 'The Doomsday Machine,' the planet killer destroys planets and consumes the debris to fuel itself.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Spock theorizes that the doomsday machine smashes planets into rubble with its antiproton beam and consumes the fragments as fuel, cutting a destructive path toward the Federation's most densely populated region."},{"id":"TOS-129","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"In 'Friday's Child,' on what planet does the McCoy-assisted birth of the heir to a tribal throne take place?","answers":{"A":"Capella IV","B":"Neural","C":"Eminiar VII","D":"Argelius II"},"correct":"A","explanation":"On Capella IV, home of the warrior Capellans, McCoy helps deliver the child of the slain leader's widow Eleen; the boy is named Leonard James Akaar in honor of McCoy and Kirk."},{"id":"TOS-130","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'A Taste of Armageddon,' how do the planets Eminiar VII and Vendikar wage their centuries-long war?","answers":{"A":"With cloaked starships","B":"By computer simulation, with citizens reporting to disintegration chambers","C":"Through gladiatorial combat","D":"Using biological weapons"},"correct":"B","explanation":"Eminiar VII and Vendikar fight a 'clean' war run entirely by computers; people declared casualties of virtual attacks must voluntarily report to disintegration chambers to keep the war bloodlessly civilized."},{"id":"TOS-131","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Ships & Technology","question":"What is the name of the standard small auxiliary craft carried by the Enterprise, famously stranded in one season-one episode?","answers":{"A":"The Copernicus","B":"The Galileo","C":"The Columbus","D":"The Picasso"},"correct":"B","explanation":"The shuttlecraft Galileo (NCC-1701/7) is the Enterprise auxiliary vessel marooned on Taurus II in 'The Galileo Seven'; the Columbus is another of the ship's shuttles."},{"id":"TOS-132","series":"TOS","difficulty":"medium","type":"true_false","category":"Starfleet Ranks & Protocol","question":"In Starfleet's chain of command during TOS, a commodore outranks a captain.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Commodore is a flag rank above captain, as shown when Commodore Matt Decker and Commodore Stocker outrank starship captains; it sits between captain and rear admiral."},{"id":"TOS-133","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of Spock's pet sehlat that he had as a child on Vulcan?","answers":{"A":"I-Chaya","B":"Porthos","C":"Spot","D":"Chu'lak"},"correct":"A","explanation":"Spock's childhood pet, a bear-like sehlat named I-Chaya, is named in the animated episode 'Yesteryear,' written by D.C. Fontana, which depicts young Spock on Vulcan."},{"id":"TOS-134","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"In 'The Man Trap,' what does the shape-shifting creature on planet M-113 drain from its victims to survive?","answers":{"A":"Blood","B":"Salt","C":"Water","D":"Memories"},"correct":"B","explanation":"The M-113 creature, the last of its kind, kills by draining the salt from a victim's body, leaving telltale ring-shaped marks; it can disguise itself by appearing as whoever its prey desires."},{"id":"TOS-135","series":"TOS","difficulty":"medium","type":"true_false","category":"Crossovers & Connections","question":"James Doohan, who played Scotty, also provided many guest voices in 'Star Trek: The Animated Series.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In addition to reprising Scotty, James Doohan voiced numerous guest characters and aliens in The Animated Series (1973-1974), alongside Majel Barrett, who voiced several female roles."},{"id":"TOS-136","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Space Seed,' which Enterprise historian falls in love with Khan and initially helps him seize the ship?","answers":{"A":"Marla McGivers","B":"Janice Lester","C":"Areel Shaw","D":"Helen Noel"},"correct":"A","explanation":"Lieutenant Marla McGivers, the Enterprise's historian, becomes infatuated with Khan and aids his takeover, but ultimately turns against him and chooses exile with him on Ceti Alpha V."},{"id":"TOS-137","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Timeline & History","question":"In 'Tomorrow Is Yesterday,' the Enterprise is thrown back in time to what era of Earth's history?","answers":{"A":"Ancient Rome","B":"1960s United States","C":"The American Civil War","D":"Prohibition-era Chicago"},"correct":"B","explanation":"Flung back to 1960s Earth, the Enterprise is detected by a U.S. Air Force jet; the crew must beam up pilot Captain John Christopher and undo the timeline damage before returning to their own era."},{"id":"TOS-138","series":"TOS","difficulty":"medium","type":"true_false","category":"Planets & Locations","question":"In 'This Side of Paradise,' spores on the planet Omicron Ceti III induce a blissful, contented state in the colonists and crew.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Plant spores on Omicron Ceti III protect inhabitants from deadly Berthold rays while inducing perfect contentment; their influence even lets Spock feel love before Kirk breaks the effect with strong emotion."},{"id":"TOS-139","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"Which composer wrote the iconic original Star Trek main title theme?","answers":{"A":"Jerry Goldsmith","B":"Alexander Courage","C":"James Horner","D":"Fred Steiner"},"correct":"B","explanation":"Alexander Courage composed the famous TOS main title theme. Jerry Goldsmith later wrote the theme for 'Star Trek: The Motion Picture,' which became the TNG theme."},{"id":"TOS-140","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Timeline & History","question":"In 'Space Seed,' which historical period on Earth is identified as the era of the Eugenics Wars that produced Khan?","answers":{"A":"The 1990s","B":"The 2050s","C":"The 1940s","D":"The 2150s"},"correct":"A","explanation":"'Space Seed' dialogue places the Eugenics Wars in the 1990s, describing Khan as a genetically engineered tyrant who ruled much of Earth from roughly 1992 to 1996."},{"id":"TOS-141","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"What is Starfleet's General Order 24, which Kirk threatens to invoke in 'A Taste of Armageddon'?","answers":{"A":"An order to evacuate all Federation citizens","B":"An order to destroy all life on a planet's surface","C":"A self-destruct sequence for the ship","D":"An order to surrender to a superior force"},"correct":"B","explanation":"Kirk has Scotty prepare General Order 24, the directive to obliterate all life on the surface of Eminiar VII, using the threat as leverage to force the warring planets to negotiate peace."},{"id":"TOS-142","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Planets & Locations","question":"In 'A Private Little War,' what is the name of the planet where Kirk arms one faction to counter Klingon interference?","answers":{"A":"Neural","B":"Ekos","C":"Sigma Iotia II","D":"Beta III"},"correct":"A","explanation":"On the planet Neural, the Klingons secretly supply flintlock firearms to the villagers, prompting Kirk to arm the hill people equally in a Cold War-style 'balance of power' allegory."},{"id":"TOS-143","series":"TOS","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'The Changeling,' the space probe Nomad mistakes Kirk for its creator, the scientist Jackson Roykirk.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The merged probe Nomad confuses 'Kirk' with its creator Jackson Roykirk; this sterilizing, perfection-seeking machine that wipes out imperfect life is widely seen as a precursor to V'Ger in 'The Motion Picture.'"},{"id":"TOS-144","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Villains & Antagonists","question":"In 'Day of the Dove,' what is the nature of the entity that traps Klingons and humans aboard the Enterprise and provokes them to fight?","answers":{"A":"A telepathic Romulan agent","B":"A non-corporeal being that feeds on hostile emotions","C":"A rogue Federation computer","D":"A shape-shifting salt creature"},"correct":"B","explanation":"A glowing alien entity feeds on the hatred and aggression of the trapped crews, healing their wounds to keep the endless brawl going until Kirk and Kang's forces drive it off with shared laughter and goodwill."},{"id":"TOS-145","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Timeline & History","question":"According to 'Balance of Terror,' the Earth-Romulan War was fought with primitive ships and ended with what outcome?","answers":{"A":"The Romulans joining the Federation","B":"The establishment of a Neutral Zone enforced by treaty","C":"The total destruction of the Romulan homeworld","D":"An alliance against the Klingons"},"correct":"B","explanation":"'Balance of Terror' establishes that the Earth-Romulan War, fought a century earlier with atomic weapons, ended in a treaty that set up a Neutral Zone; neither side had seen the other until the episode's events."},{"id":"TOS-146","series":"TOS","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"In 'The Ultimate Computer,' the M-5 multitronic unit takes control of the Enterprise during war games and begins firing on other Starfleet ships for real.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Dr. Richard Daystrom's M-5 computer, imprinted with his own engrams, treats the war-game exercise as a real threat and destroys part of the attacking fleet before Kirk talks it into shutting down."},{"id":"TOS-147","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"In 'The Deadly Years,' under what regulation is Commodore Stocker able to relieve the rapidly aging Captain Kirk of command?","answers":{"A":"A hearing on competency to command","B":"Article 14, Section 31","C":"The Prime Directive","D":"Court-martial for cowardice"},"correct":"A","explanation":"In 'The Deadly Years,' a formal competency hearing finds the prematurely aged Kirk unfit, allowing Commodore Stocker to assume command, a decision that nearly proves disastrous near the Romulan Neutral Zone."},{"id":"TOS-148","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"In 'Star Trek V: The Final Frontier,' who is the renegade Vulcan that hijacks the Enterprise-A in search of God at the galaxy's center?","answers":{"A":"Sybok","B":"Sarek","C":"Surak","D":"Tuvok"},"correct":"A","explanation":"Sybok, Spock's emotionally embracing half-brother, commandeers the Enterprise-A to journey through the Great Barrier to the planet Sha Ka Ree in search of the divine."},{"id":"TOS-149","series":"TOS","difficulty":"hard","type":"true_false","category":"Crossovers & Connections","question":"In 'Star Trek VI: The Undiscovered Country,' the Klingon General Chang quotes Shakespeare and claims it is best read 'in the original Klingon.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"General Chang, played by Christopher Plummer, peppers his speech with Shakespeare quotations and famously insists Shakespeare must be read 'in the original Klingon' during the Khitomer dinner scene."},{"id":"TOS-150","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"In 'Star Trek: The Motion Picture,' who is the Deltan navigator that joins the Enterprise and is later merged with V'Ger?","answers":{"A":"Ilia","B":"Janice Rand","C":"Christine Chapel","D":"Marta"},"correct":"A","explanation":"Lieutenant Ilia, a bald Deltan navigator and former love interest of Commander Decker, is absorbed by V'Ger and returned as a robotic probe duplicate, central to the film's resolution."},{"id":"TOS-151","series":"TOS","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Let That Be Your Last Battlefield,' the two warring aliens Bele and Lokai both come from what planet?","answers":{"A":"Cheron","B":"Ariannus","C":"Eminiar VII","D":"Organia"},"correct":"A","explanation":"Bele and Lokai are the last survivors of Cheron, whose people were divided over which side of their bodies was black or white, a parable on racism in 'Let That Be Your Last Battlefield.'"},{"id":"TOS-152","series":"TOS","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Lieutenant Sulu serves as the primary helmsman of the USS Enterprise during the five-year mission.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Though shown in the science division in the second pilot 'Where No Man Has Gone Before,' Sulu serves throughout the series as the Enterprise's senior helmsman, holding the rank of lieutenant."},{"id":"TOS-153","series":"TOS","difficulty":"medium","type":"multiple_choice","category":"Ships & Technology","question":"What is the registry designation of the shuttlecraft Galileo featured in 'The Galileo Seven'?","answers":{"A":"NCC-1701/7","B":"NCC-1031","C":"NCC-1701/2","D":"NCC-1864"},"correct":"A","explanation":"The Class F shuttlecraft Galileo, assigned to the USS Enterprise, carries the registry NCC-1701/7, as seen in 'The Galileo Seven.'"},{"id":"TOS-154","series":"TOS","difficulty":"medium","type":"true_false","category":"Villains & Antagonists","question":"In 'I, Mudd,' Kirk and his crew defeat the androids controlling them by overwhelming the android mind with illogical and contradictory behavior.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'I, Mudd,' the crew, with Harry Mudd's help, stage absurd, illogical performances that overload the android leader Norman and the android collective, freeing themselves."},{"id":"TOS-155","series":"TOS","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"What is the standard crew complement of the USS Enterprise during the five-year mission, as established in production materials and dialogue?","answers":{"A":"430","B":"203","C":"1,012","D":"150"},"correct":"A","explanation":"The Enterprise's crew complement is established as 430 (43 officers and 387 enlisted); the lower figure of 203 dates to the earlier pilot 'The Cage' under Captain Pike."},{"id":"TNG-001","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who is the captain of the USS Enterprise-D?","answers":{"A":"Data","B":"Jean-Luc Picard","C":"Geordi La Forge","D":"William Riker"},"correct":"B","explanation":"Jean-Luc Picard commands the Enterprise-D from 2364 through its destruction in Star Trek: Generations (2371)."},{"id":"TNG-002","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Counselor Troi is half Betazoid.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Deanna Troi's mother Lwaxana is a full Betazoid; her father Ian Andrew Troi was a human Starfleet officer."},{"id":"TNG-003","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What is the registry number of the USS Enterprise-D?","answers":{"A":"NCC-74656","B":"NCC-1701-D","C":"NCC-1701-C","D":"NCC-1701-E"},"correct":"B","explanation":"The Galaxy-class Enterprise-D bears the registry NCC-1701-D, shown on the dedication plaque and throughout TNG."},{"id":"TNG-004","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Data is an android created by Dr. Noonian Soong.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Dr. Noonien Soong built Data on Omicron Theta, as revealed in 'Datalore' and 'Brothers.'"},{"id":"TNG-005","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What species is Worf?","answers":{"A":"Cardassian","B":"Klingon","C":"Vulcan","D":"Romulan"},"correct":"B","explanation":"Worf, son of Mogh, is the first Klingon Starfleet officer and was raised on Earth by human foster parents after the Khitomer massacre."},{"id":"TNG-006","series":"TNG","difficulty":"easy","type":"true_false","category":"Villains & Antagonists","question":"The Borg's famous phrase is 'Resistance is futile.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Borg first declare 'Resistance is futile' in 'Q Who' and repeat it throughout TNG, including 'The Best of Both Worlds.'"},{"id":"TNG-007","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the android crew member aboard the Enterprise-D?","answers":{"A":"Data","B":"B-4","C":"Lore","D":"Julian"},"correct":"A","explanation":"Lt. Commander Data serves as second officer and operations officer aboard the Enterprise-D throughout TNG."},{"id":"TNG-008","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Dr. Beverly Crusher is the Chief Medical Officer aboard the Enterprise-D.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Beverly Crusher is CMO for most of TNG; only in Season 2 is she replaced by Dr. Pulaski while serving at Starfleet Medical."},{"id":"TNG-009","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Quotes & Catchphrases","question":"What is Picard's most famous command phrase when ordering the ship to go to warp?","answers":{"A":"Full speed ahead","B":"Engage","C":"Make it so","D":"Go to warp"},"correct":"B","explanation":"Picard's signature command 'Engage' is delivered with a forward point throughout TNG when ordering the ship to warp."},{"id":"TNG-010","series":"TNG","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"The holodeck is a recreational and training facility that creates realistic simulations.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The holodeck uses photons, force fields, and replicated matter to create immersive simulations for recreation, training, and investigation."},{"id":"TNG-011","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is Geordi La Forge's role on the Enterprise-D?","answers":{"A":"Helm Officer","B":"Security Chief","C":"Chief Engineer","D":"Chief Medical Officer"},"correct":"C","explanation":"Geordi La Forge is promoted from conn officer to Chief Engineer in Season 2 ('The Child') and holds the post through the films."},{"id":"TNG-012","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Wesley Crusher is the son of Dr. Beverly Crusher.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Wesley is the son of Beverly and the late Jack Crusher, who served under Picard's command on the USS Stargazer."},{"id":"TNG-013","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Villains & Antagonists","question":"What omnipotent being frequently torments the crew of the Enterprise-D?","answers":{"A":"Armus","B":"Q","C":"The Traveler","D":"Nagilum"},"correct":"B","explanation":"Q, played by John de Lancie, appears in the pilot 'Encounter at Farpoint' and recurs throughout TNG, ending with 'All Good Things...'"},{"id":"TNG-014","series":"TNG","difficulty":"easy","type":"true_false","category":"Starfleet Ranks & Protocol","question":"The Prime Directive prohibits Starfleet from interfering with the development of pre-warp civilizations.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Starfleet General Order 1 forbids interference in the natural development of pre-warp societies, a central theme in episodes like 'Pen Pals' and 'Who Watches the Watchers.'"},{"id":"TNG-015","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What species is Counselor Deanna Troi's mother, Lwaxana?","answers":{"A":"Vulcan","B":"Trill","C":"Betazoid","D":"Bolian"},"correct":"C","explanation":"Lwaxana Troi, played by Majel Barrett, is a full-blooded Betazoid and Daughter of the Fifth House, introduced in 'Haven.'"},{"id":"TNG-016","series":"TNG","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"The Enterprise-D is a Galaxy-class starship.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Enterprise-D is the second Galaxy-class vessel constructed at Utopia Planitia, as established in 'Encounter at Farpoint.'"},{"id":"TNG-017","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Quotes & Catchphrases","question":"What phrase does Picard use when giving a firm order or decision?","answers":{"A":"So noted","B":"Confirmed","C":"Make it so","D":"Proceed"},"correct":"C","explanation":"'Make it so' is Picard's habitual order to subordinates throughout TNG, signaling a decision is final."},{"id":"TNG-018","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Worf serves as Security Chief on the Enterprise-D.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Worf is promoted to Chief of Security following Tasha Yar's death in 'Skin of Evil' and holds the post until the Enterprise-D's destruction."},{"id":"TNG-019","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the home planet of the Vulcans?","answers":{"A":"Vulcan","B":"Betazed","C":"Romulus","D":"Qo'noS"},"correct":"A","explanation":"Vulcan (also called T'Khasi or Ni'Var) orbits 40 Eridani A and is the homeworld of Spock, Sarek, and Tuvok."},{"id":"TNG-020","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Commander William Riker is Picard's first officer.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Riker serves as Picard's Number One from 'Encounter at Farpoint' until taking command of the USS Titan in Star Trek: Nemesis."},{"id":"TNG-021","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In which two-part episode is Picard assimilated by the Borg?","answers":{"A":"Yesterday's Enterprise","B":"The Best of Both Worlds","C":"Chain of Command","D":"The Defector"},"correct":"B","explanation":"Picard is assimilated and becomes Locutus of Borg in 'The Best of Both Worlds' Parts I and II, the Season 3 finale and Season 4 premiere."},{"id":"TNG-022","series":"TNG","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"Ferengi society is strongly driven by the pursuit of profit.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Ferengi culture is governed by the Rules of Acquisition; profit motive shapes their laws, religion, and family life, as seen in 'The Last Outpost' and throughout DS9."},{"id":"TNG-023","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What device allows crew members to be instantly transported from one location to another?","answers":{"A":"Warp drive","B":"Transporter","C":"Holodeck","D":"Replicator"},"correct":"B","explanation":"The transporter dematerializes a subject into a matter stream and reassembles it elsewhere, used routinely throughout TNG."},{"id":"TNG-024","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Data has an evil twin brother named Lore.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Lore is Data's older, malevolent prototype built by Dr. Soong, introduced in 'Datalore' and later allied with the Borg in 'Descent.'"},{"id":"TNG-025","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"What is Picard's rank at the start of TNG?","answers":{"A":"Commander","B":"Commodore","C":"Admiral","D":"Captain"},"correct":"D","explanation":"Picard holds the rank of Captain from the pilot 'Encounter at Farpoint' through Generations; he was promoted decades earlier on the USS Stargazer."},{"id":"TNG-026","series":"TNG","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"A replicator can produce food and other objects from energy.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Replicators use transporter-based matter-energy conversion to synthesize food, clothing, and small objects from stored patterns and bulk matter."},{"id":"TNG-027","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What unique visual aid does Geordi La Forge use due to his blindness?","answers":{"A":"Neural scanner","B":"Tricorder attachment","C":"VISOR","D":"Cybernetic eye implant"},"correct":"C","explanation":"Geordi was born blind and wears a VISOR (Visual Instrument and Sensory Organ Replacement) that lets him see across the EM spectrum until receiving ocular implants in First Contact."},{"id":"TNG-028","series":"TNG","difficulty":"easy","type":"true_false","category":"Planets & Locations","question":"Ten Forward is the name of the lounge aboard the Enterprise-D.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Ten Forward, located at the forward edge of Deck 10 in the saucer, is the ship's social lounge managed by Guinan."},{"id":"TNG-029","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who is the bartender of Ten Forward on the Enterprise-D?","answers":{"A":"Troi","B":"Whoopi Goldberg's character Guinan","C":"O'Brien","D":"Nurse Ogawa"},"correct":"B","explanation":"Guinan, the El-Aurian bartender played by Whoopi Goldberg, joins the cast in Season 2 ('The Child') and serves as a confidante to Picard and the crew."},{"id":"TNG-030","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Picard's favorite hot drink is Earl Grey tea.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Picard's standard replicator order is 'Tea, Earl Grey, hot,' a verbal pattern repeated throughout TNG and the films."},{"id":"TNG-031","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What Klingon exclamation means 'success'?","answers":{"A":"Sto-Vo-Kor","B":"bat'leth","C":"mek'leth","D":"qapla'"},"correct":"D","explanation":"Qapla' is the Klingon exclamation for 'success,' commonly used as a parting word, as heard in episodes featuring the Klingon Empire."},{"id":"TNG-032","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Data is incapable of experiencing human emotions without his emotion chip.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Data lacks emotions throughout TNG until Dr. Soong's emotion chip is installed in Star Trek: Generations, a central premise of his character arc."},{"id":"TNG-033","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In the TNG pilot episode, which entity puts humanity on trial?","answers":{"A":"The Traveler","B":"The Prophets","C":"Q","D":"The Borg"},"correct":"C","explanation":"Q places humanity on trial in 'Encounter at Farpoint,' a trial he claims is still in session through 'All Good Things...'"},{"id":"TNG-034","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of Data's cat?","answers":{"A":"Whiskers","B":"Mittens","C":"Spot","D":"Patches"},"correct":"C","explanation":"Spot appears in multiple episodes and is the subject of Data's poem 'Ode to Spot' in 'Schisms.'"},{"id":"TNG-035","series":"TNG","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Riker was offered command of his own starship multiple times but turned it down.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Riker declines command of the USS Drake, the Aries, and the Melbourne; his reluctance to leave the Enterprise is addressed in 'The Icarus Factor' and 'The Best of Both Worlds.'"},{"id":"TNG-036","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Inner Light,' Picard lives an entire lifetime as which character?","answers":{"A":"Meribor","B":"Eline","C":"Batai","D":"Kamin"},"correct":"D","explanation":"In 'The Inner Light,' a Kataan probe causes Picard to experience a lifetime as Kamin, an iron weaver on the doomed planet, leaving him with the memory and a Ressikan flute."},{"id":"TNG-037","series":"TNG","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"The Romulans and Vulcans share a common ancestry.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Romulans descend from Vulcans who rejected Surak's teachings of logic and left their homeworld, as established in TOS and reinforced in TNG's 'Unification' two-parter."},{"id":"TNG-038","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Ships & Technology","question":"What is the maximum standard warp speed of a Galaxy-class starship?","answers":{"A":"Warp 8","B":"Warp 9.6","C":"Warp 9.2","D":"Warp 10"},"correct":"B","explanation":"The Galaxy-class maximum sustainable cruise is Warp 9.6 per the TNG Technical Manual; higher speeds can be reached only briefly before structural damage."},{"id":"TNG-039","series":"TNG","difficulty":"medium","type":"true_false","category":"Villains & Antagonists","question":"Picard's Borg designation was Locutus of Borg.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Assimilated in 'The Best of Both Worlds,' Picard becomes Locutus to serve as the Borg's voice to humanity, an ordeal revisited in First Contact."},{"id":"TNG-040","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"Who replaced Dr. Crusher in Season 2 of TNG?","answers":{"A":"Dr. Selar","B":"Nurse Ogawa","C":"Dr. Crusher returned early","D":"Dr. Pulaski"},"correct":"D","explanation":"Dr. Katherine Pulaski, played by Diana Muldaur, serves as CMO throughout Season 2 before Beverly Crusher returns in Season 3."},{"id":"TNG-041","series":"TNG","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Yesterday's Enterprise,' the Enterprise-C travels forward through a temporal rift.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Enterprise-C, commanded by Rachel Garrett, emerges from a temporal rift at Narendra III into the Enterprise-D's era, altering history into a Federation-Klingon war."},{"id":"TNG-042","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"What is the name of the Klingon home world?","answers":{"A":"Romulus","B":"Betazed","C":"Qo'noS","D":"Cardassia Prime"},"correct":"C","explanation":"Qo'noS (often anglicized Kronos) is the Klingon homeworld, seat of the High Council, depicted in 'Sins of the Father' and 'Redemption.'"},{"id":"TNG-043","series":"TNG","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Guinan's species, the El-Aurians, are known as a 'race of listeners.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Guinan describes the El-Aurians as listeners in 'Q Who' and Star Trek: Generations, which is why she counsels the crew so effectively."},{"id":"TNG-044","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"What is the Starfleet rank insignia color for command division officers in TNG?","answers":{"A":"Red","B":"Teal","C":"Gold","D":"Blue"},"correct":"A","explanation":"TNG-era command uniforms use red; operations/security use gold; sciences/medical use blue, the inverse of the TOS color scheme."},{"id":"TNG-045","series":"TNG","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"The Ferengi Rules of Acquisition number 284 in total.","answers":{"A":"True","B":"False"},"correct":"B","explanation":"There are 285 Rules of Acquisition, as confirmed in DS9's 'Body Parts'; the question's number 284 is off by one."},{"id":"TNG-046","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What holodeck character does Data frequently play detective as?","answers":{"A":"Dixon Hill","B":"Sherlock Holmes","C":"Hercule Poirot","D":"Sam Spade"},"correct":"B","explanation":"Data plays Sherlock Holmes in 'Elementary, Dear Data' and 'Ship in a Bottle,' with Geordi as Watson; the program also creates the sentient Moriarty."},{"id":"TNG-047","series":"TNG","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Worf's foster parents are human, named Sergey and Helena Rozhenko.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Sergey and Helena Rozhenko adopted Worf after the Khitomer massacre, as shown in 'Family' and 'Heart of Glory.'"},{"id":"TNG-048","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In which episode does Picard play a Dixon Hill holodeck program?","answers":{"A":"Elementary, Dear Data","B":"Manhunt","C":"The Big Goodbye","D":"Ship in a Bottle"},"correct":"C","explanation":"'The Big Goodbye' (Season 1) is Picard's first Dixon Hill holodeck adventure; the episode won a Peabody Award for its writing."},{"id":"TNG-049","series":"TNG","difficulty":"medium","type":"true_false","category":"Ships & Technology","question":"The Enterprise-D has a saucer separation capability.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Galaxy-class ships can detach the saucer section from the stardrive; this is performed in 'Encounter at Farpoint,' 'The Best of Both Worlds Part II,' and Generations."},{"id":"TNG-050","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the Klingon ceremonial blade known as?","answers":{"A":"mek'leth","B":"targ","C":"d'k tahg","D":"bat'leth"},"correct":"D","explanation":"The bat'leth ('sword of honor') was forged by Kahless from a lock of his own hair, according to legend recounted in 'Reunion' and 'Rightful Heir.'"},{"id":"TNG-051","series":"TNG","difficulty":"medium","type":"true_false","category":"Timeline & History","question":"TNG is set approximately 100 years after the events of the original Star Trek series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"TNG begins in 2364, about 78-100 years after TOS's mid-2260s setting; this gap is dramatized when Spock appears in 'Unification.'"},{"id":"TNG-052","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"Who was the Cardassian torturer in 'Chain of Command Part II'?","answers":{"A":"Damar","B":"Dukat","C":"Gul Madred","D":"Gul Macet"},"correct":"C","explanation":"Gul Madred, played by David Warner, interrogates Picard with the 'four lights' psychological torture in 'Chain of Command, Part II.'"},{"id":"TNG-053","series":"TNG","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Chain of Command,' Picard famously declares 'There are four lights!'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Picard shouts 'There are four lights!' to Gul Madred at the end of 'Chain of Command, Part II,' refusing to capitulate despite the torture."},{"id":"TNG-054","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What does Troi's species make her capable of?","answers":{"A":"Mind control","B":"Precognition","C":"Telepathy only","D":"Empathic sensing of emotions"},"correct":"D","explanation":"As a half-Betazoid, Troi has empathic abilities rather than full telepathy; she senses emotions but cannot read specific thoughts."},{"id":"TNG-055","series":"TNG","difficulty":"medium","type":"true_false","category":"Crossovers & Connections","question":"Miles O'Brien appears in TNG before joining the main cast of DS9.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Colm Meaney's O'Brien serves as transporter chief on the Enterprise-D from the pilot through Season 6 before transferring to Deep Space 9."},{"id":"TNG-056","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"What is the name of the planet where Data was created?","answers":{"A":"Velara III","B":"Exo III","C":"Omicron Theta","D":"Minos"},"correct":"C","explanation":"Data was discovered on the colony of Omicron Theta after the Crystalline Entity destroyed it; Dr. Soong's lab is shown there in 'Datalore.'"},{"id":"TNG-057","series":"TNG","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Alexander Rozhenko is the son of Worf.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Alexander is Worf's son by K'Ehleyr, introduced in 'Reunion' and raised by Sergey and Helena Rozhenko before returning aboard the Enterprise in 'New Ground.'"},{"id":"TNG-058","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"Who serves as the primary tactical and security officer aboard the Enterprise-D for most of TNG?","answers":{"A":"Ensign Ro","B":"Lt. Worf","C":"Ensign Crusher","D":"Lt. Yar"},"correct":"B","explanation":"Worf takes the tactical/security post after Tasha Yar's death in 'Skin of Evil' (Season 1) and holds it through the remainder of TNG."},{"id":"TNG-059","series":"TNG","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Tasha Yar is killed in the episode 'Skin of Evil.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Security chief Natasha Yar is killed by the malevolent oil-creature Armus in the Season 1 episode 'Skin of Evil.'"},{"id":"TNG-060","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What is the name of the TNG series finale?","answers":{"A":"Descent","B":"The Emissary","C":"Preemptive Strike","D":"All Good Things..."},"correct":"D","explanation":"'All Good Things...' is the two-hour series finale in which Q has Picard jumping among past, present, and future to prevent a Q-created anti-time anomaly."},{"id":"TNG-061","series":"TNG","difficulty":"medium","type":"true_false","category":"Villains & Antagonists","question":"The Borg Queen first appears in the TNG television series.","answers":{"A":"True","B":"False"},"correct":"B","explanation":"The Borg Queen, played by Alice Krige, debuts in the 1996 film Star Trek: First Contact, not in the TNG TV series."},{"id":"TNG-062","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the Borg's collective term for their group consciousness?","answers":{"A":"The Hive","B":"The Amalgam","C":"The Unity","D":"The Collective"},"correct":"D","explanation":"The Borg refer to themselves as 'the Collective,' a hive mind linked by subspace, as established in 'Q Who' and 'The Best of Both Worlds.'"},{"id":"TNG-063","series":"TNG","difficulty":"medium","type":"true_false","category":"Timeline & History","question":"First contact between humans and Vulcans occurred on April 5, 2063.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Zefram Cochrane's warp flight on April 5, 2063 prompts the landing of the Vulcan T'Plana-Hath in Bozeman, Montana, dramatized in Star Trek: First Contact."},{"id":"TNG-064","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of Picard's nephew who dies in a tragic accident seen in 'Family'?","answers":{"A":"Thomas","B":"Louis","C":"Robert","D":"Rene"},"correct":"D","explanation":"Rene Picard, son of Robert, is shown in 'Family' (Season 4); his and Robert's later deaths in a fire at the family vineyard devastate Picard in Star Trek: Generations."},{"id":"TNG-065","series":"TNG","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"The Cardassians are known for their brutal occupations of other worlds.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Cardassian Occupation of Bajor (2328-2369) is a defining atrocity referenced throughout TNG ('Ensign Ro,' 'Chain of Command') and DS9."},{"id":"TNG-066","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Tapestry,' Q allows Picard to relive his past to prevent which incident?","answers":{"A":"A barroom fight where he was stabbed through the heart","B":"The destruction of the Enterprise-D","C":"His assimilation by the Borg","D":"His capture by Cardassians"},"correct":"A","explanation":"In 'Tapestry,' Q lets Picard relive his Academy days and avoid the Nausicaan bar fight; the resulting timid life shows Picard the value of his original mistake."},{"id":"TNG-067","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is Data's positronic net processing speed in calculations per second?","answers":{"A":"60 billion","B":"6 trillion","C":"60 trillion","D":"600 billion"},"correct":"C","explanation":"Data states in 'The Measure of a Man' that his positronic net runs at 60 trillion operations per second with a storage capacity of 800 quadrillion bits."},{"id":"TNG-068","series":"TNG","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"The Galaxy-class starship has a crew complement of approximately 1,012 personnel.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Picard's standard hailing line cites '1,014 souls' aboard in 'Encounter at Farpoint,' establishing the roughly 1,000-person Galaxy-class complement including families."},{"id":"TNG-069","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Measure of a Man,' who serves as prosecutor in Data's sentience hearing?","answers":{"A":"Commander Riker","B":"Captain Louvois","C":"Counselor Troi","D":"Admiral Nakamura"},"correct":"A","explanation":"JAG officer Phillipa Louvois orders Riker to prosecute the case against Data's sentience in 'The Measure of a Man'; Picard defends Data."},{"id":"TNG-070","series":"TNG","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"The Tamarians communicate exclusively through metaphor and allegory from their own history.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Darmok,' the Tamarians (Children of Tama) speak only in references to their mytho-historical figures, like 'Darmok and Jalad at Tanagra.'"},{"id":"TNG-071","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Planets & Locations","question":"The Tamarian captain strands himself and Picard on which planet to force communication?","answers":{"A":"El-Adrel IV","B":"Melona IV","C":"Veridian III","D":"Solari IV"},"correct":"A","explanation":"Captain Dathon transports himself and Picard to El-Adrel IV to face a creature together, forcing a shared experience ('Darmok and Jalad at Tanagra') to overcome the language barrier."},{"id":"TNG-072","series":"TNG","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Dr. Soong's wife, Juliana, was secretly an android copy.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Inheritance,' Data discovers that Juliana Tainer is an android replica Soong built after the original Juliana died; she remains unaware of her nature."},{"id":"TNG-073","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Timeline & History","question":"TNG is set in which century?","answers":{"A":"22nd century","B":"24th century","C":"23rd century","D":"25th century"},"correct":"B","explanation":"TNG is set in the 24th century, beginning in 2364 with 'Encounter at Farpoint' and ending in 2370 with 'All Good Things...'"},{"id":"TNG-074","series":"TNG","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Cause and Effect,' the Enterprise-D is destroyed and the crew relives the same day multiple times.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Enterprise is trapped in a causality loop colliding with the USS Bozeman; Data eventually plants a clue (the number three, via dealt cards) to break the cycle."},{"id":"TNG-075","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the Romulan commander who works secretly with Picard in 'The Defector'?","answers":{"A":"Jarok","B":"Tomalak","C":"Sela","D":"Tebok"},"correct":"A","explanation":"Admiral Alidar Jarok poses as a logistics officer to warn the Federation of a Romulan plot in 'The Defector'; he commits suicide after learning the data was a test."},{"id":"TNG-076","series":"TNG","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Sela is the half-Romulan daughter of Tasha Yar from an alternate timeline.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Sela (also played by Denise Crosby) is the daughter of the alternate-timeline Tasha Yar from 'Yesterday's Enterprise,' revealed in 'Redemption' and 'Unification.'"},{"id":"TNG-077","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"What material is the primary hull of the Enterprise-D composed of?","answers":{"A":"Ablative armor plating","B":"Tritanium alloy","C":"Duranium and tritanium composite","D":"Neutronium"},"correct":"C","explanation":"The TNG Technical Manual specifies the Enterprise-D hull as a duranium/tritanium composite, providing structural strength against impact and weapons fire."},{"id":"TNG-078","series":"TNG","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Frame of Mind,' Riker questions whether his entire life on the Enterprise is a delusion.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Riker is held by Tilonus IV captors who use a memory-probe to make him doubt his own reality; layered hallucinations shift between asylum and Enterprise."},{"id":"TNG-079","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the name of the Klingon afterlife for honorable warriors?","answers":{"A":"Barge of the Dead","B":"Sto-Vo-Kor","C":"Gre'thor","D":"Fek'lhr"},"correct":"B","explanation":"Sto-Vo-Kor is the Klingon afterlife for honored warriors; the dishonored are condemned to Gre'thor, as discussed in 'Rightful Heir' and DS9."},{"id":"TNG-080","series":"TNG","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Ensign Ro Laren is Bajoran.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Ro Laren, played by Michelle Forbes, is the first major Bajoran character in Trek, introduced in 'Ensign Ro' (Season 5)."},{"id":"TNG-081","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Offspring,' Data creates an android child. What does he name her?","answers":{"A":"Petal","B":"Rhea","C":"Lal","D":"Nova"},"correct":"C","explanation":"In 'The Offspring,' Data names his android daughter Lal, the Hindi word for 'beloved'; she dies after a cascade failure in her positronic net."},{"id":"TNG-082","series":"TNG","difficulty":"hard","type":"true_false","category":"Starfleet Ranks & Protocol","question":"The Judge Advocate General (JAG) office adjudicates legal matters within Starfleet.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"JAG officers like Captain Phillipa Louvois (TNG: 'The Measure of a Man') and Admiral Satie ('The Drumhead') handle Starfleet judicial proceedings."},{"id":"TNG-083","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Villains & Antagonists","question":"What is the name of the entity that killed Tasha Yar?","answers":{"A":"Lore","B":"Armus","C":"The Crystalline Entity","D":"Nagilum"},"correct":"B","explanation":"Armus, the malevolent oil-like creature on Vagra II, kills Tasha Yar with an energy discharge in 'Skin of Evil.'"},{"id":"TNG-084","series":"TNG","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"The Traveler is from Tau Alpha C.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Traveler, who mentors Wesley Crusher, hails from Tau Alpha C, as established in 'Where No One Has Gone Before' and 'Remember Me.'"},{"id":"TNG-085","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"In 'The Best of Both Worlds, Part II,' how does Data ultimately disable the Borg cube heading for Earth?","answers":{"A":"By detonating the main deflector's energy discharge","B":"By tapping the captured Borg link and ordering the Collective to 'sleep'/regenerate","C":"By beaming a quantum torpedo into the cube's core","D":"By transmitting a self-replicating computer virus"},"correct":"B","explanation":"After Locutus is captured, Data taps into the Borg subspace link; cued by Picard's whispered 'sleep,' he accesses the regeneration subroutine and commands the Collective to regenerate, shutting down the cube's systems so it self-destructs."},{"id":"TNG-086","series":"TNG","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Time's Arrow,' the crew discovers Data's severed head in a cave on Earth dating to the 19th century.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Excavators find Data's 500-year-old head beneath San Francisco; the crew travels to 1893 to investigate, encountering Samuel Clemens and the Devidians."},{"id":"TNG-087","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Planets & Locations","question":"On which planet is the Crystalline Entity first encountered?","answers":{"A":"Melona IV","B":"Omicron Theta","C":"Gravesworld","D":"Exo III"},"correct":"B","explanation":"The Crystalline Entity destroyed the Omicron Theta colony where Data was created, as established in 'Datalore' and revisited in 'Silicon Avatar.'"},{"id":"TNG-088","series":"TNG","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"The Bynars from the episode '11001001' communicate in binary code.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Bynars, who live in symbiotic pairs linked to a central computer, speak in rapid binary bursts; their behavior drives the plot of '11001001.'"},{"id":"TNG-089","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What year does the TNG series finale 'All Good Things...' flash-forward to?","answers":{"A":"2404","B":"2395","C":"2400","D":"2385"},"correct":"B","explanation":"'All Good Things...' flashes forward roughly 25 years from 2370 to about 2395, showing an elderly Picard suffering from Irumodic Syndrome."},{"id":"TNG-090","series":"TNG","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Darmok,' the phrase 'Shaka, when the walls fell' means failure.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"'Shaka, when the walls fell' is the Tamarian image-metaphor for failure, contrasted with 'Sokath, his eyes uncovered' for understanding."},{"id":"TNG-091","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Villains & Antagonists","question":"In 'Descent,' what does Lore use to manipulate Data into helping him?","answers":{"A":"A computer virus","B":"A telepathic signal","C":"Negative emotions transmitted via the emotion chip","D":"A neural interface implant"},"correct":"C","explanation":"In 'Descent,' Lore feeds Data negative emotions through the emotion chip (which Lore had intercepted), corrupting his judgment to join the rogue Borg."},{"id":"TNG-092","series":"TNG","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"The Enterprise-D was destroyed on Veridian III in the film Star Trek: Generations.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"After a warp-core breach, the Enterprise-D's saucer section crash-lands on Veridian III in Star Trek: Generations (1994)."},{"id":"TNG-093","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"Which TNG character appeared in the DS9 pilot episode?","answers":{"A":"Picard","B":"Data","C":"Riker","D":"Worf"},"correct":"A","explanation":"Picard appears in the DS9 pilot 'Emissary' to hand command of the station to Sisko, a meeting laden with Sisko's resentment over the Battle of Wolf 359."},{"id":"TNG-094","series":"TNG","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Worf's biological father is Mogh, who was killed at Khitomer.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Mogh died in the 2346 Romulan massacre at Khitomer; the discommendation of his house drives the plot of 'Sins of the Father' and 'Redemption.'"},{"id":"TNG-095","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the title of the Romulan head of state?","answers":{"A":"First Consul","B":"Praetor","C":"Proconsul","D":"Chancellor"},"correct":"B","explanation":"The Praetor leads the Romulan Star Empire and presides over the Senate; the title is referenced throughout TNG and dramatized in Star Trek: Nemesis."},{"id":"TNG-096","series":"TNG","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"Picard's artificial heart was implanted after he was stabbed by a Nausicaan.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"As recounted in 'Samaritan Snare' and dramatized in 'Tapestry,' Cadet Picard was stabbed through the heart by a Nausicaan in a bar fight on Starbase Earhart, necessitating a bioartificial replacement."},{"id":"TNG-097","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of Riker's duplicate created by a transporter accident?","answers":{"A":"Thomas Riker","B":"Clone Riker","C":"Beta Riker","D":"Will Riker"},"correct":"A","explanation":"In 'Second Chances,' a transporter accident on Nervala IV eight years earlier created Thomas Riker, an exact duplicate of Will who lived stranded on the planet."},{"id":"TNG-098","series":"TNG","difficulty":"hard","type":"true_false","category":"Planets & Locations","question":"The Battle of Khitomer was a Romulan attack on a Klingon outpost.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The 2346 Khitomer massacre was a Romulan surprise attack on the Klingon colony, killing some 4,000 including Worf's parents Mogh and Kaasin."},{"id":"TNG-099","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"What is the name of the main navigational deflector dish's primary purpose?","answers":{"A":"Propulsion boost","B":"Sensor enhancement","C":"Clearing debris from the ship's path at warp","D":"Weapons targeting"},"correct":"C","explanation":"The navigational deflector projects a forward field to sweep micrometeoroids and interstellar debris from the ship's path at high warp; the TNG Technical Manual details its role."},{"id":"TNG-100","series":"TNG","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"In 'The Nth Degree,' Barclay is temporarily enhanced by an alien probe to superhuman intelligence.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"A Cytherian probe boosts Lt. Reginald Barclay's intellect to the point where he interfaces directly with the Enterprise computer, allowing the ship to reach the galactic center."},{"id":"TNG-101","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Which actor plays Captain Jean-Luc Picard in TNG?","answers":{"A":"Brent Spiner","B":"Patrick Stewart","C":"Jonathan Frakes","D":"Michael Dorn"},"correct":"B","explanation":"Patrick Stewart played Picard across all 7 TNG seasons (1987-1994), four feature films, and the Paramount+ series Star Trek: Picard (2020-2023)."},{"id":"TNG-102","series":"TNG","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"The Enterprise-D is a Galaxy-class ship designed to carry families and civilians, not just Starfleet personnel.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Galaxy-class starships were designed for long-duration deep-space exploration with families aboard, including children's schools, civilian residential quarters, and amenities like Ten Forward."},{"id":"TNG-103","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What is the title of TNG's two-part pilot episode?","answers":{"A":"Where No One Has Gone Before","B":"The Naked Now","C":"Encounter at Farpoint","D":"All Good Things..."},"correct":"C","explanation":"'Encounter at Farpoint' (1987) introduces Picard's crew, the Enterprise-D, and the omnipotent Q, who puts humanity on trial — a story line bookended by the finale 'All Good Things...' seven seasons later."},{"id":"TNG-104","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What is Dr. Crusher's first name?","answers":{"A":"Deanna","B":"Beverly","C":"Christine","D":"Katherine"},"correct":"B","explanation":"Beverly Howard Crusher serves as the Enterprise-D's Chief Medical Officer for most of the series and is the mother of Wesley Crusher."},{"id":"TNG-105","series":"TNG","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"Q first appears in TNG's pilot episode 'Encounter at Farpoint' and is the same character that returns throughout the series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Q (played by John de Lancie) debuts in 'Encounter at Farpoint' putting humanity on trial; he returns in episodes like 'Q Who,' 'Tapestry,' and the finale 'All Good Things...' as well as in Voyager and Picard."},{"id":"TNG-106","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"The Klingon greeting 'nuqneH' literally translates to which phrase?","answers":{"A":"Live well","B":"What do you want?","C":"Greetings, friend","D":"Honor be with you"},"correct":"B","explanation":"Klingon culture has no equivalent of casual pleasantries; 'nuqneH' (literally 'what do you want?') is the standard greeting, reflecting their direct martial culture."},{"id":"TNG-107","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Sins of the Father,' what does Worf accept in order to protect the Klingon Empire from civil war?","answers":{"A":"Exile from the Empire","B":"Death in ritual combat","C":"Discommendation — formal disgrace and severance from the House of Mogh","D":"Election as new Chancellor"},"correct":"C","explanation":"Worf accepts discommendation to conceal the true traitor — Ja'rod of the House of Duras — preserving political stability. The disgrace is later lifted in 'Redemption.'"},{"id":"TNG-108","series":"TNG","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"A Galaxy-class starship like the Enterprise-D has 42 decks.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Per the Star Trek: The Next Generation Technical Manual and on-screen references, Galaxy-class starships have 42 decks across the saucer and stardrive sections."},{"id":"TNG-109","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"In which feature film does Picard finally confront the Borg Queen?","answers":{"A":"Star Trek: Generations","B":"Star Trek: First Contact","C":"Star Trek: Insurrection","D":"Star Trek: Nemesis"},"correct":"B","explanation":"Star Trek: First Contact (1996) introduces the Borg Queen (Alice Krige), whom Picard ultimately defeats while protecting Zefram Cochrane's first warp flight in 2063."},{"id":"TNG-110","series":"TNG","difficulty":"hard","type":"true_false","category":"Timeline & History","question":"Star Trek: First Contact depicts the historical first meeting between humans and Vulcans on April 5, 2063.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Vulcans detect Zefram Cochrane's warp flight from the Phoenix and land in Bozeman, Montana — establishing the canonical First Contact date that Picard references throughout TNG."},{"id":"TNG-111","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Quotes & Catchphrases","question":"What two-word phrase does Picard often use to address his first officer, Commander Riker?","answers":{"A":"Number One","B":"Mister Riker","C":"Commander Will","D":"First Officer"},"correct":"A","explanation":"Picard regularly calls Riker 'Number One,' a traditional naval term for the first officer, used throughout TNG beginning with 'Encounter at Farpoint.'"},{"id":"TNG-112","series":"TNG","difficulty":"easy","type":"true_false","category":"Quotes & Catchphrases","question":"Geordi La Forge's signature phrase when frustrated by engineering problems is the line 'I'm a doctor, not a bricklayer.'","answers":{"A":"True","B":"False"},"correct":"B","explanation":"'I'm a doctor, not a...' is Dr. McCoy's TOS catchphrase, not Geordi's; Geordi is an engineer and has no such line."},{"id":"TNG-113","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Quotes & Catchphrases","question":"Worf frequently recommends which course of action to threats, becoming a running characterization?","answers":{"A":"Raising shields and retreating","B":"Firing photon torpedoes / engaging the enemy","C":"Negotiating a truce","D":"Hailing for reinforcements"},"correct":"B","explanation":"Worf habitually advocates aggressive tactics such as firing torpedoes or boarding, a recurring trait often overruled by Picard throughout TNG."},{"id":"TNG-114","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Quotes & Catchphrases","question":"In 'The Best of Both Worlds,' what does the assimilated Picard (Locutus) tell the Enterprise crew about resistance and their goal?","answers":{"A":"'You will be assimilated. Your culture will adapt to service us.'","B":"'Surrender your vessel or be destroyed.'","C":"'We are the beginning and the end.'","D":"'Your weapons are useless against us.'"},"correct":"A","explanation":"As Locutus in 'The Best of Both Worlds, Part I,' Picard declares that resistance is futile and that human culture will adapt to service the Borg."},{"id":"TNG-115","series":"TNG","difficulty":"medium","type":"true_false","category":"Crossovers & Connections","question":"Chief Miles O'Brien marries Keiko, a botanist, while still serving aboard the Enterprise-D.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"O'Brien marries botanist Keiko Ishikawa in the Season 4 episode 'Data's Day' aboard the Enterprise-D, before the family transfers to Deep Space 9."},{"id":"TNG-116","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"Which legendary TOS character appears in the TNG two-part episode 'Unification'?","answers":{"A":"Captain Kirk","B":"Dr. McCoy","C":"Ambassador Spock","D":"Montgomery Scott"},"correct":"C","explanation":"Leonard Nimoy reprises Spock in 'Unification,' where the Vulcan ambassador is found on Romulus pursuing reunification of the Romulan and Vulcan peoples."},{"id":"TNG-117","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"Which original-series-era character appears in TNG's pilot 'Encounter at Farpoint' as a very elderly admiral?","answers":{"A":"Montgomery Scott","B":"Leonard McCoy","C":"Hikaru Sulu","D":"Spock"},"correct":"B","explanation":"DeForest Kelley cameos as a 137-year-old Admiral Leonard McCoy touring the Enterprise-D in 'Encounter at Farpoint,' linking TNG to the original crew."},{"id":"TNG-118","series":"TNG","difficulty":"medium","type":"true_false","category":"Crossovers & Connections","question":"Worf later became a main cast member of Star Trek: Deep Space Nine after TNG ended.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Michael Dorn's Worf joined the DS9 main cast in its fourth season (1995), making Worf the only character to be a regular on two Star Trek series."},{"id":"TNG-119","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"Which recurring TNG character was later carried over as a recurring character on Star Trek: Voyager, bridging the two 24th-century series?","answers":{"A":"Guinan","B":"Lwaxana Troi","C":"Chief O'Brien","D":"Reginald Barclay"},"correct":"D","explanation":"Lt. Reginald Barclay, introduced in TNG's 'Hollow Pursuits,' became a recurring character on Star Trek: Voyager, where his work on Project Pathfinder helped restore contact with the lost ship. (O'Brien instead moved to DS9.)"},{"id":"TNG-120","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"What is Data's rank for most of TNG?","answers":{"A":"Lieutenant","B":"Commander","C":"Lieutenant Commander","D":"Ensign"},"correct":"C","explanation":"Data holds the rank of Lieutenant Commander throughout TNG, serving as second officer and operations officer aboard the Enterprise-D."},{"id":"TNG-121","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"At what rank does Wesley Crusher serve when he is formally given the position of acting ensign?","answers":{"A":"Cadet","B":"Acting Ensign","C":"Lieutenant Junior Grade","D":"Crewman"},"correct":"B","explanation":"Picard appoints Wesley an 'acting ensign' in 'Where No One Has Gone Before,' allowing him to serve on the bridge before he formally enters Starfleet Academy."},{"id":"TNG-122","series":"TNG","difficulty":"medium","type":"true_false","category":"Starfleet Ranks & Protocol","question":"In 'The Measure of a Man,' the hearing must determine whether Data is the property of Starfleet or has the right to refuse a procedure.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The JAG hearing in 'The Measure of a Man' decides whether Data is Starfleet property who can be ordered to be disassembled, or a sentient being with self-determination."},{"id":"TNG-123","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"In 'Chain of Command,' who temporarily takes command of the Enterprise-D while Picard is on a covert mission?","answers":{"A":"Commander Riker","B":"Captain Edward Jellico","C":"Admiral Nechayev","D":"Captain Morgan Bateson"},"correct":"B","explanation":"Captain Edward Jellico assumes command of the Enterprise-D in 'Chain of Command, Part I,' clashing with the crew over his rigid style while Picard goes undercover."},{"id":"TNG-124","series":"TNG","difficulty":"easy","type":"true_false","category":"Starfleet Ranks & Protocol","question":"Commander Riker holds the rank of Commander for most of TNG.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"William Riker serves as a Commander and first officer throughout TNG, repeatedly declining promotion to captain of his own ship."},{"id":"TNG-125","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Drumhead,' a retired admiral conducts a paranoid witch-hunt aboard the Enterprise. What is her name?","answers":{"A":"Admiral Nechayev","B":"Admiral Satie","C":"Admiral Haftel","D":"Admiral Quinn"},"correct":"B","explanation":"Retired Admiral Norah Satie leads an escalating investigation into alleged conspiracy in 'The Drumhead,' which Picard ultimately condemns as a threat to civil liberties."},{"id":"TNG-126","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Lower Decks,' the episode focuses on which group of characters?","answers":{"A":"The senior staff","B":"Junior officers and enlisted crew","C":"Visiting Klingon dignitaries","D":"The ship's children"},"correct":"B","explanation":"'Lower Decks' tells the story from the perspective of junior officers like Ensign Sito Jaxa and Sam Lavelle, contrasting their view with the senior staff."},{"id":"TNG-127","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Cause and Effect,' which starship emerges from the temporal distortion and collides with the Enterprise-D?","answers":{"A":"USS Bozeman","B":"USS Yamato","C":"USS Hathaway","D":"USS Brattain"},"correct":"A","explanation":"The USS Bozeman, a Soyuz-class ship commanded by Captain Morgan Bateson and lost for 90 years, emerges from the rift and collides with the Enterprise in 'Cause and Effect.'"},{"id":"TNG-128","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Naked Now,' the crew is affected by what condition?","answers":{"A":"A telepathic plague","B":"An intoxicating illness that lowers inhibitions","C":"Rapid aging","D":"Memory loss"},"correct":"B","explanation":"'The Naked Now,' an homage to TOS's 'The Naked Time,' has a polywater intoxicant spread through the crew, removing their inhibitions."},{"id":"TNG-129","series":"TNG","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Hollow Pursuits,' Lieutenant Barclay creates holodeck fantasies featuring caricatures of the Enterprise crew.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Hollow Pursuits,' the socially anxious Reginald Barclay escapes into holodeck programs depicting idealized versions of himself defeating the senior staff."},{"id":"TNG-130","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the name of the symbiotic species whose hosts carry a long-lived joined organism, introduced in TNG's 'The Host'?","answers":{"A":"Trill","B":"Betazoid","C":"El-Aurian","D":"Changeling"},"correct":"A","explanation":"The Trill, a joined species blending humanoid host and symbiont, are first introduced in TNG's 'The Host' before becoming central to DS9's Dax."},{"id":"TNG-131","series":"TNG","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"The Q Continuum is the extra-dimensional realm inhabited by Q and other members of his species.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Q hails from the Q Continuum, a realm of near-omnipotent beings; it is named throughout TNG and visited in later Trek series."},{"id":"TNG-132","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"In 'Conspiracy,' what kind of creatures secretly infiltrate Starfleet Command?","answers":{"A":"Shapeshifting Founders","B":"Parasitic neural beings that control hosts","C":"Cloaked Romulan agents","D":"Borg drones"},"correct":"B","explanation":"In 'Conspiracy,' parasitic alien creatures attach to and control Starfleet officers via a 'mother' creature, a rare graphically violent TNG episode."},{"id":"TNG-133","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"On which planet does Picard's family own a vineyard?","answers":{"A":"On Earth, in La Barre, France","B":"On Risa","C":"On Mars","D":"On Alpha Centauri"},"correct":"A","explanation":"The Picard family runs the Chateau Picard vineyard in La Barre, France, on Earth, shown in 'Family' when Picard returns home after his Borg ordeal."},{"id":"TNG-134","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Planets & Locations","question":"At which star system does Starfleet make a doomed last stand against the Borg, an event referenced repeatedly in TNG and DS9?","answers":{"A":"Wolf 359","B":"Sector 001","C":"Maxia Zeta","D":"Minos Korva"},"correct":"A","explanation":"The Battle of Wolf 359, where 39 starships were destroyed by the Borg cube led by Locutus, is referenced in 'The Best of Both Worlds, Part II' and depicted in DS9's 'Emissary.'"},{"id":"TNG-135","series":"TNG","difficulty":"easy","type":"true_false","category":"Planets & Locations","question":"Risa is depicted in TNG as a famous pleasure resort planet.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Risa, the tropical resort world, is featured in TNG episodes such as 'Captain's Holiday,' where Picard takes a vacation and encounters Vash."},{"id":"TNG-136","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Planets & Locations","question":"In 'The Inner Light,' what is the name of the doomed planet whose civilization preserves itself in a memory probe?","answers":{"A":"Kataan","B":"Ressik","C":"Tanagra","D":"Ohniaka"},"correct":"A","explanation":"The planet Kataan launches a probe before its sun goes nova; the probe gives Picard a lifetime of memories as Kamin in the village of Ressik."},{"id":"TNG-137","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"Who is the recurring Romulan commander who repeatedly faces off against Picard, including in 'The Defector'?","answers":{"A":"Tomalak","B":"Jarok","C":"Tebok","D":"Mendak"},"correct":"A","explanation":"Commander Tomalak is a recurring Romulan adversary who confronts Picard in episodes including 'The Enemy,' 'The Defector,' and the finale 'All Good Things...'"},{"id":"TNG-138","series":"TNG","difficulty":"medium","type":"true_false","category":"Villains & Antagonists","question":"The Duras sisters, Lursa and B'Etor, attempt to seize power in the Klingon Empire and later appear in Star Trek: Generations.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Lursa and B'Etor of the House of Duras instigate the Klingon civil war in 'Redemption' and return as villains in the film Star Trek: Generations."},{"id":"TNG-139","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"In 'Q Who,' Q flings the Enterprise-D 7,000 light-years to introduce the crew to which threat?","answers":{"A":"The Dominion","B":"The Borg","C":"Species 8472","D":"The Romulans"},"correct":"B","explanation":"In 'Q Who,' Q hurls the Enterprise into the path of a Borg cube in the Delta Quadrant, giving the Federation its first direct, deadly encounter with the Borg."},{"id":"TNG-140","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Which actor portrays the android Data in TNG?","answers":{"A":"Jonathan Frakes","B":"Brent Spiner","C":"Wil Wheaton","D":"LeVar Burton"},"correct":"B","explanation":"Brent Spiner plays Data throughout TNG and the films, also portraying Lore, B-4, and Dr. Noonien Soong."},{"id":"TNG-141","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"LeVar Burton, who plays Geordi La Forge, was also the host of the children's show 'Reading Rainbow.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"LeVar Burton, who portrays Chief Engineer Geordi La Forge, hosted the long-running PBS series 'Reading Rainbow' for over two decades."},{"id":"TNG-142","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the half-Klingon Federation ambassador who is the mother of Worf's son?","answers":{"A":"K'Ehleyr","B":"Jadzia","C":"Grilka","D":"Sirella"},"correct":"A","explanation":"K'Ehleyr, a half-human, half-Klingon Federation envoy, is the mother of Worf's son Alexander; she appears in 'The Emissary' and is killed by Duras in 'Reunion.'"},{"id":"TNG-143","series":"TNG","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Nurse Alyssa Ogawa works in sickbay under Dr. Crusher aboard the Enterprise-D.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Nurse Alyssa Ogawa, played by Patti Yasutake, is a recurring medical staffer assisting Dr. Crusher in TNG's later seasons and the films."},{"id":"TNG-144","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Ships & Technology","question":"What handheld device do Starfleet officers use to scan and analyze their environment?","answers":{"A":"Phaser","B":"Tricorder","C":"PADD","D":"Communicator"},"correct":"B","explanation":"The tricorder is a multifunction handheld sensor and computing device used for scientific, medical, and engineering analysis throughout TNG."},{"id":"TNG-145","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"In 'Booby Trap' and other episodes, Geordi works with a holographic recreation of which warp-field engineer?","answers":{"A":"Zefram Cochrane","B":"Leah Brahms","C":"Katherine Pulaski","D":"Reginald Barclay"},"correct":"B","explanation":"In 'Booby Trap,' Geordi consults a holodeck recreation of warp-systems designer Dr. Leah Brahms; he later meets the real Brahms in 'Galaxy's Child.'"},{"id":"TNG-146","series":"TNG","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"A shuttlecraft is a small vessel used for short-range travel when the transporter cannot be used.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Enterprise-D carries shuttlecraft in its shuttlebays for short-range transport, often used when transporters are unavailable or unsafe, as in many TNG episodes."},{"id":"TNG-147","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Timeline & History","question":"In what year does TNG's first season begin, according to onscreen stardates?","answers":{"A":"2264","B":"2364","C":"2151","D":"2399"},"correct":"B","explanation":"'Encounter at Farpoint' establishes the start of TNG in 2364, placing the series in the 24th century."},{"id":"TNG-148","series":"TNG","difficulty":"easy","type":"true_false","category":"Timeline & History","question":"Before commanding the Enterprise-D, Picard captained the USS Stargazer for over twenty years.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Picard commanded the Constellation-class USS Stargazer for roughly 22 years until it was lost at Maxia, an event examined in 'The Battle.'"},{"id":"TNG-149","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Timeline & History","question":"The 'Maxia Zeta' incident, in which Picard lost his previous ship, gave rise to a famous evasive starship tactic named after him. What is it called?","answers":{"A":"The Riker Maneuver","B":"The Picard Maneuver","C":"The Kolvoord Starburst","D":"The Corbomite Maneuver"},"correct":"B","explanation":"When the Stargazer was attacked at Maxia, Picard jumped to warp to appear in two places at once; this 'Picard Maneuver' is a plot point in 'The Battle.'"},{"id":"TNG-150","series":"TNG","difficulty":"easy","type":"true_false","category":"Episodes & Story Arcs","question":"TNG ran for seven seasons before concluding with its series finale.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Star Trek: The Next Generation aired seven seasons from 1987 to 1994, ending with the two-hour finale 'All Good Things...'"},{"id":"TNG-151","series":"TNG","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"The USS Enterprise-E (NCC-1701-E), Picard's ship after the Enterprise-D, is a Sovereign-class starship.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Sovereign-class Enterprise-E was launched in 2372 and served as the crew's ship in Star Trek: First Contact, Insurrection, and Nemesis."},{"id":"TNG-152","series":"TNG","difficulty":"easy","type":"multiple_choice","category":"Crossovers & Connections","question":"In which feature film did the USS Enterprise-E make its first appearance?","answers":{"A":"Star Trek: Generations","B":"Star Trek: First Contact","C":"Star Trek: Insurrection","D":"Star Trek: Nemesis"},"correct":"B","explanation":"The Sovereign-class Enterprise-E debuted in Star Trek: First Contact (1996), replacing the Enterprise-D lost in Star Trek: Generations."},{"id":"TNG-153","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"In Star Trek: Generations, the villain Dr. Tolian Soran is a member of which species?","answers":{"A":"Klingon","B":"Romulan","C":"El-Aurian","D":"Cardassian"},"correct":"C","explanation":"In Star Trek: Generations, Soran (played by Malcolm McDowell) is an El-Aurian, like Guinan, obsessed with returning to the Nexus after losing his family to the Borg."},{"id":"TNG-154","series":"TNG","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In the episode 'Sarek,' the ailing Vulcan ambassador performs a mind meld with which Enterprise crew member to maintain his composure during a critical conference?","answers":{"A":"Captain Picard","B":"Commander Data","C":"Counselor Troi","D":"Doctor Crusher"},"correct":"A","explanation":"In 'Sarek' (Season 3), Sarek's Bendii Syndrome causes emotional outbursts, so he mind melds with Picard, who endures Sarek's pent-up emotions during the Legaran conference."},{"id":"TNG-155","series":"TNG","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"What is the registry number of the USS Stargazer, the Constellation-class ship Picard commanded before the Enterprise-D?","answers":{"A":"NCC-2893","B":"NCC-1701","C":"NCC-7100","D":"NCC-1864"},"correct":"A","explanation":"The USS Stargazer was a Constellation-class starship with registry NCC-2893; Picard commanded her for 22 years until the Battle of Maxia in 2355."},{"id":"DS9-001","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who is the commanding officer of Deep Space 9 at the start of the series?","answers":{"A":"Odo","B":"Jadzia Dax","C":"Benjamin Sisko","D":"Kira Nerys"},"correct":"C","explanation":"Commander (later Captain) Benjamin Sisko is assigned to command DS9 in the pilot episode 'Emissary,' overseeing the former Cardassian station Terok Nor after the Bajoran withdrawal."},{"id":"DS9-002","series":"DS9","difficulty":"easy","type":"true_false","category":"Planets & Locations","question":"Deep Space 9 is located near the entrance to a stable wormhole.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Emissary,' Sisko and Dax discover the Bajoran wormhole, the only known stable wormhole in the galaxy, leading to the Gamma Quadrant. The station is later moved adjacent to its mouth."},{"id":"DS9-003","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What species is Odo?","answers":{"A":"Bajoran","B":"Cardassian","C":"Ferengi","D":"Changeling/Founder"},"correct":"D","explanation":"Odo is a Changeling, one of the shape-shifting Founders of the Dominion, though he was raised in the Alpha Quadrant by Bajoran scientist Dr. Mora Pol and discovers his origins in 'The Search.'"},{"id":"DS9-004","series":"DS9","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Kira Nerys is a Bajoran who serves as Sisko's first officer.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Major Kira, a former Bajoran resistance fighter, is assigned as the Bajoran liaison and station first officer in 'Emissary,' and serves in that role throughout the series."},{"id":"DS9-005","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What species are the Founders, the rulers of the Dominion?","answers":{"A":"Cardassians","B":"Jem'Hadar","C":"Changelings","D":"Vorta"},"correct":"C","explanation":"The Founders are Changelings—shapeshifting beings from the Gamma Quadrant who created the Dominion to bring order to the 'solids' they distrusted, as revealed in 'The Search, Part II.'"},{"id":"DS9-006","series":"DS9","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Quark is a Ferengi bar owner on Deep Space 9.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Quark runs Quark's Bar on the Promenade throughout the entire series, serving as a black-market hub, dabo gaming establishment, and source of recurring schemes."},{"id":"DS9-007","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Planets & Locations","question":"The wormhole near Deep Space 9 leads to which quadrant?","answers":{"A":"Beta Quadrant","B":"Delta Quadrant","C":"Gamma Quadrant","D":"Alpha Quadrant"},"correct":"C","explanation":"The Bajoran wormhole connects the Alpha Quadrant near Bajor to the Idran system in the Gamma Quadrant, opening trade and eventually contact with the Dominion."},{"id":"DS9-008","series":"DS9","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Jadzia Dax is a Trill who carries a symbiont.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Jadzia is a joined Trill, host to the Dax symbiont, which retains memories from its previous hosts including Curzon, who was a mentor to Sisko."},{"id":"DS9-009","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is Sisko's son's name?","answers":{"A":"Michael","B":"Aaron","C":"Jake","D":"Noah"},"correct":"C","explanation":"Jake Sisko, played by Cirroc Lofton, is Benjamin's teenage son who grew up on DS9, eventually becoming a journalist and writer."},{"id":"DS9-010","series":"DS9","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"The Jem'Hadar are genetically engineered soldiers of the Dominion addicted to a drug called Ketracel-white.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Jem'Hadar lack a key enzyme and are dependent on ketracel-white, which is dispensed by their Vorta supervisors—a built-in control mechanism designed by the Founders."},{"id":"DS9-011","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the Cardassian tailor and spy on DS9?","answers":{"A":"Dukat","B":"Damar","C":"Garak","D":"Weyoun"},"correct":"C","explanation":"Elim Garak, played by Andrew Robinson, runs a tailor shop on the Promenade after being exiled from Cardassia, but is a former operative of the Obsidian Order."},{"id":"DS9-012","series":"DS9","difficulty":"easy","type":"true_false","category":"Starfleet Ranks & Protocol","question":"Sisko is promoted from Commander to Captain during the DS9 series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Sisko is promoted from Commander to Captain in the Season 3 finale 'The Adversary,' following his commanding success against the Jem'Hadar earlier in the season."},{"id":"DS9-013","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What religion is central to Bajoran culture?","answers":{"A":"The Pah-wraith Cult","B":"The Way of the Prophets","C":"The Order of the Blessed Exchequer","D":"The Way of the Warrior"},"correct":"B","explanation":"Bajoran religion centers on worship of the Prophets, the non-linear beings residing in the wormhole, and on adherence to their teachings as preserved by Vedeks and Kais."},{"id":"DS9-014","series":"DS9","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Dr. Julian Bashir is the chief medical officer of Deep Space 9.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Dr. Julian Bashir, played by Alexander Siddig, is assigned as CMO in 'Emissary,' having graduated salutatorian of his Starfleet Medical class."},{"id":"DS9-015","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What is the name of Sisko's Starfleet runabout and later warship?","answers":{"A":"USS Voyager","B":"USS Orinoco","C":"USS Defiant","D":"USS Rio Grande"},"correct":"C","explanation":"The USS Defiant is the warship Sisko brings to DS9 in 'The Search' to confront the Dominion threat; it serves as the station's primary combat vessel throughout the war."},{"id":"DS9-016","series":"DS9","difficulty":"easy","type":"true_false","category":"Villains & Antagonists","question":"Gul Dukat was the Cardassian prefect of Bajor during the Occupation.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Dukat served as Prefect of Bajor and commander of Terok Nor during the latter years of the Cardassian Occupation, a fact established in 'Emissary' and reinforced throughout the series."},{"id":"DS9-017","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Planets & Locations","question":"Deep Space 9 was originally built by which power?","answers":{"A":"The Dominion","B":"The Federation","C":"The Cardassians","D":"The Bajoran Resistance"},"correct":"C","explanation":"The station was constructed by Bajoran slave labor under Cardassian supervision and named Terok Nor; it was abandoned when the Cardassians withdrew from Bajor and was then turned over to Starfleet/Bajoran joint administration."},{"id":"DS9-018","series":"DS9","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Miles O'Brien serves as Chief of Operations on Deep Space 9.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Chief Miles Edward O'Brien transfers from the Enterprise-D in 'Emissary' to become DS9's Chief of Operations, responsible for the aging Cardassian station's failing systems."},{"id":"DS9-019","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What do Bajorans wear on their ears as a sign of their faith?","answers":{"A":"A simple gold ring","B":"A comm badge shaped like a sun","C":"A silver chain","D":"Earrings called d'ja pagh"},"correct":"D","explanation":"Bajorans wear an earring on the right ear as a sign of their faith; clerics use it to read a Bajoran's pagh (spirit) by grasping the ear."},{"id":"DS9-020","series":"DS9","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Sisko is known to the Bajorans as the Emissary of the Prophets.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"After meeting the wormhole aliens in 'Emissary,' Sisko is recognized by Kai Opaka and the Bajoran people as the prophesied Emissary, a role he accepts with increasing seriousness."},{"id":"DS9-021","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What major interstellar conflict dominates the later seasons of DS9?","answers":{"A":"The Borg Invasion","B":"The Cardassian Uprising","C":"The Klingon Civil War","D":"The Dominion War"},"correct":"D","explanation":"The Dominion War, fought between the Federation/Klingon/Romulan alliance and the Dominion/Cardassian/Breen forces, spans roughly seasons 5-7 and dominates the show's serialized arcs."},{"id":"DS9-022","series":"DS9","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Worf joins the crew of Deep Space 9 in Season 4.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Worf transfers to DS9 in the Season 4 premiere 'The Way of the Warrior' to assist Sisko in handling Klingon Empire tensions after the Khitomer Accords are jeopardized."},{"id":"DS9-023","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the Ferengi holy text that governs all commerce?","answers":{"A":"The Sacred Marketplace","B":"The Grand Nagus Scrolls","C":"The Book of Ferengi","D":"The Rules of Acquisition"},"correct":"D","explanation":"The 285 Rules of Acquisition codify Ferengi business ethics, with Rule #1 being 'Once you have their money, you never give it back.' Quark frequently quotes them throughout the series."},{"id":"DS9-024","series":"DS9","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Quark's brother is Rom, and Rom's son is Nog.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Rom is Quark's younger brother who works as a waiter and later engineer, and his son Nog becomes Jake Sisko's best friend and the first Ferengi in Starfleet."},{"id":"DS9-025","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who is the Grand Nagus of the Ferengi Alliance at the start of DS9?","answers":{"A":"Zek","B":"Brunt","C":"Ishka","D":"Rom"},"correct":"A","explanation":"Grand Nagus Zek, the eccentric leader of Ferengi commerce, is introduced in 'The Nagus' (Season 1) and recurs throughout the series before retiring and naming Rom his successor."},{"id":"DS9-026","series":"DS9","difficulty":"easy","type":"true_false","category":"Villains & Antagonists","question":"The Vorta act as administrators and diplomats for the Dominion.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Vorta serve as field supervisors, diplomats, and Jem'Hadar commanders for the Founders, occupying the middle administrative tier of Dominion society."},{"id":"DS9-027","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Planets & Locations","question":"What is the name of the planet Bajor's neighboring Cardassian-held system?","answers":{"A":"The Badlands","B":"Terok Nor","C":"Klingon Outpost","D":"Cardassia Prime"},"correct":"D","explanation":"Cardassia Prime is the Cardassian Union's homeworld and seat of government, neighboring Bajor and serving as the political center of Cardassian power."},{"id":"DS9-028","series":"DS9","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"The USS Defiant is equipped with a cloaking device borrowed from the Romulans.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'The Search,' the Romulans loan a cloaking device to the Defiant in exchange for intelligence on the Dominion, with the restriction it only be used in the Gamma Quadrant."},{"id":"DS9-029","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is Odo's primary role on Deep Space 9?","answers":{"A":"Chief Engineer","B":"Security Chief","C":"Chief Medical Officer","D":"Science Officer"},"correct":"B","explanation":"Odo serves as Chief of Security on DS9, a position he held under Cardassian rule on Terok Nor and continued under Starfleet/Bajoran administration."},{"id":"DS9-030","series":"DS9","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Sisko has a passion for cooking and operates a restaurant later in the series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Sisko's father, Joseph, owns Sisko's Creole Kitchen in New Orleans, and Benjamin is depicted as an enthusiastic Creole cook throughout the series, frequently preparing meals for family and crew."},{"id":"DS9-031","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What ancient Bajoran orb artifacts are said to be gifts from the Prophets?","answers":{"A":"The Orbs of the Prophets","B":"The Sacred Relics","C":"The Tears of the Prophets","D":"The Prophet Stones"},"correct":"C","explanation":"The Tears of the Prophets are nine orbs of Bajoran scripture, each granting visions and considered sacred gifts from the wormhole aliens; the Season 6 finale episode is also titled 'Tears of the Prophets.'"},{"id":"DS9-032","series":"DS9","difficulty":"easy","type":"true_false","category":"Episodes & Story Arcs","question":"DS9 was the first Star Trek series to feature a continuing serialized storyline.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"DS9 was the first Star Trek series to embrace heavy serialization, particularly through the multi-episode Dominion War arc spanning seasons 5-7—a stark departure from the episodic format of TOS and TNG."},{"id":"DS9-033","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who replaces Jadzia Dax as the Dax symbiont host?","answers":{"A":"Joran","B":"Ezri","C":"Tobin","D":"Curzon"},"correct":"B","explanation":"After Jadzia's death in 'Tears of the Prophets,' the Dax symbiont is hastily joined to counselor-in-training Ezri Tigan, who joins the DS9 crew in Season 7's 'Shadows and Symbols.'"},{"id":"DS9-034","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"How many previous hosts did the Dax symbiont have before Jadzia?","answers":{"A":"5","B":"6","C":"7","D":"8"},"correct":"C","explanation":"Jadzia is Dax's eighth host, preceded by seven prior hosts: Lela, Tobin, Emony, Audrid, Torias, Joran, and Curzon, as established across multiple episodes including 'Equilibrium' and 'Facets.'"},{"id":"DS9-035","series":"DS9","difficulty":"medium","type":"true_false","category":"Villains & Antagonists","question":"Weyoun is a Vorta who serves as an ambassador and administrator for the Dominion.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Weyoun, played by Jeffrey Combs, appears in multiple cloned iterations as the chief Vorta diplomat and supervisor of Dominion operations in the Alpha Quadrant during the war."},{"id":"DS9-036","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In which episode do Sisko and the crew discover the truth about Section 31?","answers":{"A":"Inter Arma Enim Silent Leges","B":"Inquisition","C":"Extreme Measures","D":"Homefront"},"correct":"B","explanation":"Section 31 is first revealed in the Season 6 episode 'Inquisition,' when Director Sloan kidnaps Bashir to recruit him, exposing the existence of the autonomous black-ops agency."},{"id":"DS9-037","series":"DS9","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"Changelings revert to a gelatinous state when they regenerate.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Changelings must return to their natural liquid form roughly every 16 hours to regenerate; Odo originally used a bucket for this purpose before receiving more sophisticated quarters."},{"id":"DS9-038","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"What is the name of the Changeling homeworld?","answers":{"A":"Omarion Nebula","B":"The Great Link","C":"The Link","D":"The Founders' World"},"correct":"A","explanation":"The Founders originally lived on a planet within the Omarion Nebula in the Gamma Quadrant; this world is destroyed by the Tal Shiar/Obsidian Order fleet in 'The Die is Cast,' after which they relocate to a new homeworld."},{"id":"DS9-039","series":"DS9","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Bashir was genetically enhanced as a child without Starfleet's knowledge.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Doctor Bashir, I Presume,' it is revealed that Julian's parents had him genetically enhanced as a child—illegal under Federation law since the Eugenics Wars—and he had concealed the fact for his entire Starfleet career."},{"id":"DS9-040","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"What secret Cardassian intelligence organization does Garak work for?","answers":{"A":"The Tal Shiar","B":"Section 31","C":"The Obsidian Order","D":"The Cardassian Guard"},"correct":"C","explanation":"Garak was an operative of the Obsidian Order, the Cardassian intelligence agency feared throughout the quadrant; he was exiled by Enabran Tain and stationed himself on DS9 as a 'plain, simple tailor.'"},{"id":"DS9-041","series":"DS9","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Trials and Tribble-ations,' the DS9 crew travels back in time to the original Star Trek episode 'The Trouble with Tribbles.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The 30th anniversary episode 'Trials and Tribble-ations' inserts the DS9 crew into TOS footage from 'The Trouble with Tribbles,' as they pursue a Klingon Arne Darvin trying to assassinate Kirk."},{"id":"DS9-042","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Ships & Technology","question":"What class of starship is the USS Defiant?","answers":{"A":"Intrepid-class","B":"Excelsior-class","C":"Galaxy-class","D":"Defiant-class"},"correct":"D","explanation":"The USS Defiant (NX-74205) is the prototype of the Defiant-class, a compact escort/warship developed in response to the Borg threat after Wolf 359."},{"id":"DS9-043","series":"DS9","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Jadzia Dax and Worf get married during the DS9 series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Worf and Jadzia marry in 'You Are Cordially Invited' in Season 6, following an extended Klingon courtship that began after his transfer to DS9."},{"id":"DS9-044","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the communal merging of Changelings called?","answers":{"A":"The Merging","B":"The Collective","C":"The Confluence","D":"The Great Link"},"correct":"D","explanation":"The Great Link is the communal merging of Changelings into a shared sea of consciousness, in which individual identity dissolves; Odo experiences it for the first time in 'The Search.'"},{"id":"DS9-045","series":"DS9","difficulty":"medium","type":"true_false","category":"Villains & Antagonists","question":"Dukat eventually becomes possessed by a Pah-wraith.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Dukat allies with and is later possessed by the Pah-wraiths, the banished enemies of the Prophets, in his descent into religious fanaticism culminating in the series finale 'What You Leave Behind.'"},{"id":"DS9-046","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What is the name of the mirror universe recurring storyline in DS9?","answers":{"A":"Through the Looking Glass","B":"The Looking Glass War","C":"Mirror Universe","D":"Crossover"},"correct":"D","explanation":"The Season 2 episode 'Crossover' established DS9's recurring Mirror Universe storyline, which continued in 'Through the Looking Glass,' 'Shattered Mirror,' 'Resurrection,' and 'The Emperor's New Cloak.'"},{"id":"DS9-047","series":"DS9","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Sisko's mother was revealed to be a Prophet who inhabited a human body.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Image in the Sand' and 'Shadows and Symbols,' it is revealed that Sisko's birth mother Sarah was a Prophet who possessed a human woman to ensure Benjamin's birth as the Emissary."},{"id":"DS9-048","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"Section 31 is described as which type of Starfleet organization?","answers":{"A":"A rogue intelligence organization operating outside Federation law","B":"A diplomatic corps","C":"An elite special forces unit","D":"A judicial oversight body"},"correct":"A","explanation":"Section 31, named for the section of the Starfleet Charter authorizing extraordinary measures, operates autonomously and outside Federation law, as established in 'Inquisition' and explored in subsequent episodes."},{"id":"DS9-049","series":"DS9","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"Nog becomes the first Ferengi to join Starfleet.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Heart of Stone' Nog requests Sisko's recommendation to the Academy, becoming the first Ferengi in Starfleet; he is later commissioned as an ensign and promoted to lieutenant by the series end."},{"id":"DS9-050","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"Who kills Jadzia Dax?","answers":{"A":"Weyoun","B":"Garak","C":"Dukat (possessed by a Pah-wraith)","D":"A Jem'Hadar soldier"},"correct":"C","explanation":"In the Season 6 finale 'Tears of the Prophets,' Dukat—then possessed by a Pah-wraith—murders Jadzia in the DS9 temple while attempting to seal the wormhole."},{"id":"DS9-051","series":"DS9","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"Cardassians have a deeply authoritarian government with strong military control.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Cardassian Union is governed by the Central Command (military) and the Obsidian Order (intelligence) with the Detapa Council ostensibly civilian; their society values duty, obedience, and family above all."},{"id":"DS9-052","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"What is the original Cardassian name for Deep Space 9?","answers":{"A":"Korma Station","B":"Terok Nor","C":"Cardassia Outpost Alpha","D":"Empok Nor"},"correct":"B","explanation":"DS9 was originally Terok Nor, a Cardassian-built mining and processing station in orbit over Bajor during the Occupation; it was renamed when Bajor invited Starfleet to administer it."},{"id":"DS9-053","series":"DS9","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Damar starts as a loyal Cardassian officer but eventually leads a resistance against the Dominion.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Initially Dukat's loyal aide, Corat Damar succeeds him as Cardassian leader under the Dominion, but in Season 7 he founds the Cardassian Rebellion against Weyoun, dying in the final assault on Cardassia."},{"id":"DS9-054","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Ships & Technology","question":"What unique weapon system does the Defiant use that most Federation ships lack?","answers":{"A":"Transphasic torpedoes","B":"Quantum resonance charges","C":"Pulse phaser cannons","D":"Tricobalt devices"},"correct":"C","explanation":"The Defiant is equipped with rapid-fire pulse phaser cannons rather than standard phaser arrays, allowing it to deliver concentrated forward firepower against capital ships and fleets."},{"id":"DS9-055","series":"DS9","difficulty":"medium","type":"true_false","category":"Crossovers & Connections","question":"Worf's wedding to Jadzia took place on the holosuite program of a Klingon warrior's feast.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'You Are Cordially Invited,' Worf and Jadzia's wedding follows traditional Klingon ritual including the holosuite reenactment of Kahless and Lukara's stand at the Great Hall of Qam-Chee."},{"id":"DS9-056","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Visitor,' an adult Jake sacrifices his life for which purpose?","answers":{"A":"To save the wormhole","B":"To defeat the Dominion","C":"To prevent a Borg invasion","D":"To restore Sisko from temporal displacement"},"correct":"D","explanation":"In 'The Visitor,' an elderly Jake takes his own life to release his father from a subspace anomaly that had pulled Sisko out of normal time, restoring the original timeline."},{"id":"DS9-057","series":"DS9","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"The Pah-wraiths are the Bajoran equivalent of evil spirits or fallen Prophets.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Pah-wraiths are wormhole aliens banished from the Celestial Temple by the Prophets long ago, imprisoned in the Fire Caves of Bajor, and considered demonic spirits in Bajoran theology."},{"id":"DS9-058","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What is the first name of the Ferengi Grand Nagus who mentors Quark?","answers":{"A":"Krax","B":"Brunt","C":"Neebs","D":"Zek"},"correct":"D","explanation":"Grand Nagus Zek, played by Wallace Shawn, frequently visits DS9 and entrusts Quark with various commercial dealings; he ultimately retires and selects Rom as his successor in 'The Dogs of War.'"},{"id":"DS9-059","series":"DS9","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"The DS9 series finale is titled 'What You Leave Behind.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"'What You Leave Behind,' a feature-length double episode airing June 2, 1999, concludes the Dominion War, Sisko's destiny as the Emissary, and the series itself."},{"id":"DS9-060","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"What does Weyoun's species (Vorta) have a particular sensitivity to?","answers":{"A":"Telepathy","B":"Light","C":"Taste and flavor (they find most food bland)","D":"Sound frequencies"},"correct":"C","explanation":"Weyoun remarks several times (notably in 'Treachery, Faith and the Great River') that the Founders genetically engineered the Vorta with deliberately diminished aesthetic senses, including a poor sense of taste."},{"id":"DS9-061","series":"DS9","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Odo's mentor figure and father figure on DS9 is Kira Nerys.","answers":{"A":"True","B":"False"},"correct":"B","explanation":"Odo's mentor and father figure is the Bajoran scientist Dr. Mora Pol, who studied him as an unknown life form. Kira is Odo's eventual romantic partner, not his father figure."},{"id":"DS9-062","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"What Klingon ritual does Worf perform when a fellow warrior dies to scare away evil?","answers":{"A":"Mauk-to'Vor","B":"Hegh'bat","C":"Ak'voh","D":"Death Howl"},"correct":"D","explanation":"The Klingon death ritual involves the warrior's comrades opening the deceased's eyes and roaring at the sky to warn the dead that a Klingon warrior is arriving; first depicted in TNG's 'Heart of Glory' and reused throughout DS9."},{"id":"DS9-063","series":"DS9","difficulty":"medium","type":"true_false","category":"Timeline & History","question":"The Cardassian Occupation of Bajor lasted approximately 50 years.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Cardassian Occupation of Bajor lasted roughly 50 years (c. 2319 to 2369), ending shortly before the events of 'Emissary' and leaving Bajor traumatized and impoverished."},{"id":"DS9-064","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What is the name of the holosuite program Bashir and O'Brien frequently play together?","answers":{"A":"The Battle of Britain","B":"A spy thriller featuring Bond-like secret agents","C":"Dixon Hill","D":"James Bond"},"correct":"B","explanation":"Bashir and O'Brien frequently use the 'Julian Bashir, Secret Agent' holosuite program—a Bond-style 1960s spy fantasy—introduced in 'Our Man Bashir' in Season 4."},{"id":"DS9-065","series":"DS9","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Garak claims to be 'just a simple tailor' but is actually a former spy.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Garak repeatedly insists he is 'just a plain, simple tailor,' but is in fact a former operative of the Obsidian Order, the Cardassian intelligence service led by his father Enabran Tain."},{"id":"DS9-066","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"What Bajoran religious title is the head of the Bajoran faith given?","answers":{"A":"Ranjen","B":"Vedek","C":"Grand Kai","D":"Kai"},"correct":"D","explanation":"The Kai is the spiritual leader of the Bajoran people, elected by the Vedek Assembly; Kai Opaka, Kai Winn Adami, and Kai Bareil are featured during the series."},{"id":"DS9-067","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'In the Pale Moonlight,' Sisko justifies what morally questionable act?","answers":{"A":"Fabricating evidence to bring the Romulans into the Dominion War","B":"Destroying a Dominion supply depot in neutral space","C":"Torturing a Cardassian prisoner","D":"Assassinating Dukat"},"correct":"A","explanation":"In 'In the Pale Moonlight,' Sisko conspires with Garak to forge a Dominion attack plan that, after a Romulan senator's assassination, brings the Romulan Empire into the war against the Dominion. Sisko famously concludes 'I can live with it.'"},{"id":"DS9-068","series":"DS9","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Curzon Dax was a mentor to Benjamin Sisko.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Curzon Dax, the seventh Dax host and a Federation ambassador, was Sisko's mentor and close friend; their relationship continues into Sisko's friendship with Jadzia and is dramatized in 'Emissary' and 'Blood Oath.'"},{"id":"DS9-069","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"What substance do the Jem'Hadar require to survive that the Founders use to control them?","answers":{"A":"Dominion nectar","B":"Ketracel-white","C":"Isogenic enzyme","D":"Morphogenic enzyme"},"correct":"B","explanation":"Ketracel-white (also called 'the white') is the isogenic enzyme the Jem'Hadar lack and require to live; the Vorta dispense it via tubes in their necks, ensuring loyalty through chemical dependency."},{"id":"DS9-070","series":"DS9","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"The USS Defiant was originally designed to fight the Borg.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"As stated in 'The Search, Part I,' the Defiant was developed as a prototype warship to counter the Borg threat following the Battle of Wolf 359, though the program was mothballed before being reactivated for use against the Dominion."},{"id":"DS9-071","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of Odo's female Changeling adversary who is a Founder?","answers":{"A":"The Female Shapeshifter","B":"She has no name; known only as 'the Female Changeling'","C":"Laas","D":"The Founder"},"correct":"B","explanation":"The recurring Founder antagonist played by Salome Jens is never given a personal name on screen; she is credited and referred to only as 'the Female Changeling.'"},{"id":"DS9-072","series":"DS9","difficulty":"hard","type":"true_false","category":"Timeline & History","question":"The Dominion War results in the near-genocide of the Cardassian population.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'What You Leave Behind,' the Female Changeling orders the extermination of the Cardassian people as retribution for the rebellion; the Jem'Hadar slaughter two million Cardassians at Cardassia City in one action and intend to wipe out the population before the Dominion surrenders."},{"id":"DS9-073","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Far Beyond the Stars,' Sisko envisions himself as which character?","answers":{"A":"A slave on a colony world","B":"A prophet in ancient Bajor","C":"A Starfleet admiral in 1950s New York","D":"Benny Russell, a 1950s science fiction writer"},"correct":"D","explanation":"In 'Far Beyond the Stars,' Sisko experiences visions of being Benny Russell, a Black science fiction writer in 1950s New York whose story about a space station commander named Sisko is suppressed by his editor."},{"id":"DS9-074","series":"DS9","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"The Dax symbiont was once hosted by a murderer named Joran.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"As revealed in 'Equilibrium,' Joran Belar was the sixth Dax host, a violent murderer whose existence the Trill Symbiosis Commission concealed; Jadzia recovers his memories during the episode."},{"id":"DS9-075","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the Bajoran prophecy about the Emissary called?","answers":{"A":"The Emissary Scroll","B":"The First Prophecy","C":"The Ohalu Prophecy","D":"The Reckoning"},"correct":"D","explanation":"The Reckoning is the ancient Bajoran prophecy of a final confrontation between the Prophets and the Pah-wraiths, dramatized in the Season 6 episode of the same name."},{"id":"DS9-076","series":"DS9","difficulty":"hard","type":"true_false","category":"Villains & Antagonists","question":"Section 31 engineered a disease to infect the Founders through Odo.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'When It Rains...' and 'Extreme Measures,' it is revealed Section 31 infected Odo with a morphogenic virus during his visit to Starfleet Medical in 'Homefront,' using him as a vector to spread the disease throughout the Great Link."},{"id":"DS9-077","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"What was the name of the first runabout lost in the DS9 series?","answers":{"A":"USS Mekong","B":"USS Yangtzee Kiang","C":"USS Rio Grande","D":"USS Orinoco"},"correct":"B","explanation":"The runabout USS Yangtzee Kiang is destroyed in 'Battle Lines' (Season 1), crashing on a moon in the Gamma Quadrant where Kai Opaka is killed and then resurrected by microbes."},{"id":"DS9-078","series":"DS9","difficulty":"hard","type":"true_false","category":"Crossovers & Connections","question":"Lursa and B'Etor, the Duras sisters, appear in DS9.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Duras sisters Lursa and B'Etor, recurring TNG antagonists, appear in the Season 1 DS9 episode 'Past Prologue,' attempting to sell weapons to Bajoran extremist Tahna Los before being killed in Star Trek: Generations."},{"id":"DS9-079","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is the full name of the Cardassian who eventually leads the resistance against the Dominion?","answers":{"A":"Cartan Damar","B":"Mekor Damar","C":"Skrain Dukat","D":"Corat Damar"},"correct":"D","explanation":"Legate Corat Damar (played by Casey Biggs) rises from Dukat's aide to Cardassian head of state under Dominion rule, then leads the Cardassian Rebellion against Weyoun in Season 7 before being killed liberating Cardassia Prime."},{"id":"DS9-080","series":"DS9","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Sacrifice of Angels,' the wormhole aliens/Prophets destroy a Dominion fleet to save DS9.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In the Season 6 episode 'Sacrifice of Angels,' Sisko begs the Prophets to stop a 2,800-ship Dominion reinforcement fleet from emerging from the wormhole; they vanish the entire fleet, with the price being Sisko's eventual departure."},{"id":"DS9-081","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Villains & Antagonists","question":"How many Weyoun clones appear across the DS9 series (including those killed)?","answers":{"A":"4","B":"5","C":"3","D":"6"},"correct":"B","explanation":"Five distinct Weyoun clones appear in the series: Weyoun 4 (killed in 'To the Death'), Weyoun 5, Weyoun 6 (the defector), Weyoun 7, and Weyoun 8—as the Founders activate replacement clones to continue his role as Dominion supervisor."},{"id":"DS9-082","series":"DS9","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Garak's mentor and father figure in the Obsidian Order was Enabran Tain.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Enabran Tain, head of the Obsidian Order, is revealed in 'The Wire' and 'In Purgatory's Shadow' to be Garak's biological father; their tortured relationship is a major arc of Garak's backstory."},{"id":"DS9-083","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Timeline & History","question":"How long did the Dominion War last?","answers":{"A":"1 year","B":"3 years","C":"5 years","D":"2 years"},"correct":"D","explanation":"The Dominion War began with the Cardassian-Dominion alliance and the Federation's mining of the wormhole in late 2373 ('Call to Arms') and ended with the signing of the Treaty of Bajor in 2375—approximately two years."},{"id":"DS9-084","series":"DS9","difficulty":"hard","type":"true_false","category":"Planets & Locations","question":"Empok Nor is an abandoned Cardassian station identical in design to Deep Space 9.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Empok Nor, featured in the Season 5 episode 'Empok Nor,' is a sister station to Terok Nor (DS9), of the same Nor-class Cardassian design, abandoned in the Trivas system."},{"id":"DS9-085","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Statistical Probabilities,' Bashir works with a group of genetically enhanced individuals who predict which outcome?","answers":{"A":"A Federation victory in the Dominion War","B":"The Prophets sealing the wormhole","C":"Federation defeat and billions of deaths unless they surrender","D":"The destruction of Deep Space 9"},"correct":"C","explanation":"In 'Statistical Probabilities,' Bashir's fellow genetically enhanced 'Jack Pack' calculate that Federation defeat is virtually certain and recommend immediate surrender to minimize the projected 900+ billion deaths."},{"id":"DS9-086","series":"DS9","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Odo ultimately returns to the Great Link at the end of the series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In the finale 'What You Leave Behind,' Odo returns to the Great Link to cure his people of the Section 31 virus, leaving Kira and DS9 behind as part of the war's resolution."},{"id":"DS9-087","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the Bajoran word for the wormhole aliens they worship as gods?","answers":{"A":"The Prophets","B":"The Celestials","C":"The Seers","D":"The Beings"},"correct":"A","explanation":"Bajorans call the non-linear wormhole aliens 'the Prophets,' worshipping them as gods who reside in the Celestial Temple and communicate through the Orbs and the Emissary."},{"id":"DS9-088","series":"DS9","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"The Dominion used Ketracel-white distribution ships as strategic targets.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Federation forces targeted Dominion ketracel-white storage depots and supply lines (such as in 'A Time to Stand') to weaken the Jem'Hadar, since the supply was their lifeline; the Dominion guarded these convoys heavily."},{"id":"DS9-089","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is Garak's mother's name, revealed in the DS9 novel expanded universe but hinted on screen?","answers":{"A":"Tora","B":"Ziyal","C":"Palandine","D":"Mila"},"correct":"D","explanation":"Mila, the housekeeper at Enabran Tain's estate, is revealed (most explicitly in 'When It Rains...' and in Andrew Robinson's novel A Stitch in Time) to be Garak's mother and Tain's longtime mistress."},{"id":"DS9-090","series":"DS9","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In the DS9 finale, Sisko defeats Dukat in the Fire Caves and then ascends to be with the Prophets.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'What You Leave Behind,' Sisko tackles the Pah-wraith-possessed Dukat into the Fire Caves on Bajor, sealing them away, then joins the Prophets in the Celestial Temple, promising Kasidy he will one day return."},{"id":"DS9-091","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Villains & Antagonists","question":"Who is the head of the Obsidian Order before its destruction?","answers":{"A":"Toran","B":"Legate Ghemor","C":"Enabran Tain","D":"Gul Dukat"},"correct":"C","explanation":"Enabran Tain headed the Obsidian Order until its destruction in 'The Die is Cast,' when a joint Tal Shiar/Obsidian Order strike on the Founders' homeworld was annihilated by the Dominion."},{"id":"DS9-092","series":"DS9","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"The Vorta were originally peaceful forest dwellers who were uplifted by the Founders.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Treachery, Faith and the Great River,' Weyoun 6 recounts that the Vorta were primitive ape-like forest creatures who once sheltered a Founder from hunters; in gratitude, the Founders genetically engineered them into the Dominion's administrative caste."},{"id":"DS9-093","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In which season premiere does Sisko first take the Defiant into the Gamma Quadrant and meet the Founders, establishing the Dominion as the show's central antagonist?","answers":{"A":"Season 4","B":"Season 2","C":"Season 1","D":"Season 3"},"correct":"D","explanation":"Season 3 opens with 'The Search,' in which Sisko brings the Defiant to the Gamma Quadrant to confront the Dominion directly and encounters the Founders for the first time, establishing the central antagonist for the remainder of the series."},{"id":"DS9-094","series":"DS9","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Rom becomes Grand Nagus of the Ferengi Alliance at the end of the series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In the penultimate episode 'The Dogs of War,' Zek retires and names Rom—the unlikely social reformer—as the next Grand Nagus, signaling sweeping change to Ferengi society."},{"id":"DS9-095","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"The Defiant is destroyed in which story arc and later replaced?","answers":{"A":"The Second Battle of Chin'toka","B":"The First Battle of Chin'toka","C":"The final assault on Cardassia","D":"The siege of AR-558"},"correct":"A","explanation":"The original Defiant is destroyed by Breen energy-dampening weapons during the Second Battle of Chin'toka in 'The Changing Face of Evil' (Season 7); the USS Sao Paulo is renamed Defiant as its replacement."},{"id":"DS9-096","series":"DS9","difficulty":"hard","type":"true_false","category":"Crossovers & Connections","question":"The DS9 episode 'Emissary' begins during the Battle of Wolf 359, which was first depicted in TNG.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The pilot 'Emissary' opens with Sisko aboard the USS Saratoga at the Battle of Wolf 359, where his wife Jennifer dies and Locutus of Borg (Picard) destroys the ship—events directly connecting to TNG's 'The Best of Both Worlds.'"},{"id":"DS9-097","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of Dukat's half-Bajoran daughter?","answers":{"A":"Nerys Dukat","B":"Tora Ziyal","C":"Tora Naprem","D":"Meru Dukat"},"correct":"B","explanation":"Tora Ziyal, daughter of Dukat and his Bajoran consort Tora Naprem, is introduced in 'Indiscretion' (Season 4) and is later killed by Damar in 'Sacrifice of Angels.'"},{"id":"DS9-098","series":"DS9","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"The Breen are a species that has never been seen without their refrigeration suits.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Throughout DS9, the Breen are always depicted in their enigmatic helmeted refrigeration suits; their true appearance and physiology are never revealed onscreen, a deliberate worldbuilding choice."},{"id":"DS9-099","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What DS9 episode is widely considered the darkest, featuring the crew trapped at AR-558 in brutal ground combat?","answers":{"A":"Rocks and Shoals","B":"The Siege of AR-558","C":"It's Only a Paper Moon","D":"Inter Arma Enim Silent Leges"},"correct":"B","explanation":"'The Siege of AR-558' (Season 7) depicts the brutal ground defense of a Dominion communications relay, drawing heavily on World War II combat film conventions to show the human cost of the Dominion War."},{"id":"DS9-100","series":"DS9","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"The Breen weapon that disabled Federation ships' power systems was eventually countered by a Klingon workaround.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"After the Breen energy-dampening weapon devastated the Federation fleet at the Second Battle of Chin'toka, the Klingons developed and shared a countermeasure that allowed Allied ships to resist the weapon, as seen in 'When It Rains...'"},{"id":"DS9-101","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Which actor plays Commander/Captain Benjamin Sisko in DS9?","answers":{"A":"Avery Brooks","B":"Colm Meaney","C":"Alexander Siddig","D":"Michael Dorn"},"correct":"A","explanation":"Avery Brooks plays Sisko across all 7 seasons (1993-1999) — the first Black lead in a Star Trek series."},{"id":"DS9-102","series":"DS9","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"Bajorans traditionally wear their religious earring on the right ear.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Bajoran d'ja pagh is worn on the right ear so a Vedek can deliver a blessing by gripping the wearer's earlobe — seen frequently with Kira and the station's clergy."},{"id":"DS9-103","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the holographic Rat Pack-era lounge singer who befriends the DS9 crew in later seasons?","answers":{"A":"Vic Fontaine","B":"Dixon Hill","C":"Felix Knightly","D":"Frankie Lewis"},"correct":"A","explanation":"Vic Fontaine (James Darren), a holographic 1962 Las Vegas crooner, first appears in 'His Way' (Season 6) and becomes a recurring fixture who helps Odo woo Kira and supports the crew emotionally."},{"id":"DS9-104","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What is Garak's given first name, revealed gradually over the series?","answers":{"A":"Tekeny","B":"Skrain","C":"Elim","D":"Corat"},"correct":"C","explanation":"Elim Garak's full name surfaces in 'The Wire' and 'In Purgatory's Shadow,' tied to his backstory as an exiled Obsidian Order operative and Enabran Tain's protégé."},{"id":"DS9-105","series":"DS9","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"The Klingon Empire briefly breaks its alliance with the Federation during DS9 and invades Cardassia.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'The Way of the Warrior' (Season 4) — manipulated by a hidden Changeling impersonating General Martok — Chancellor Gowron withdraws from the Khitomer Accords and attacks Cardassia. The alliance is restored in 'By Inferno's Light.'"},{"id":"DS9-106","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"How are new Vorta produced?","answers":{"A":"Sexually, like most humanoids","B":"By cloning — when one dies, a new clone with inherited memories activates","C":"Via symbiotic implantation, like Trill","D":"Born to Founder mothers"},"correct":"B","explanation":"The Vorta are engineered clones. Weyoun 4, 5, 6, 7, and 8 all appear in DS9, each inheriting the previous clone's memories upon activation."},{"id":"DS9-107","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In the acclaimed episode 'Duet,' the Cardassian Marritza is initially believed to be which infamous war criminal of the Bajoran Occupation?","answers":{"A":"Gul Madred","B":"Gul Darhe'el, the 'Butcher of Gallitep'","C":"Gul Dukat","D":"Legate Damar"},"correct":"B","explanation":"Marritza, a file clerk wracked by guilt over witnessing the Gallitep massacre, deliberately impersonates the dead commandant Darhe'el so he can be publicly tried — a confession of collective Cardassian guilt."},{"id":"DS9-108","series":"DS9","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"Sisko's wife Jennifer died in the Battle of Wolf 359, during which Picard had been assimilated as Locutus of Borg.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Jennifer Sisko died aboard the USS Saratoga at Wolf 359, the Borg massacre led by Locutus — fueling Sisko's lingering resentment toward Picard, dramatized in their tense first meeting in the pilot 'Emissary.'"},{"id":"DS9-109","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"Who is the silent Lurian bar patron at Quark's, constantly referenced as a chatterbox but never heard speaking on screen?","answers":{"A":"Brunt","B":"Morn","C":"Broik","D":"Leck"},"correct":"B","explanation":"Morn appears in nearly every episode and is repeatedly described as a non-stop talker off-screen — but never speaks on camera, a running joke whose name is an anagram of Cheers' Norm."},{"id":"DS9-110","series":"DS9","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In the final season, Kira Nerys helps train Damar's Cardassian resistance against the Dominion.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kira and Garak join Damar's resistance in the final arc — Bajorans teaching Cardassians how to fight an occupation, mirroring Kira's earlier life as a Bajoran resistance fighter against the Cardassians."},{"id":"DS9-111","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Quotes & Catchphrases","question":"Which Rule of Acquisition is the famous Rule #1?","answers":{"A":"Never spend more for an acquisition than you have to","B":"A man is only worth the sum of his possessions","C":"Greed is eternal","D":"Once you have their money, you never give it back"},"correct":"D","explanation":"Rule of Acquisition #1, 'Once you have their money, you never give it back,' is quoted by Quark; the Rules are a running source of Ferengi wisdom throughout DS9, including 'The Nagus' and 'Body Parts.'"},{"id":"DS9-112","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Quotes & Catchphrases","question":"How do the Jem'Hadar typically declare their loyalty before battle, beginning with 'Obedience brings victory...'?","answers":{"A":"...and victory is life.","B":"...and life is the Dominion.","C":"...and the Founders are gods.","D":"...and death is honor."},"correct":"A","explanation":"The Jem'Hadar ritual oath 'Obedience brings victory, and victory is life' expresses their conditioned devotion to the Founders, heard in episodes such as 'To the Death.'"},{"id":"DS9-113","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of Miles O'Brien's wife, a botanist who runs the station's school early in the series?","answers":{"A":"Keiko","B":"Kasidy","C":"Leeta","D":"Molly"},"correct":"A","explanation":"Keiko O'Brien, a botanist who transferred from the Enterprise-D with Miles, establishes and runs the station's school in DS9's first season before later pursuing fieldwork on Bajor."},{"id":"DS9-114","series":"DS9","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Kasidy Yates is a freighter captain who becomes Sisko's romantic partner and eventually his wife.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kasidy Yates, introduced in 'Family Business' (Season 3), is a civilian freighter captain who becomes Sisko's love interest and marries him in the final season, expecting their child as he joins the Prophets."},{"id":"DS9-115","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What gambling game, run by a dabo girl, is a popular attraction at Quark's bar?","answers":{"A":"Tongo","B":"Dabo","C":"Fizzbin","D":"Dom-jot"},"correct":"B","explanation":"Dabo is the spinning wheel-style game of chance run at Quark's by 'dabo girls' such as Leeta and M'Pella; players shout 'Dabo!' on a winning result throughout the series."},{"id":"DS9-116","series":"DS9","difficulty":"easy","type":"true_false","category":"Planets & Locations","question":"The shops, bar, and infirmary on Deep Space 9 are located on a level called the Promenade.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Promenade is the central commercial concourse of DS9, home to Quark's bar, the Bajoran temple, the infirmary, Garak's tailor shop, and the security office, established in 'Emissary.'"},{"id":"DS9-117","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Which DS9 character is the dabo girl who marries Rom?","answers":{"A":"Ishka","B":"M'Pella","C":"Leeta","D":"Ezri"},"correct":"C","explanation":"Leeta, a Bajoran dabo girl at Quark's, falls in love with and marries Rom; their courtship and Ferengi-tradition wedding play out across the later seasons."},{"id":"DS9-118","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Villains & Antagonists","question":"What is the name of the genetically engineered soldier caste that serves as the Dominion's army?","answers":{"A":"The Vorta","B":"The Cardassian Guard","C":"The Breen","D":"The Jem'Hadar"},"correct":"D","explanation":"The Jem'Hadar are the Dominion's bred-for-war shock troops, fanatically loyal to the Founders and supervised by the Vorta, introduced in the Season 2 finale 'The Jem'Hadar.'"},{"id":"DS9-119","series":"DS9","difficulty":"easy","type":"true_false","category":"Starfleet Ranks & Protocol","question":"Miles O'Brien is a non-commissioned officer, holding the rank of Chief Petty Officer rather than a commissioned officer rank.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"O'Brien is an enlisted non-commissioned officer (Senior Chief Petty Officer), notably one of Star Trek's few prominent non-commissioned characters, a point emphasized in episodes like 'The Assignment' and 'Hippocratic Oath.'"},{"id":"DS9-120","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"The Trill join with a long-lived symbiont. Where in the body does the symbiont reside?","answers":{"A":"In a pouch in the abdomen","B":"Within the skull, behind the brain","C":"In the chest cavity beside the heart","D":"In the spinal column"},"correct":"A","explanation":"A Trill symbiont lives in an abdominal pouch of its humanoid host; the joining is essential to the symbiont, which would die within hours if removed without a host, as shown in 'Invasive Procedures.'"},{"id":"DS9-121","series":"DS9","difficulty":"easy","type":"true_false","category":"Crossovers & Connections","question":"Chief Miles O'Brien was a regular character on Star Trek: The Next Generation before transferring to Deep Space 9.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Colm Meaney's Miles O'Brien served as transporter chief aboard the Enterprise-D throughout TNG before transferring to DS9 in 'Emissary,' making him a key crossover character between the two series."},{"id":"DS9-122","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What is the title of the DS9 series premiere?","answers":{"A":"Encounter at Farpoint","B":"The Search","C":"Caretaker","D":"Emissary"},"correct":"D","explanation":"'Emissary' is the feature-length DS9 pilot, in which Sisko takes command of the station, discovers the wormhole, and is named the Emissary of the Prophets by the Bajorans."},{"id":"DS9-123","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Timeline & History","question":"Just before the series begins, the Cardassians do what to Bajor and its station?","answers":{"A":"Sign a permanent peace treaty with Bajor","B":"Withdraw from Bajor, ending the Occupation","C":"Join the Federation","D":"Destroy the station and flee"},"correct":"B","explanation":"The Cardassian withdrawal from Bajor ends the decades-long Occupation and leaves the abandoned station Terok Nor behind; Bajor's provisional government then invites the Federation to administer it as DS9, the premise of 'Emissary.'"},{"id":"DS9-124","series":"DS9","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"Deep Space 9's smaller Starfleet support craft, named after rivers, are called runabouts.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"DS9 operates Danube-class runabouts named for Earth rivers, including the Rio Grande, Yangtzee Kiang, Orinoco, and Mekong, used for short-range missions throughout the series."},{"id":"DS9-125","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Quotes & Catchphrases","question":"What is the title of the Ferengi business game Quark plays, in which players acquire and sell to bankrupt opponents?","answers":{"A":"Dabo","B":"Tongo","C":"Dom-jot","D":"Kotra"},"correct":"B","explanation":"Tongo is a card-and-wheel game of Ferengi finance played by Quark, Jadzia, and others; calls like 'Acquire!' and 'Confront!' are part of its play, seen in episodes such as 'Rules of Acquisition.'"},{"id":"DS9-126","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Crossovers & Connections","question":"Which character originated on The Next Generation as a recurring Klingon and later became a regular on Deep Space 9?","answers":{"A":"Martok","B":"Worf","C":"Gowron","D":"Kurn"},"correct":"B","explanation":"Worf, played by Michael Dorn, was a TNG main cast member who joined DS9 as a regular in Season 4's 'The Way of the Warrior,' bridging the two series during the Klingon-Federation tensions."},{"id":"DS9-127","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"Which Klingon general becomes a close ally of the DS9 crew and is eventually appointed Chancellor of the Klingon Empire?","answers":{"A":"Gowron","B":"Kor","C":"Martok","D":"Kurn"},"correct":"C","explanation":"General Martok, played by J.G. Hertzler, fights alongside the DS9 crew during the Dominion War and is named Chancellor by Worf after Worf kills Gowron in 'Tacking Into the Wind.'"},{"id":"DS9-128","series":"DS9","difficulty":"medium","type":"true_false","category":"Starfleet Ranks & Protocol","question":"When the Federation suspects a Changeling has infiltrated Earth, Starfleet briefly places Earth under martial law in the 'Homefront'/'Paradise Lost' two-parter.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Homefront' and 'Paradise Lost,' Admiral Leyton exploits Changeling paranoia to seize power, declaring a state of emergency and deploying troops on Earth in an attempted Starfleet coup that Sisko helps thwart."},{"id":"DS9-129","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In which Season 5 finale does Sisko order the wormhole mined, triggering the start of the Dominion War?","answers":{"A":"By Inferno's Light","B":"A Call to Arms","C":"In Purgatory's Shadow","D":"A Time to Stand"},"correct":"B","explanation":"In the Season 5 finale 'Call to Arms,' Sisko mines the wormhole to block Dominion reinforcements; the Dominion and Cardassians respond by attacking, and Starfleet abandons the station, igniting open war."},{"id":"DS9-130","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Timeline & History","question":"Which power does Cardassia secretly join under Dukat in late Season 5, dramatically shifting the balance of power toward war?","answers":{"A":"The Romulan Star Empire","B":"The Klingon Empire","C":"The Dominion","D":"The Breen Confederacy"},"correct":"C","explanation":"In 'By Inferno's Light' (Season 5), Dukat reveals Cardassia has secretly joined the Dominion, making himself leader of a Cardassian client state and dramatically shifting the Alpha Quadrant balance of power toward war."},{"id":"DS9-131","series":"DS9","difficulty":"medium","type":"true_false","category":"Crossovers & Connections","question":"The Ferengi first appeared in Star Trek: The Next Generation before becoming central to DS9.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Ferengi debuted in TNG's first-season episode 'The Last Outpost' as intended antagonists; DS9 later reinvented and humanized them through Quark, Rom, Nog, and Ferengi culture."},{"id":"DS9-132","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"Quark and Rom's mother, who scandalously earns profit and wears clothes against Ferengi custom, is named what?","answers":{"A":"Leeta","B":"Pel","C":"Ishka","D":"Prinadora"},"correct":"C","explanation":"Ishka ('Moogie'), introduced in 'Family Business,' defies Ferengi tradition by earning profit and wearing clothing; she later influences Grand Nagus Zek toward reforms granting Ferengi females rights."},{"id":"DS9-133","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"What is the name of the lawless, plasma-storm-filled region near the Cardassian border favored by the Maquis?","answers":{"A":"The Briar Patch","B":"The Demilitarized Zone","C":"The Badlands","D":"The Neutral Zone"},"correct":"C","explanation":"The Badlands, a region of violent plasma storms, served as a hideout for the Maquis raiders operating against Cardassia; it features in DS9 episodes such as 'The Maquis' and as the setting that strands Voyager."},{"id":"DS9-134","series":"DS9","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"Federation colonists who resisted the Cardassian peace treaty formed a paramilitary group called the Maquis, which DS9 helped introduce to Star Trek.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Maquis were introduced in DS9's two-part 'The Maquis' (Season 2), formed by disgruntled Federation colonists in the Demilitarized Zone, setting up a conflict later carried into Star Trek: Voyager."},{"id":"DS9-135","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"Which Starfleet officer and former Maquis member is revealed to be a traitor working with the Maquis, and is a recurring foil to Sisko early on?","answers":{"A":"Calvin Hudson","B":"Michael Eddington","C":"Cal Hudson","D":"Thomas Riker"},"correct":"B","explanation":"Lt. Commander Michael Eddington, DS9's Starfleet security officer, secretly defects to the Maquis in 'For the Cause' (Season 4) and becomes a personal nemesis of Sisko until 'For the Uniform' and 'Blaze of Glory.'"},{"id":"DS9-136","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Ships & Technology","question":"What is the registry number of the original USS Defiant?","answers":{"A":"NCC-1764","B":"NX-74205","C":"NCC-74656","D":"NX-59650"},"correct":"B","explanation":"The original USS Defiant carries the registry NX-74205, the 'NX' prefix denoting its status as an experimental prototype of the Defiant-class warship."},{"id":"DS9-137","series":"DS9","difficulty":"medium","type":"true_false","category":"Starfleet Ranks & Protocol","question":"Nog is eventually commissioned and promoted to the rank of Lieutenant by the end of the series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"After becoming the first Ferengi at Starfleet Academy, Nog is commissioned an ensign and is promoted to lieutenant (junior grade) for his battlefield service during the Dominion War."},{"id":"DS9-138","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the title of the elected leader of Bajor's civilian government during much of the series?","answers":{"A":"Kai","B":"Legate","C":"First Minister","D":"Vedek"},"correct":"C","explanation":"The First Minister leads Bajor's provisional/civilian government; Shakaar Edon, Kira's former resistance cell leader, is elected First Minister, distinct from the religious office of Kai."},{"id":"DS9-139","series":"DS9","difficulty":"medium","type":"true_false","category":"Timeline & History","question":"Bajor formally withdraws its application to join the Federation on the advice of Sisko at the start of the Dominion War.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Call to Arms,' Sisko advises Bajor to sign a nonaggression pact with the Dominion and postpone Federation membership to spare the planet from the coming war, sparing Bajor occupation during the conflict."},{"id":"DS9-140","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Quotes & Catchphrases","question":"In 'In the Pale Moonlight,' Sisko's closing line, repeated as a grim self-justification, is what?","answers":{"A":"The needs of the many outweigh the needs of the few.","B":"It is possible to commit no mistakes and still lose.","C":"I can live with it.","D":"The line must be drawn here."},"correct":"C","explanation":"Sisko ends 'In the Pale Moonlight' confessing his role in deception and an assassination that drew the Romulans into the war, concluding that he can live with it before ordering the log erased."},{"id":"DS9-141","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"Which one-time TNG character, a transporter-duplicate of Will Riker, appears in DS9 having joined the Maquis?","answers":{"A":"Thomas Riker","B":"Tom Paris","C":"Ro Laren","D":"Cal Hudson"},"correct":"A","explanation":"Thomas Riker, the transporter duplicate created in TNG's 'Second Chances,' resurfaces in DS9's 'Defiant' (Season 3), where he steals the Defiant for the Maquis and is captured by the Cardassians."},{"id":"DS9-142","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Timeline & History","question":"What treaty, signed in the series finale, formally ends the Dominion War?","answers":{"A":"The Khitomer Accords","B":"The Treaty of Algeron","C":"The Treaty of Bajor","D":"The Federation-Cardassian Treaty"},"correct":"C","explanation":"The Treaty of Bajor, signed aboard DS9 in 'What You Leave Behind,' marks the Dominion's surrender and the end of the war, with the Female Changeling agreeing to return the Dominion to the Gamma Quadrant."},{"id":"DS9-143","series":"DS9","difficulty":"hard","type":"true_false","category":"Crossovers & Connections","question":"In 'Trials and Tribble-ations,' the Department of Temporal Investigations agents who interview Sisko are named Dulmur and Lucsly, anagrams of the surnames of two real-world investigators from a famous TV series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"DTI agents Dulmur and Lucsly, debuting in 'Trials and Tribble-ations,' are deliberate anagrams of 'Mulder' and 'Scully' from The X-Files, an in-joke about time-travel investigators."},{"id":"DS9-144","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Villains & Antagonists","question":"Which Founder infiltrated the Klingon high command, impersonating General Martok to provoke war between the Klingons and Cardassians?","answers":{"A":"Laas","B":"The Female Changeling","C":"A Changeling impersonating Martok","D":"Odo's brother"},"correct":"C","explanation":"A Changeling spy posing as General Martok manipulated Chancellor Gowron into attacking Cardassia in 'The Way of the Warrior' and was finally exposed and killed in 'Apocalypse Rising'; the real Martok had been held captive."},{"id":"DS9-145","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"What role is Sisko given at the start of Season 6, coordinating Allied operations against the Dominion from Starbase 375?","answers":{"A":"Admiral of the Ninth Fleet","B":"Adjutant to the Klingon High Council","C":"Adjutant and strategic operations officer planning the war effort","D":"Commander-in-Chief of Starfleet"},"correct":"C","explanation":"Captain Sisko is assigned as adjutant/strategic-operations planner coordinating the Allied war effort from Starbase 375 in the Season 6 opening arc ('A Time to Stand' onward), directing fleet operations against the Dominion."},{"id":"DS9-146","series":"DS9","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"The recapture of Deep Space 9 from the Dominion is depicted in the six-episode arc that opens Season 6.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Season 6 opens with a serialized six-episode arc ('A Time to Stand' through 'Sacrifice of Angels') in which the Federation, having lost the station to the Dominion in 'Call to Arms,' fights to retake DS9 and the wormhole."},{"id":"DS9-147","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"In 'Children of Time,' the Defiant crew discovers a colony descended from themselves. What caused the colony to exist?","answers":{"A":"A transporter accident duplicated the crew","B":"A time-travel accident sent the crew 200 years into the past, where they settled","C":"The Prophets created copies of the crew","D":"A Dominion cloning experiment"},"correct":"B","explanation":"In 'Children of Time,' an energy barrier throws the Defiant 200 years into the past upon departure; a previous attempt stranded the crew, who founded a colony of 8,000 descendants, creating a wrenching temporal dilemma."},{"id":"DS9-148","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"What is the registry of the runabout USS Rio Grande, DS9's longest-surviving runabout?","answers":{"A":"NCC-72452","B":"NCC-74205","C":"NCC-72003","D":"NCC-1701"},"correct":"A","explanation":"The USS Rio Grande, registry NCC-72452, is among the first runabouts assigned to DS9 and notably survives the entire series while several sister runabouts are destroyed."},{"id":"DS9-149","series":"DS9","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Worf's discommendation and his brother Kurn's fate are revisited in the DS9 episode 'Sons of Mogh.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Sons of Mogh' (Season 4), Worf's brother Kurn arrives dishonored and suicidal after Worf's break with Gowron; to save him, Dr. Bashir wipes Kurn's memory and he is given a new identity as Rodek."},{"id":"DS9-150","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Planets & Locations","question":"The Founders relocated their homeworld after the Omarion Nebula planet was destroyed. Where was their new homeworld located relative to the Dominion?","answers":{"A":"In the Alpha Quadrant, hidden near Cardassia","B":"In the Bajoran wormhole itself","C":"At the center of Dominion space in the Gamma Quadrant","D":"Inside the Briar Patch"},"correct":"C","explanation":"After their Omarion Nebula world was destroyed in 'The Die is Cast,' the Founders established a new, secret homeworld deep within Dominion territory in the Gamma Quadrant, where Odo is judged in 'Broken Link.'"},{"id":"DS9-151","series":"DS9","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What career does Jake Sisko pursue instead of joining Starfleet?","answers":{"A":"Starship engineer","B":"Writer and journalist","C":"Bajoran vedek","D":"Dabo dealer at Quark's"},"correct":"B","explanation":"Unlike most Starfleet children, Jake chooses a career as a writer and journalist; he declines the Pennington School scholarship in 'Shadows and Symbols' and writes throughout the series, notably under Onaya's influence in 'The Muse.'"},{"id":"DS9-152","series":"DS9","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"The USS Defiant first appears in the third-season premiere 'The Search, Part I.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Sisko brings the prototype warship Defiant (NX-74205) to DS9 in 'The Search, Part I,' the Season 3 premiere, to make first contact with the Dominion in the Gamma Quadrant."},{"id":"DS9-153","series":"DS9","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"Which actress portrayed the ambitious Bajoran religious leader Vedek (later Kai) Winn Adami?","answers":{"A":"Nana Visitor","B":"Louise Fletcher","C":"Marina Sirtis","D":"Salome Jens"},"correct":"B","explanation":"Louise Fletcher, the Oscar-winning Nurse Ratched of 'One Flew Over the Cuckoo's Nest,' played the scheming Winn Adami across the series, beginning with 'In the Hands of the Prophets.'"},{"id":"DS9-154","series":"DS9","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"In the Jem'Hadar military hierarchy, the leader of a unit holds the rank of 'First.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Jem'Hadar use a simple ranking system in which the unit leader is the 'First,' his second-in-command the 'Second,' and so on, as seen with Omet'iklan and Toman'torax in 'To the Death.'"},{"id":"DS9-155","series":"DS9","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"In 'To the Death,' which Jem'Hadar First executes his Second, Toman'torax, for striking Worf?","answers":{"A":"Ikat'ika","B":"Omet'iklan","C":"Goran'Agar","D":"Remata'Klan"},"correct":"B","explanation":"Omet'iklan, the disciplined First leading the joint mission against renegade Jem'Hadar in 'To the Death,' kills his Second Toman'torax after the latter attacks Lieutenant Commander Worf."},{"id":"VOY-001","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who is the captain of the USS Voyager?","answers":{"A":"Janeway","B":"Chakotay","C":"Paris","D":"Tuvok"},"correct":"A","explanation":"Captain Kathryn Janeway, played by Kate Mulgrew, commands the USS Voyager throughout the series, beginning with the pilot 'Caretaker.'"},{"id":"VOY-002","series":"VOY","difficulty":"easy","type":"true_false","category":"Planets & Locations","question":"Voyager is stranded in the Delta Quadrant at the start of the series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In the pilot 'Caretaker,' the Caretaker entity pulls Voyager into the Delta Quadrant, stranding the ship approximately 70,000 light years from home."},{"id":"VOY-003","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What class of starship is the USS Voyager?","answers":{"A":"Intrepid-class","B":"Galaxy-class","C":"Nova-class","D":"Sovereign-class"},"correct":"A","explanation":"The USS Voyager (NCC-74656) is an Intrepid-class starship, a long-range science vessel designed for deep space exploration."},{"id":"VOY-004","series":"VOY","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Seven of Nine is a former Borg drone.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Seven of Nine, born Annika Hansen, was assimilated by the Borg as a child and severed from the Collective by Janeway in 'Scorpion, Part II' (Season 4)."},{"id":"VOY-005","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of Voyager's holographic doctor?","answers":{"A":"Dr. Zimmerman","B":"Dr. Crusher","C":"Dr. Bashir","D":"The Doctor"},"correct":"D","explanation":"Voyager's Emergency Medical Hologram, played by Robert Picardo, is simply called 'The Doctor' throughout the series, never settling on a permanent name."},{"id":"VOY-006","series":"VOY","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"The Kazon are a Delta Quadrant species that frequently antagonize Voyager in the early seasons.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Kazon, divided into rival sects, serve as Voyager's primary antagonists in Seasons 1 and 2, culminating in the takeover of Voyager in 'Basics.'"},{"id":"VOY-007","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is Chakotay's role on Voyager?","answers":{"A":"Helmsman","B":"Chief Engineer","C":"Security Chief","D":"First Officer"},"correct":"D","explanation":"Chakotay, formerly a Maquis captain, accepts a commission as Commander and First Officer when his crew merges with Janeway's in 'Caretaker.'"},{"id":"VOY-008","series":"VOY","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Tom Paris serves as Voyager's primary helmsman.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Lt. Tom Paris, recruited by Janeway from the Federation penal colony in New Zealand, serves as Voyager's chief conn officer and helmsman throughout the series."},{"id":"VOY-009","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Planets & Locations","question":"Approximately how far is Voyager from home at the start of the series?","answers":{"A":"100,000 light years","B":"70,000 light years","C":"25,000 light years","D":"50,000 light years"},"correct":"B","explanation":"In 'Caretaker,' Janeway notes the ship is approximately 70,000 light years from Federation space, which would take roughly 75 years to traverse at maximum warp."},{"id":"VOY-010","series":"VOY","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"B'Elanna Torres is the Chief Engineer of Voyager and is half-Klingon.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"B'Elanna Torres, daughter of a human father and a Klingon mother, is promoted to Chief Engineer by Janeway in 'Parallax' (Season 1)."},{"id":"VOY-011","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What species is Tuvok?","answers":{"A":"Vulcan","B":"Betazoid","C":"Romulan","D":"Bajoran"},"correct":"A","explanation":"Lt. Commander Tuvok, Voyager's tactical and security officer, is a Vulcan who had infiltrated Chakotay's Maquis cell as Janeway's undercover operative."},{"id":"VOY-012","series":"VOY","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Neelix is an alien cook and morale officer aboard Voyager.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Neelix joins Voyager in 'Caretaker' and serves as cook, ambassador, and self-appointed morale officer; Janeway formally appoints him Morale Officer in 'Investigations.'"},{"id":"VOY-013","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What unique computer technology does Voyager use that earlier Federation ships lack?","answers":{"A":"Bio-neural gel packs","B":"Positronic crystal matrices","C":"Ablative hull armor","D":"Quantum slipstream drive"},"correct":"A","explanation":"Voyager's computer systems use bio-neural gel packs - organic processors that improve response time over traditional isolinear circuitry, as first explained in 'Caretaker' and central to the plot of 'Learning Curve.'"},{"id":"VOY-014","series":"VOY","difficulty":"easy","type":"true_false","category":"Villains & Antagonists","question":"Species 8472 is considered one of the most dangerous threats Voyager faces.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Introduced in 'Scorpion,' Species 8472 are biologically advanced beings from fluidic space whose tissue is resistant to Borg assimilation, making them powerful enough to threaten the Collective itself."},{"id":"VOY-015","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is Seven of Nine's human birth name?","answers":{"A":"Clara Hansen","B":"Sophie Hansen","C":"Annika Hansen","D":"Erin Hansen"},"correct":"C","explanation":"Seven of Nine was born Annika Hansen and was assimilated at age six along with her parents Magnus and Erin Hansen, exobiologists studying the Borg ('The Raven')."},{"id":"VOY-016","series":"VOY","difficulty":"easy","type":"true_false","category":"Episodes & Story Arcs","question":"Voyager is stranded in the Delta Quadrant by an entity called the Caretaker.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Caretaker, a Nacene entity protecting the Ocampa, pulls Voyager across the galaxy searching for a compatible mate; he dies in the pilot episode before he can send the ship home."},{"id":"VOY-017","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What species is Neelix?","answers":{"A":"Hirogen","B":"Talaxian","C":"Ocampan","D":"Kazon"},"correct":"B","explanation":"Neelix is a Talaxian, a species from the Delta Quadrant whose homeworld region was devastated by the Haakonian Order, as revealed in 'Jetrel.'"},{"id":"VOY-018","series":"VOY","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Kes is an Ocampan whose species only lives about 9 years.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kes, an Ocampa rescued from the Caretaker's array in the pilot, has a natural lifespan of approximately nine years - a fact that drives much of her storyline."},{"id":"VOY-019","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What is the registry number of the USS Voyager?","answers":{"A":"NCC-71701","B":"NCC-1701-D","C":"NCC-74205","D":"NCC-74656"},"correct":"D","explanation":"The USS Voyager bears the registry number NCC-74656, shown on the ship's hull and identified in dialogue throughout the series."},{"id":"VOY-020","series":"VOY","difficulty":"easy","type":"true_false","category":"Starfleet Ranks & Protocol","question":"Janeway merges her Starfleet crew with a Maquis crew at the start of the series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"After the Maquis ship Val Jean is destroyed in 'Caretaker,' Janeway integrates Chakotay's surviving Maquis crew into Voyager's complement under Starfleet protocols."},{"id":"VOY-021","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who is Voyager's Operations Officer and Ensign throughout most of the series?","answers":{"A":"Tom Paris","B":"Harry Kim","C":"Tuvok","D":"Chakotay"},"correct":"B","explanation":"Ensign Harry Kim, fresh out of Starfleet Academy, serves as Voyager's Operations Officer and famously remains an Ensign for the entire seven-year journey."},{"id":"VOY-022","series":"VOY","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"The Hirogen are a hunter species who prize trophies from their prey.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Hirogen, introduced in 'Hunters' (Season 4), are a nomadic warrior culture that travels in hunting parties, collecting trophies (relics) from worthy prey."},{"id":"VOY-023","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Quotes & Catchphrases","question":"What is Captain Janeway's most recognized coffee order?","answers":{"A":"Coffee, black","B":"Raktajino, extra strong","C":"Vulcan spice tea","D":"Earl Grey tea, hot"},"correct":"A","explanation":"Janeway's love of coffee is a running gag throughout the series; she famously orders 'Coffee, black' and calls coffee 'the finest organic suspension ever devised' in 'Hunters.'"},{"id":"VOY-024","series":"VOY","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"The Doctor's holographic matrix was created by Dr. Lewis Zimmerman.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Dr. Lewis Zimmerman of the Jupiter Station Holoprogramming Center designed the EMH Mark I, basing its appearance on himself, as revealed in 'The Swarm' and 'Life Line.'"},{"id":"VOY-025","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"How does Voyager finally return to the Alpha Quadrant?","answers":{"A":"The Caretaker's array","B":"A slipstream drive","C":"A Borg transwarp hub","D":"Transwarp conduit"},"correct":"C","explanation":"In 'Endgame,' Voyager uses one of six Borg transwarp conduits within a hub to return home, simultaneously destroying the hub from inside a Borg sphere."},{"id":"VOY-026","series":"VOY","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"The Borg are encountered by Voyager in the Delta Quadrant.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Delta Quadrant is the Borg's home territory, and Voyager has repeated encounters with the Collective starting in 'Unity' (Season 3) and the 'Scorpion' two-parter."},{"id":"VOY-027","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Who is Tom Paris's love interest and eventual wife on Voyager?","answers":{"A":"Kes","B":"B'Elanna Torres","C":"Seven of Nine","D":"Samantha Wildman"},"correct":"B","explanation":"Tom Paris and B'Elanna Torres begin a relationship in 'Day of Honor' (Season 4), marry in 'Drive' (Season 7), and have a daughter named Miral in 'Endgame.'"},{"id":"VOY-028","series":"VOY","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Chakotay was formerly a Maquis leader before joining Voyager.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Chakotay, a former Starfleet officer, resigned to join the Maquis and captained the Val Jean before being stranded with Voyager in 'Caretaker.'"},{"id":"VOY-029","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the Borg Queen's role in the Collective?","answers":{"A":"She controls only tactical decisions","B":"She is the central processor of the Collective","C":"She is a symbolic figurehead only","D":"She manages diplomatic relations"},"correct":"B","explanation":"The Borg Queen, established in Star Trek: First Contact and continued in Voyager ('Dark Frontier,' 'Unimatrix Zero,' 'Endgame'), serves as the central consciousness and coordinating intelligence of the Collective."},{"id":"VOY-030","series":"VOY","difficulty":"easy","type":"true_false","category":"Ships & Technology","question":"Voyager is equipped with a holographic doctor as its primary medical officer.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"After the death of the Chief Medical Officer in the pilot, the EMH (The Doctor) becomes Voyager's permanent Chief Medical Officer for the duration of the series."},{"id":"VOY-031","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the Maquis leader who becomes Voyager's first officer?","answers":{"A":"Torres","B":"Tuvok","C":"Seska","D":"Chakotay"},"correct":"D","explanation":"Chakotay, captain of the Maquis ship Val Jean, accepts a field commission as Commander and becomes Voyager's First Officer in 'Caretaker.'"},{"id":"VOY-032","series":"VOY","difficulty":"easy","type":"true_false","category":"Villains & Antagonists","question":"Seska was a Cardassian spy disguised as a Bajoran who infiltrated the Maquis.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Seska, revealed in 'State of Flux' to be a Cardassian Obsidian Order operative surgically altered to appear Bajoran, defects to the Kazon and becomes a recurring antagonist."},{"id":"VOY-033","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What is the name of VOY's pilot episode?","answers":{"A":"Threshold","B":"Parallax","C":"Caretaker","D":"Deadlock"},"correct":"C","explanation":"'Caretaker,' the two-hour pilot that aired January 16, 1995, introduces the crew and establishes Voyager's stranding in the Delta Quadrant."},{"id":"VOY-034","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What famous opera singer's holographic program does the Doctor become fond of?","answers":{"A":"Beverly Crusher's program","B":"The Doctor creates his own opera persona","C":"Luciano Pavarotti","D":"Enrico Caruso"},"correct":"B","explanation":"The Doctor pursues opera as a hobby and performs his own holographic operatic shows on the holodeck, most notably in 'Virtuoso' where he becomes a celebrity on a Qomar world."},{"id":"VOY-035","series":"VOY","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Seven of Nine was assimilated by the Borg as a young child.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Annika Hansen was assimilated at age six along with her parents Magnus and Erin Hansen, who were studying the Borg from their ship the Raven ('The Raven,' 'Dark Frontier')."},{"id":"VOY-036","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Blink of an Eye,' Voyager becomes trapped in the orbit of a planet where time moves how much faster?","answers":{"A":"Much faster — an entire civilization rises and falls","B":"100 times faster","C":"10 times faster","D":"1,000 times faster"},"correct":"A","explanation":"In 'Blink of an Eye' (Season 6), the planet's tachyon-affected time dilation causes a day on Voyager to equal years on the surface, with civilization advancing from primitive tribes to spaceflight while Voyager remains stuck in orbit."},{"id":"VOY-037","series":"VOY","difficulty":"medium","type":"true_false","category":"Ships & Technology","question":"Voyager's warp core uses a matter-antimatter reaction like other Federation ships.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Voyager uses a standard deuterium/antideuterium matter-antimatter reactor moderated by dilithium crystals, consistent with other Federation starship designs."},{"id":"VOY-038","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"Species 8472 originates from which realm?","answers":{"A":"A subspace pocket","B":"A transwarp conduit","C":"The Delta Quadrant nebula","D":"Fluidic space"},"correct":"D","explanation":"Species 8472 comes from fluidic space, an alternate dimension consisting entirely of organic fluid, accessed through quantum singularities ('Scorpion,' Parts I and II)."},{"id":"VOY-039","series":"VOY","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Harry Kim is never promoted above Ensign during the entire run of Voyager.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Harry Kim remains an Ensign for all seven seasons of Voyager, a long-running joke among fans and frequently lampooned in the series itself."},{"id":"VOY-040","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Year of Hell,' what weapon does Annorax use to erase civilizations from history?","answers":{"A":"A chronoton torpedo barrage","B":"A temporal displacement cannon","C":"A temporal weapon ship","D":"A time loop device"},"correct":"C","explanation":"Annorax commands a Krenim temporal weapon ship in 'Year of Hell' (Season 4) that uses temporal incursions to erase entire species and civilizations from the timeline."},{"id":"VOY-041","series":"VOY","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Tuvok is Janeway's oldest and most trusted friend, having served with her before Voyager.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Tuvok served with Janeway for years before Voyager and is her most trusted confidant; their long friendship is referenced throughout the series, particularly in episodes like 'Revulsion' and 'Resolutions.'"},{"id":"VOY-042","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"What Delta Quadrant species employs the 'Think Tank' of problem solvers?","answers":{"A":"The Malon","B":"The Think Tank are independent of any species","C":"The Hazari","D":"The Devore"},"correct":"B","explanation":"In 'Think Tank' (Season 5), the group is a collective of unrelated species - led by Kurros (Jason Alexander) - who solve problems for payment and operate independently of any government or species."},{"id":"VOY-043","series":"VOY","difficulty":"medium","type":"true_false","category":"Ships & Technology","question":"Voyager uses a quantum slipstream drive successfully in the episode 'Hope and Fear.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Hope and Fear' (Season 4), Voyager experiments with a quantum slipstream drive on the Arturis-supplied USS Dauntless, traveling 300 light years before the field destabilizes."},{"id":"VOY-044","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the Borg children who are discovered and join Voyager's crew?","answers":{"A":"Naomi and Icheb only","B":"Icheb, Lora, and Tal","C":"Icheb, Mezoti, Rebi, and Azan","D":"Icheb, Seven, and Three of Five"},"correct":"C","explanation":"In 'Collective' (Season 6), Voyager rescues four Borg children - Icheb, Mezoti, and twins Rebi and Azan - from a damaged cube. Icheb remains aboard the longest, becoming Seven's protégé."},{"id":"VOY-045","series":"VOY","difficulty":"medium","type":"true_false","category":"Villains & Antagonists","question":"The Malon are a species responsible for dumping antimatter waste in space.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Malon, introduced in 'Night' (Season 5), are an industrial species whose freighters dump toxic theta radiation waste into uninhabited regions of space, often causing ecological devastation."},{"id":"VOY-046","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Deadlock,' what unusual scenario splits Voyager into two co-existing versions?","answers":{"A":"A transporter accident","B":"Time travel","C":"A mirror universe incursion","D":"A spatial anomaly causes a duplicate Voyager in a parallel dimension"},"correct":"D","explanation":"In 'Deadlock' (Season 2), passing through a plasma cloud creates a duplicate Voyager in a parallel space; one version eventually self-destructs to defeat a Vidiian boarding party, with the Harry Kim and baby Naomi Wildman from the destroyed ship surviving."},{"id":"VOY-047","series":"VOY","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Naomi Wildman is the first child born on Voyager during the journey home.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Naomi Wildman, daughter of Ensign Samantha Wildman and Ktarian Greskrendtregk, is born in 'Deadlock' (Season 2) and is established as the first child born aboard Voyager."},{"id":"VOY-048","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What is the Doctor's default name before he gives himself one?","answers":{"A":"The Doctor (no other name)","B":"Emergency Medical Holographic Program","C":"EMH Mark I","D":"Holodoc"},"correct":"C","explanation":"The Doctor is the EMH Mark I (Emergency Medical Hologram Mark I), the standard designation for Dr. Zimmerman's first-generation holographic medical program installed on Voyager."},{"id":"VOY-049","series":"VOY","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"The Devore are a xenophobic species that hunt telepaths.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Devore Imperium, introduced in 'Counterpoint' (Season 5), is a xenophobic empire that persecutes and detains telepaths; Janeway smuggles Brenari refugees through their space."},{"id":"VOY-050","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"What series finale episode title ends Voyager's journey home?","answers":{"A":"Journey's End","B":"Homecoming","C":"All Good Things","D":"Endgame"},"correct":"D","explanation":"'Endgame,' the two-hour series finale that aired May 23, 2001, depicts Voyager's return to Earth via a Borg transwarp hub with help from a future Admiral Janeway."},{"id":"VOY-051","series":"VOY","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Tom Paris was in a penal colony before joining Voyager.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Tom Paris was incarcerated at the Federation penal settlement in New Zealand when Janeway recruited him as an observer/pilot in 'Caretaker,' offering him a chance at redemption."},{"id":"VOY-052","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"Who is the primary Kazon leader who repeatedly antagonizes Voyager in Seasons 1 and 2?","answers":{"A":"Maje Cullah","B":"Maje Nistrim","C":"Maje Jabin","D":"Maje Razik"},"correct":"A","explanation":"Maje Cullah of the Kazon-Nistrim sect, played by Anthony De Longis, is Seska's ally and Voyager's primary Kazon antagonist, culminating in the 'Basics' two-parter where they briefly capture the ship."},{"id":"VOY-053","series":"VOY","difficulty":"medium","type":"true_false","category":"Ships & Technology","question":"The Doctor can be transmitted to other ships and locations via mobile emitter.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Starting in 'Future's End' (Season 3), the Doctor acquires a 29th-century autonomous mobile emitter that allows him to operate anywhere, freeing him from sickbay and the holodeck."},{"id":"VOY-054","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Timeline & History","question":"The mobile emitter the Doctor uses is from which time period?","answers":{"A":"The 31st century","B":"The 26th century","C":"The 29th century","D":"The 22nd century"},"correct":"C","explanation":"The Doctor's mobile emitter is 29th-century technology obtained from a future timeship in 'Future's End,' representing technology approximately 500 years beyond Voyager's era."},{"id":"VOY-055","series":"VOY","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Seven of Nine's Borg designation was Seven of Nine, Tertiary Adjunct of Unimatrix Zero-One.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Her full Borg designation, established in 'Scorpion, Part II,' is 'Seven of Nine, Tertiary Adjunct of Unimatrix Zero-One,' which is shortened to Seven of Nine after her severance from the Collective."},{"id":"VOY-056","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"The Voth are a proud Delta Quadrant species who believe they originated where?","answers":{"A":"In the Delta Quadrant originally","B":"In the Gamma Quadrant","C":"On Earth, descended from dinosaurs","D":"From a generation ship"},"correct":"C","explanation":"In 'Distant Origin' (Season 3), Voyager's crew helps Voth scientist Forra Gegen prove that the Voth descend from Earth's hadrosaurs that fled before the K-T extinction event, a theory their religious 'Doctrine' suppresses."},{"id":"VOY-057","series":"VOY","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Threshold,' Tom Paris mutates into a salamander-like creature after reaching Warp 10.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Threshold' (Season 2), Paris breaks the transwarp threshold of warp 10 and undergoes a hyper-evolutionary transformation into an amphibious creature; he and Janeway, both mutated, produce offspring together before being restored."},{"id":"VOY-058","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What is Chakotay's spiritual background?","answers":{"A":"Maquis military philosophy","B":"Native American spiritual traditions","C":"Atheism and logic","D":"He follows Bajoran religious customs"},"correct":"B","explanation":"Chakotay is from a fictional Native American colony world and practices spirit-guide traditions, frequently using a medicine wheel and an akoonah device to enter vision quests throughout the series."},{"id":"VOY-059","series":"VOY","difficulty":"medium","type":"true_false","category":"Crossovers & Connections","question":"Q appears in Voyager and brings his son to Janeway to be raised by the crew.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Q2' (Season 7), Q brings his troublesome son (also called Q) to Voyager so Janeway can mentor him; the son was conceived by Q and a female Q in 'The Q and the Grey' (Season 3) to help end the Q Continuum's civil war."},{"id":"VOY-060","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Ships & Technology","question":"What is the name of the ancient Starfleet communication relay network Voyager taps into?","answers":{"A":"The Pathfinder Network","B":"The Federation Beacon System","C":"Starfleet Deep Space Relay Network","D":"The Midas Array via MIDAS and Project Pathfinder"},"correct":"D","explanation":"Starfleet uses the MIDAS array, a deep-space telescope, to bounce a hyper-subspace signal off a pulsar and reach Voyager as part of Project Pathfinder, beginning in the episode 'Pathfinder' (Season 6)."},{"id":"VOY-061","series":"VOY","difficulty":"medium","type":"true_false","category":"Characters & Crew","question":"Lt. Barclay plays a key role on Earth in maintaining contact with Voyager.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"TNG's Reginald Barclay (Dwight Schultz) is the obsessed Starfleet engineer who devises the method to contact Voyager in 'Pathfinder' and becomes a recurring presence in Earth-side episodes like 'Inside Man' and 'Author, Author.'"},{"id":"VOY-062","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Living Witness,' a backup copy of the Doctor is found on an alien world how many years in the future?","answers":{"A":"100 years","B":"700 years","C":"400 years","D":"200 years"},"correct":"B","explanation":"In 'Living Witness' (Season 4), a backup module of the Doctor is reactivated approximately 700 years after Voyager's encounter with the Kyrian and Vaskan peoples, who have built distorted historical reconstructions of Voyager's crew."},{"id":"VOY-063","series":"VOY","difficulty":"medium","type":"true_false","category":"Starfleet Ranks & Protocol","question":"Janeway grants Maquis crew members provisional Starfleet ranks.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Caretaker' and continued in 'Parallax,' Janeway issues field commissions and provisional Starfleet ranks to the Maquis crew (Chakotay as Commander, Torres as Lieutenant) to unify the ships under Starfleet protocol."},{"id":"VOY-064","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What hobby does the Doctor passionately pursue beyond medicine?","answers":{"A":"Painting","B":"Opera singing","C":"Competitive chess","D":"Writing holographic novels"},"correct":"B","explanation":"The Doctor's lifelong passion is opera, central to episodes including 'Virtuoso,' 'Tinker Tenor Doctor Spy,' and many others; Robert Picardo's real-life singing background informs the character."},{"id":"VOY-065","series":"VOY","difficulty":"medium","type":"true_false","category":"Alien Species & Cultures","question":"The Talaxians are a warm and sociable species, fitting Neelix's gregarious personality.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Talaxians, including Neelix and the colony he eventually joins in 'Homestead' (Season 7), are depicted as a warm, family-oriented, and hospitable species."},{"id":"VOY-066","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"What antagonist is responsible for the deaths of Neelix's entire people, the Talaxians of Rinax?","answers":{"A":"The Haakonian Order","B":"The Kazon","C":"The Vidiians","D":"The Hirogen"},"correct":"A","explanation":"In 'Jetrel' (Season 1), the Haakonian Order ended their war with the Talaxians by using the metreon cascade weapon on the moon Rinax, killing Neelix's family and an estimated 300,000 Talaxians."},{"id":"VOY-067","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"What is the name of the Borg transwarp hub that Janeway's future self destroys in 'Endgame'?","answers":{"A":"Transwarp Nexus 9","B":"Unimatrix Zero","C":"The hub has no specific name","D":"Conduit Omega"},"correct":"C","explanation":"In 'Endgame,' the Borg transwarp hub is identified only as one of six in the galaxy ('a transwarp hub') and is never given a unique name in dialogue."},{"id":"VOY-068","series":"VOY","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Seven of Nine's parents were Borg researchers who voluntarily approached the Collective.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Magnus and Erin Hansen, exobiologists, took their daughter Annika on a multi-year expedition aboard the USS Raven to study the Borg, ultimately resulting in the family's assimilation ('The Raven,' 'Dark Frontier')."},{"id":"VOY-069","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Timeless,' a future Harry Kim sends a message back in time to prevent what disaster?","answers":{"A":"A Hirogen attack","B":"Voyager's destruction in a slipstream accident","C":"The Borg assimilation of Voyager","D":"Janeway's death"},"correct":"B","explanation":"In 'Timeless' (the 100th episode), Voyager crashes on an ice planet during a failed quantum slipstream test; 15 years later, Kim and Chakotay use a Borg temporal transmitter to send corrections back in time to prevent the disaster."},{"id":"VOY-070","series":"VOY","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"Unimatrix Zero is a virtual realm where Borg drones retain their individuality while regenerating.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In the 'Unimatrix Zero' two-parter (Seasons 6/7), a small subset of drones with a recessive mutation share a virtual sanctuary during regeneration cycles where they retain individuality and form a secret resistance."},{"id":"VOY-071","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the future Admiral Janeway's ship in 'Endgame'?","answers":{"A":"USS Challenger","B":"USS Admiral","C":"USS Relativity","D":"USS Rhode Island"},"correct":"D","explanation":"In 'Endgame,' future Admiral Janeway borrows the USS Rhode Island (Nova-class, captained by a future Harry Kim) to provide cover during her temporal incursion to alter Voyager's journey home."},{"id":"VOY-072","series":"VOY","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"Voyager briefly uses Borg-derived ablative armor and transphasic torpedoes in 'Endgame.'","answers":{"A":"True","B":"False"},"correct":"B","explanation":"The ablative generator armor and transphasic torpedoes used in 'Endgame' are future Starfleet technology brought back by Admiral Janeway from the late 24th century, not Borg-derived; the Borg consider them entirely unfamiliar."},{"id":"VOY-073","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the Vaadwaur most infamous for historically?","answers":{"A":"Draining stars for fuel","B":"Pirating Borg technology","C":"Using an ancient subspace highway for rapid travel and conquest","D":"Enslaving the Talaxians"},"correct":"C","explanation":"In 'Dragon's Teeth' (Season 6), Voyager revives Vaadwaur soldiers from 900 years of stasis; the species had once used a network of underspace corridors for rapid conquest before being driven to near-extinction."},{"id":"VOY-074","series":"VOY","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Icheb voluntarily donates his cortical node to save Seven of Nine when hers begins to fail.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Imperfection' (Season 7), Icheb risks his life by donating his cortical node to replace Seven's failing one, despite the Doctor's objections; the procedure succeeds and both survive."},{"id":"VOY-075","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Course: Oblivion,' what is the disturbing revelation about the Voyager crew in that episode?","answers":{"A":"They are all holograms","B":"They are biomimetic duplicates created from Silver Blood","C":"They are Hirogen replicas","D":"They are future versions of the crew"},"correct":"B","explanation":"In 'Course: Oblivion' (Season 5), the entire crew is revealed to be silver-blood biomimetic duplicates created in 'Demon' (Season 4); their ship and bodies disintegrate as they vainly attempt to reach Earth."},{"id":"VOY-076","series":"VOY","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"The Intrepid-class can achieve a maximum warp of 9.975.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Stated in 'Caretaker' and confirmed in the Voyager Technical Manual, the Intrepid-class's maximum sustainable cruise velocity is warp 9.975, achievable thanks to its variable-geometry warp nacelles."},{"id":"VOY-077","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the future Admiral Janeway's purpose in traveling back to Voyager's time?","answers":{"A":"To retrieve Seven of Nine for Starfleet","B":"To bring Voyager home sooner and prevent crew deaths","C":"To stop a temporal paradox","D":"To prevent the Borg from winning a war"},"correct":"B","explanation":"In 'Endgame,' Admiral Janeway travels back from a future where Voyager took 23 more years to return home, motivated by losses including Seven, Chakotay, and a debilitated Tuvok."},{"id":"VOY-078","series":"VOY","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"The Krenim are a temporal weapons-using species encountered in the 'Year of Hell' arc.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Krenim Imperium, led by the obsessed historian Annorax in 'Year of Hell, Parts I and II,' employs a chroniton-based temporal weapon ship to erase rivals from history and restore their lost empire."},{"id":"VOY-079","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Timeline & History","question":"In 'Future's End,' Voyager travels back to which decade on Earth?","answers":{"A":"The 1980s","B":"The 1990s","C":"The 2000s","D":"The 1970s"},"correct":"B","explanation":"In 'Future's End' (Season 3), Voyager is pulled to 1996 Los Angeles, where they confront Henry Starling, a tech mogul who built his empire on technology stolen from a crashed 29th-century timeship."},{"id":"VOY-080","series":"VOY","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"The Maquis crew members of Voyager were all initially distrustful of Janeway's authority.","answers":{"A":"True","B":"False"},"correct":"B","explanation":"Not all - some Maquis like Chakotay quickly aligned with Janeway, and the initial planned 'Maquis vs. Starfleet' tension was downplayed by the show's writers in favor of a more unified crew dynamic after the first season."},{"id":"VOY-081","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Muse,' the Doctor's holographic novel leads to a crisis when what happens?","answers":{"A":"An alien race tries to steal his program","B":"A playwright uses B'Elanna and Voyager's logs as the basis for epic drama","C":"Voyager sues the Doctor for breach of privacy","D":"The Doctor's novel gets published and a holographic character in it becomes real"},"correct":"B","explanation":"In 'Muse' (Season 6), B'Elanna crashes on a pre-warp world where a poet named Kelis discovers her and adapts her recovered logs and stories of Voyager into theatrical productions for his patrons."},{"id":"VOY-082","series":"VOY","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"The Vidiians steal organs from other species to combat a fatal disease called the Phage.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Vidiians, introduced in 'Phage' (Season 1), harvest organs and tissue from living victims (called 'donors') to slow the progress of the Phage, a flesh-consuming plague that has ravaged their species for 2,000 years."},{"id":"VOY-083","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What is the name of the holographic character the Doctor names himself after in one episode?","answers":{"A":"Schweitzer","B":"Mozart","C":"Joe","D":"Kenneth"},"correct":"A","explanation":"In 'Heroes and Demons' (Season 1), the Doctor adopts the name 'Schweitzer' (after humanitarian Albert Schweitzer) while inside the Beowulf holodeck program, though he discards it after the experience."},{"id":"VOY-084","series":"VOY","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"In 'Equinox,' the USS Equinox used nucleogenic lifeforms as a fuel source to speed their journey home.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In the 'Equinox' two-parter (Seasons 5/6), Captain Ransom's crew kills nucleogenic lifeforms from another dimension and converts their remains into enhanced warp drive fuel, jumping their ship light years closer to home."},{"id":"VOY-085","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"Which TNG character helps establish the Pathfinder project that contacts Voyager?","answers":{"A":"Data","B":"Geordi La Forge","C":"Reg Barclay","D":"Troi"},"correct":"C","explanation":"Lt. Reginald Barclay, the anxious engineer from TNG, becomes the driving force behind Project Pathfinder in 'Pathfinder' (Season 6), eventually achieving regular communication with Voyager."},{"id":"VOY-086","series":"VOY","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"The Hirogen use holo-technology to recreate historical hunts after obtaining it from Voyager.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'The Killing Game' two-parter (Season 4), Voyager trades holodeck technology to the Hirogen so they can hunt simulated prey, and the technology's misuse is revisited in 'Flesh and Blood' (Season 7)."},{"id":"VOY-087","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Bride of Chaotica!,' the crew must interact with what type of holodeck characters to defeat alien photonic beings?","answers":{"A":"Ancient Romans","B":"Medieval knights","C":"1950s science fiction serial characters","D":" 20th-century noir detectives"},"correct":"C","explanation":"In 'Bride of Chaotica!' (Season 5), the crew exploits Tom Paris's 'Captain Proton' Adventures of Captain Proton, a black-and-white 1930s/50s-style sci-fi serial holoprogram, to drive off photonic beings caught in conflict with Dr. Chaotica."},{"id":"VOY-088","series":"VOY","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"Tuvok mind-melds with a serial killer to understand his violent urges, suffering long-term damage.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Meld' (Season 2), Tuvok mind-melds with crewman Lon Suder, a Betazoid murderer, and inherits violent impulses that destabilize his Vulcan control - one of the darker episodes of the series."},{"id":"VOY-089","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Planets & Locations","question":"What is the name of the Ocampa homeworld that the Caretaker was protecting?","answers":{"A":"Kes'ala","B":"Ocampa Prime","C":"It is unnamed and simply called the Ocampa homeworld","D":"Ocampan IV"},"correct":"C","explanation":"The Ocampa homeworld is referred to throughout 'Caretaker' and subsequent appearances simply as 'the Ocampa homeworld'; no proper planetary name is given in dialogue."},{"id":"VOY-090","series":"VOY","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"The bio-neural gel packs on Voyager can become infected and require medical treatment.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Learning Curve' (Season 1), the bio-neural gel packs are infected by a bacterium originating from Neelix's cheese; the crew cures them by raising the ship's temperature to induce a 'fever' that kills the bacteria, a vulnerability the show repeatedly highlights."},{"id":"VOY-091","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Characters & Crew","question":"What was the name of Naomi Wildman's Ktarian father who she never met?","answers":{"A":"Greskrendtregk","B":"Ensign Wildman","C":"Ktarian Guard Neelan","D":"Lieutenant Ktarian"},"correct":"A","explanation":"Greskrendtregk is the Ktarian husband of Ensign Samantha Wildman and father of Naomi; he remained in the Alpha Quadrant when Voyager was stranded and is referenced in 'Elogium' and 'Mortal Coil.'"},{"id":"VOY-092","series":"VOY","difficulty":"hard","type":"true_false","category":"Timeline & History","question":"In 'Relativity,' Voyager encounters a 29th-century timeship called the USS Relativity.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Relativity' (Season 5), Seven of Nine is recruited by Captain Braxton of the 29th-century Federation timeship USS Relativity to prevent the destruction of Voyager via a temporal weapon."},{"id":"VOY-093","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Latent Image,' the Doctor discovers a suppressed memory of a moral dilemma. What was it?","answers":{"A":"He chose to save Ensign Harry Kim over Ensign Ahni Jetal when only one could survive","B":"He covered up an accidental death","C":"He performed unauthorized surgery on a crew member","D":"He deleted another EMH's program"},"correct":"A","explanation":"Faced with two equally injured patients and only time to save one, the Doctor chose Kim — his friend — over Ensign Jetal. The unresolved guilt fractured his program until Janeway refused to simply delete the memory and instead helped him cope."},{"id":"VOY-094","series":"VOY","difficulty":"hard","type":"true_false","category":"Alien Species & Cultures","question":"The Borg designation for their collective space is 'Borg space' with no other formal name.","answers":{"A":"True","B":"False"},"correct":"B","explanation":"The Borg's territory is organized into numbered Unimatrices (e.g., Unimatrix 01, where the Borg Queen resides as referenced in 'Dark Frontier' and 'Unimatrix Zero'), not just informally 'Borg space.'"},{"id":"VOY-095","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"What is the maximum crew complement of an Intrepid-class starship?","answers":{"A":"141","B":"172","C":"350","D":"257"},"correct":"A","explanation":"Per the Star Trek: Voyager Technical Manual and dialogue throughout the series, the standard Intrepid-class crew complement is 141, though Voyager's actual numbers fluctuate as crew is lost and added during the Delta Quadrant journey."},{"id":"VOY-096","series":"VOY","difficulty":"hard","type":"true_false","category":"Villains & Antagonists","question":"Captain Ransom of the USS Equinox is ultimately killed by the nucleogenic beings he wronged.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Equinox, Part II,' Captain Ransom has a change of heart and tries to evacuate his crew while opening communication with the nucleogenic lifeforms; he goes down with the Equinox during their final attack."},{"id":"VOY-097","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Author, Author,' the Doctor's holographic novel is ruled to be a work of which status?","answers":{"A":"A legally protected autobiography","B":"A banned document","C":"Starfleet property","D":"A protected artistic work, though his personhood status is left unresolved"},"correct":"D","explanation":"In 'Author, Author' (Season 7), the arbitrator rules that the Doctor qualifies as an artist with rights over his work 'Photons Be Free,' but explicitly declines to rule on the broader question of holographic personhood."},{"id":"VOY-098","series":"VOY","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"B'Elanna Torres's Klingon heritage caused her significant personal conflict throughout the series.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"B'Elanna struggles with her Klingon identity throughout the series, in episodes such as 'Faces' (where she is literally split into Klingon and human halves), 'Day of Honor,' 'Barge of the Dead,' and 'Lineage.'"},{"id":"VOY-099","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Crossovers & Connections","question":"Which TNG character appears in Voyager's 'Life Line' episode alongside Reginald Barclay?","answers":{"A":"Miles O'Brien","B":"Geordi La Forge","C":"Lwaxana Troi","D":"Counselor Troi"},"correct":"D","explanation":"In 'Life Line' (Season 6), Counselor Deanna Troi (Marina Sirtis) joins Barclay on Jupiter Station to help the Doctor cope emotionally while treating his dying creator, Dr. Lewis Zimmerman."},{"id":"VOY-100","series":"VOY","difficulty":"hard","type":"true_false","category":"Ships & Technology","question":"Voyager's deflector dish was modified to emit a sustained tachyon beam to detect cloaked ships.","answers":{"A":"True","B":"False"},"correct":"B","explanation":"Voyager rarely encounters cloaked ships in the Delta Quadrant (the Borg, Kazon, Hirogen, etc. do not use cloaking); the tachyon-beam anti-cloak modification was a recurring TNG trope, not a documented Voyager modification."},{"id":"VOY-101","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Which actress plays Captain Kathryn Janeway in Voyager?","answers":{"A":"Jeri Ryan","B":"Kate Mulgrew","C":"Roxann Dawson","D":"Genevieve Bujold"},"correct":"B","explanation":"Kate Mulgrew plays Janeway across all 7 seasons (1995-2001). Genevieve Bujold was originally cast but departed after the first day of filming."},{"id":"VOY-102","series":"VOY","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Tom Paris's father is Admiral Owen Paris, a senior Starfleet officer.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Admiral Owen Paris (later involved with Project Pathfinder) is a strict, traditional officer; much of Tom Paris's rebellious arc is framed against his father's expectations."},{"id":"VOY-103","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"What is Captain Janeway's first name?","answers":{"A":"Kate","B":"Erin","C":"Kathryn","D":"Annika"},"correct":"C","explanation":"Captain Kathryn Janeway commands Voyager throughout the series. Kate is the actress's real name (Kate Mulgrew); Erin is Seven of Nine's mother; Annika is Seven's birth name."},{"id":"VOY-104","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"In which season does Seven of Nine join Voyager's crew?","answers":{"A":"Season 2","B":"Season 3","C":"Season 4","D":"Season 5"},"correct":"C","explanation":"Seven of Nine (Jeri Ryan) joins the cast in the Season 4 opener 'Scorpion, Part II,' after Voyager's temporary alliance with the Borg leaves her severed from the Collective."},{"id":"VOY-105","series":"VOY","difficulty":"medium","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Virtuoso,' the Doctor becomes a famous opera celebrity to an alien race that had never encountered music before.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The Qomar regard the Doctor's singing as the most sophisticated mathematical art they have ever heard; he nearly resigns from Voyager to pursue an opera career before they tire of him."},{"id":"VOY-106","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Scorpion,' Voyager forms an unprecedented temporary alliance with which adversary to survive a greater threat?","answers":{"A":"The Hirogen","B":"The Kazon","C":"The Borg","D":"The Vidiians"},"correct":"C","explanation":"Janeway trades anti-Species-8472 nanoprobe technology to the Borg for safe passage through their space — a controversial deal that also delivers Seven of Nine to the crew."},{"id":"VOY-107","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Tuvix,' Tuvok and Neelix are accidentally merged into a single being. What causes the merge?","answers":{"A":"A subspace anomaly during transport","B":"Sabotage by Seska","C":"A symbiogenetic Delta Quadrant orchid in the transporter buffer","D":"A Borg-modified transporter pattern"},"correct":"C","explanation":"A native plant with symbiogenetic properties merges with Tuvok and Neelix in the transporter beam, producing Tuvix. Janeway later forcibly separates him in a famously controversial ethical decision."},{"id":"VOY-108","series":"VOY","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Drone,' Seven of Nine's Borg nanoprobes merge with the Doctor's mobile emitter to create an advanced 29th-century Borg drone named One.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"A transporter accident in 'Drone' (Season 5) fuses Seven's nanoprobes with the 29th-century mobile emitter, producing 'One' — a far more advanced drone than anything the contemporary Collective fields. He sacrifices himself to avoid being assimilated."},{"id":"VOY-109","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"The Krenim of 'Year of Hell' specialize in what kind of weapons technology?","answers":{"A":"Genetic toxins","B":"Temporal (chroniton-based) weapons that erase enemies from history","C":"Subspace warheads","D":"Tachyon disruptors"},"correct":"B","explanation":"Annorax's temporal weapon ship fires chroniton incursions that retroactively delete civilizations from history — including, repeatedly, Voyager itself."},{"id":"VOY-110","series":"VOY","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Endgame,' a future Admiral Janeway travels back in time to help her past self bring Voyager home decades earlier than the original timeline.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Admiral Janeway, who arrived home after 23 more years of attrition and lost crew, breaks the Temporal Prime Directive to help Voyager return via a Borg transwarp hub — a paradox that overwrites the original future."},{"id":"VOY-111","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Quotes & Catchphrases","question":"What standing order does Janeway give regarding the conservation of replicator energy early in the series?","answers":{"A":"Replicator rations","B":"Power conservation protocol","C":"Energy lockdown","D":"Fuel restriction directive"},"correct":"A","explanation":"Because Voyager cannot resupply in the Delta Quadrant, the crew is placed on replicator rations, which is why Neelix's galley becomes the ship's primary food source ('Caretaker' onward)."},{"id":"VOY-112","series":"VOY","difficulty":"easy","type":"true_false","category":"Quotes & Catchphrases","question":"The Doctor frequently opens his appearances with the phrase 'Please state the nature of the medical emergency.'","answers":{"A":"True","B":"False"},"correct":"A","explanation":"As the Emergency Medical Hologram, the Doctor's automatic activation line is 'Please state the nature of the medical emergency,' a recurring catchphrase from the pilot 'Caretaker' onward."},{"id":"VOY-113","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Quotes & Catchphrases","question":"What Borg phrase do the Collective use when first confronting their targets?","answers":{"A":"You will be assimilated","B":"Surrender your vessel","C":"Resistance is futile","D":"We are the Collective"},"correct":"C","explanation":"'Resistance is futile' is the Borg's signature declaration, heard repeatedly in Voyager's Borg-centered episodes such as 'Scorpion' and 'Dark Frontier.'"},{"id":"VOY-114","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Planets & Locations","question":"In which quadrant of the galaxy is Voyager stranded?","answers":{"A":"Alpha Quadrant","B":"Beta Quadrant","C":"Gamma Quadrant","D":"Delta Quadrant"},"correct":"D","explanation":"Voyager is pulled into the Delta Quadrant by the Caretaker in the pilot, far from the Alpha Quadrant home of the Federation."},{"id":"VOY-115","series":"VOY","difficulty":"easy","type":"true_false","category":"Planets & Locations","question":"Voyager's journey begins in the Badlands, a region of space near Cardassian and Bajoran territory.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Caretaker,' Voyager enters the plasma-storm-filled Badlands to search for Chakotay's missing Maquis ship before both vessels are swept to the Delta Quadrant."},{"id":"VOY-116","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Planets & Locations","question":"Where was Voyager built and launched from?","answers":{"A":"Utopia Planitia Fleet Yards, Mars","B":"San Francisco Fleet Yards, Earth","C":"Starbase 74","D":"Deep Space 9"},"correct":"A","explanation":"The USS Voyager was constructed at the Utopia Planitia Fleet Yards in orbit of Mars, the Federation's primary starship construction facility."},{"id":"VOY-117","series":"VOY","difficulty":"easy","type":"true_false","category":"Starfleet Ranks & Protocol","question":"Tuvok holds the rank of Lieutenant Commander for most of the series before being promoted.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Tuvok serves as a Lieutenant Commander and is promoted to full Commander by Janeway in the seventh-season episode 'Renaissance Man.'"},{"id":"VOY-118","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"What rank does Tom Paris hold for most of the series as Voyager's helmsman?","answers":{"A":"Ensign","B":"Lieutenant","C":"Commander","D":"Lieutenant Commander"},"correct":"B","explanation":"Paris is given the rank of Lieutenant when recruited; he is briefly demoted to Ensign in 'Thirty Days' (Season 5) before earning his rank back."},{"id":"VOY-119","series":"VOY","difficulty":"easy","type":"true_false","category":"Timeline & History","question":"At maximum speeds, Janeway estimates the journey home would take about 75 years.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Caretaker,' Janeway tells the crew that covering the roughly 70,000 light years back to the Alpha Quadrant would take approximately 75 years at maximum warp."},{"id":"VOY-120","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Timeline & History","question":"How many years does Voyager's journey home actually take before the crew returns in 'Endgame'?","answers":{"A":"5 years","B":"7 years","C":"10 years","D":"23 years"},"correct":"B","explanation":"Thanks to numerous shortcuts and Admiral Janeway's intervention, Voyager makes it home in seven years rather than the originally estimated 75."},{"id":"VOY-121","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Alien Species & Cultures","question":"What is the name of Kes's species?","answers":{"A":"Talaxian","B":"Ocampa","C":"Kazon","D":"Nacene"},"correct":"B","explanation":"Kes is an Ocampa, the short-lived species that lived underground and was cared for by the Caretaker, as established in 'Caretaker.'"},{"id":"VOY-122","series":"VOY","difficulty":"easy","type":"true_false","category":"Characters & Crew","question":"Kes and Neelix are romantically involved during Kes's time aboard Voyager.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Kes and Neelix arrive together as a couple in 'Caretaker' and remain romantically involved for much of Kes's run, though their relationship later ends before she departs in 'The Gift.'"},{"id":"VOY-123","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Ships & Technology","question":"What kind of small auxiliary craft does Tom Paris design and build aboard Voyager?","answers":{"A":"The Delta Flyer","B":"The Aeroshuttle","C":"The Cochrane","D":"A captain's yacht"},"correct":"A","explanation":"The Delta Flyer, designed largely by Tom Paris, is a custom shuttle built by the crew in 'Extreme Risk' (Season 5) and used on many subsequent missions."},{"id":"VOY-124","series":"VOY","difficulty":"easy","type":"true_false","category":"Episodes & Story Arcs","question":"Seven of Nine regenerates in a Borg alcove rather than sleeping in a conventional bed.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Because of her Borg physiology, Seven regenerates in a specially installed alcove in Cargo Bay 2, a recurring detail introduced after she joins the crew in Season 4."},{"id":"VOY-125","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"In 'The 37's,' Voyager discovers humans abducted from Earth in what year?","answers":{"A":"1937","B":"1947","C":"1969","D":"1996"},"correct":"A","explanation":"In 'The 37's' (Season 2), Voyager finds humans abducted from Earth in 1937, including aviator Amelia Earhart, who had been taken by the Briori centuries earlier."},{"id":"VOY-126","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Planets & Locations","question":"What is the name of the desert planet where Voyager establishes a settlement after the crew is exiled in 'Basics, Part II'?","answers":{"A":"Hanon IV","B":"Sikaris","C":"Tarok","D":"Ocampa"},"correct":"A","explanation":"In 'Basics, Part II' (Season 3), the Kazon strand the crew on the primitive planet Hanon IV, where they must survive among volcanic terrain and hostile natives until they retake the ship."},{"id":"VOY-127","series":"VOY","difficulty":"medium","type":"true_false","category":"Planets & Locations","question":"In 'Sacred Ground,' Janeway undergoes a spiritual trial on a planet to save Kes's life.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Sacred Ground' (Season 3), Kes is injured by an energy field at a sacred shrine, and Janeway must complete a ritual ordeal among the Nechani monks to win her recovery."},{"id":"VOY-128","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Starfleet Ranks & Protocol","question":"In 'Thirty Days,' why is Tom Paris demoted to Ensign and confined to the brig?","answers":{"A":"He disobeyed orders to protect an alien ocean world","B":"He stole the Delta Flyer","C":"He attacked a fellow officer","D":"He leaked classified logs"},"correct":"A","explanation":"In 'Thirty Days' (Season 5), Paris defies Janeway's orders by trying to stop the destruction of a Monean ocean-world, earning a demotion to Ensign and 30 days in the brig."},{"id":"VOY-129","series":"VOY","difficulty":"medium","type":"true_false","category":"Starfleet Ranks & Protocol","question":"Janeway holds the rank of Captain throughout Voyager's journey and is promoted to Vice Admiral only after returning home.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Janeway commands as a Captain for the entire Delta Quadrant journey; her promotion to Vice Admiral is established afterward, reflected by her rank in Star Trek Nemesis and referenced in 'Endgame.'"},{"id":"VOY-130","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Timeline & History","question":"In 'Eye of the Needle,' Voyager makes contact through a wormhole with a Romulan from which time period relative to Voyager?","answers":{"A":"The distant future","B":"Twenty years in Voyager's past","C":"The same time period","D":"The 22nd century"},"correct":"B","explanation":"In 'Eye of the Needle' (Season 1), the micro-wormhole connects to a Romulan scientist named Telek R'Mor, who exists about twenty years before Voyager's present, dashing hopes of an immediate trip home."},{"id":"VOY-131","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Quotes & Catchphrases","question":"What blunt assessment does Seven of Nine often give about human behavior she finds inefficient?","answers":{"A":"'That is irrelevant.'","B":"'Fascinating.'","C":"'Make it so.'","D":"'The needs of the many...'"},"correct":"A","explanation":"Seven of Nine frequently dismisses things she considers unimportant with a flat 'That is irrelevant,' reflecting her lingering Borg directness across her Season 4-7 appearances."},{"id":"VOY-132","series":"VOY","difficulty":"medium","type":"true_false","category":"Quotes & Catchphrases","question":"Neelix's homecooked dish 'leola root' is referenced repeatedly as an unpopular ingredient among the crew.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Leola root, a nutritious but unappetizing Delta Quadrant vegetable that Neelix insists on using, becomes a running joke about his cooking throughout the series."},{"id":"VOY-133","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"What new ability does Kes develop that ultimately leads to her leaving Voyager in 'The Gift'?","answers":{"A":"Time travel","B":"Rapidly growing telepathic and telekinetic powers","C":"Borg assimilation immunity","D":"Shapeshifting"},"correct":"B","explanation":"In 'The Gift' (Season 4), Kes's escalating mental powers begin to threaten the ship, and she evolves into a higher form of energy, propelling Voyager 9,500 light years closer to home as she departs."},{"id":"VOY-134","series":"VOY","difficulty":"medium","type":"true_false","category":"Crossovers & Connections","question":"In 'Flashback,' Tuvok recalls serving aboard the USS Excelsior under Captain Hikaru Sulu.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"The 30th-anniversary episode 'Flashback' (Season 3) reveals Tuvok served aboard the Excelsior under Captain Sulu (George Takei) during the events surrounding Star Trek VI: The Undiscovered Country."},{"id":"VOY-135","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Villains & Antagonists","question":"What weakness do the Kazon notably lack that keeps them technologically behind Voyager?","answers":{"A":"Warp drive","B":"The ability to replicate water","C":"Functional weapons","D":"Spaceflight"},"correct":"B","explanation":"The Kazon famously covet Federation replicator technology because they cannot reliably produce water, a vulnerability central to Seska's scheming in episodes like 'State of Flux.'"},{"id":"VOY-136","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'Mortal Coil,' which character dies and is revived by Seven's Borg nanoprobes, then struggles with a crisis of faith?","answers":{"A":"Harry Kim","B":"Neelix","C":"Chakotay","D":"Tom Paris"},"correct":"B","explanation":"In 'Mortal Coil' (Season 4), Neelix dies on an away mission and is resurrected with Borg nanoprobes; experiencing no afterlife shatters his Talaxian religious beliefs and drives him to the brink of suicide."},{"id":"VOY-137","series":"VOY","difficulty":"medium","type":"true_false","category":"Ships & Technology","question":"The astrometrics lab, built by Seven of Nine and Harry Kim, dramatically improves Voyager's stellar navigation.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Year of Hell' (Season 4), Seven and Kim design and build the astrometrics lab, whose advanced sensors help chart safer, faster courses through the Delta Quadrant."},{"id":"VOY-138","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Alien Species & Cultures","question":"In 'Cold Fire,' Voyager encounters the Caretaker's mate, a second Nacene entity. What is her name?","answers":{"A":"Suspiria","B":"Sublimia","C":"Ocampa","D":"Tanis"},"correct":"A","explanation":"In 'Cold Fire' (Season 2), Voyager locates Suspiria, the female Caretaker and mate of the entity that stranded them. She protects a different group of Ocampa aboard a space station called Exosia; Tanis is the Ocampan who serves her, not the Caretaker herself."},{"id":"VOY-139","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Timeline & History","question":"In 'Before and After,' Kes experiences her life out of sequence due to what condition?","answers":{"A":"A transporter malfunction","B":"A chroniton-radiation effect causing her to move backward through her own timeline","C":"A Borg neural implant","D":"A holodeck accident"},"correct":"B","explanation":"In 'Before and After' (Season 3), chroniton radiation from a future Krenim weapon causes Kes to jump backward through the stages of her life, foreshadowing the later 'Year of Hell' arc."},{"id":"VOY-140","series":"VOY","difficulty":"hard","type":"true_false","category":"Timeline & History","question":"In 'Shattered,' Chakotay moves through different time periods of Voyager that coexist in separate sections of the ship.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Shattered' (Season 7), a spatial rift fractures Voyager into 37 different time frames; Chakotay, immune to the effect, travels between eras to enlist a past version of Janeway to repair the ship."},{"id":"VOY-141","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Planets & Locations","question":"In 'Gravity,' Tuvok, Tom Paris, and the Doctor crash on a planet inside what unusual region of space?","answers":{"A":"A nebula","B":"A subspace sinkhole where time runs faster","C":"A Borg debris field","D":"Fluidic space"},"correct":"B","explanation":"In 'Gravity' (Season 5), the away team is trapped on a desert world inside a subspace sinkhole where time passes far more quickly than outside, complicating Voyager's rescue effort."},{"id":"VOY-142","series":"VOY","difficulty":"hard","type":"true_false","category":"Starfleet Ranks & Protocol","question":"In 'Worst Case Scenario,' a Starfleet holonovel about a Maquis mutiny aboard Voyager becomes a popular crew pastime.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Worst Case Scenario' (Season 3), Tuvok's unfinished training scenario about a Maquis uprising is discovered and enjoyed by the crew, before Seska's sabotage turns it deadly."},{"id":"VOY-143","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"In 'Nemesis,' Chakotay is psychologically conditioned by which warring species to hate their enemy?","answers":{"A":"The Vori","B":"The Kradin","C":"The Devore","D":"The Swarm"},"correct":"A","explanation":"In 'Nemesis' (Season 4), Chakotay is brainwashed by the Vori into seeing the Kradin as monstrous enemies, exploring how propaganda manufactures hatred in wartime."},{"id":"VOY-144","series":"VOY","difficulty":"hard","type":"true_false","category":"Crossovers & Connections","question":"In 'Death Wish,' a rogue Q seeks asylum aboard Voyager so that he may end his immortal existence.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Death Wish' (Season 2), a Q known as Quinn asks Janeway for asylum to commit suicide and escape eternal life, leading to a hearing that draws in the familiar Q (John de Lancie)."},{"id":"VOY-145","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Episodes & Story Arcs","question":"In 'The Voyager Conspiracy,' Seven of Nine becomes consumed by paranoid theories after doing what?","answers":{"A":"Mind-melding with Tuvok","B":"Assimilating data directly through her alcove while regenerating","C":"Reading the Doctor's holonovel","D":"Linking to a Borg cube"},"correct":"B","explanation":"In 'The Voyager Conspiracy' (Season 6), Seven modifies her alcove to absorb information while regenerating, but the data overload causes her to construct elaborate, contradictory conspiracy theories about the crew."},{"id":"VOY-146","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Villains & Antagonists","question":"In 'Living Witness,' the reactivated Doctor backup is accused by the Kyrians of being part of a brutal warship's crew. What was Voyager falsely portrayed as?","answers":{"A":"A peaceful trading vessel","B":"A genocidal warship called the 'Warship Voyager'","C":"A Borg cube","D":"A Hirogen hunting ship"},"correct":"B","explanation":"In 'Living Witness' (Season 4), Kyrian historians have reconstructed a distorted history casting Voyager as the brutal 'Warship Voyager' and its crew as war criminals, which the Doctor's backup must correct."},{"id":"VOY-147","series":"VOY","difficulty":"hard","type":"true_false","category":"Characters & Crew","question":"In 'Lineage,' B'Elanna Torres wants to genetically alter her unborn daughter to remove her Klingon traits.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Lineage' (Season 7), a pregnant B'Elanna, fearing her daughter will face the rejection she suffered, secretly schemes to have the Doctor genetically remove the child's Klingon characteristics before reconciling."},{"id":"VOY-148","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Ships & Technology","question":"In 'Renaissance Man,' the Doctor impersonates several crew members to carry out a hostage demand. What did the aliens want?","answers":{"A":"Voyager's warp core","B":"The Doctor's mobile emitter","C":"Seven of Nine","D":"The astrometrics database"},"correct":"A","explanation":"In 'Renaissance Man' (Season 7), the R'Kaal hold Janeway hostage, and the Doctor, believing her life is at stake, schemes to surrender Voyager's warp core while impersonating various crew members."},{"id":"VOY-149","series":"VOY","difficulty":"hard","type":"multiple_choice","category":"Alien Species & Cultures","question":"In 'Tsunkatse,' Seven of Nine is forced to fight in alien gladiatorial matches alongside a guest character played by which famous wrestler?","answers":{"A":"Hulk Hogan","B":"The Rock (Dwayne Johnson)","C":"Stone Cold Steve Austin","D":"Andre the Giant"},"correct":"B","explanation":"In 'Tsunkatse' (Season 6), Seven is forced into Penk's combat arena; pro wrestler The Rock (Dwayne Johnson) appears as a Pendari champion she must fight."},{"id":"VOY-150","series":"VOY","difficulty":"hard","type":"true_false","category":"Episodes & Story Arcs","question":"In 'Blink of an Eye,' the rapidly evolving planetary civilization eventually launches astronauts who briefly visit Voyager.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In 'Blink of an Eye' (Season 6), the planet's civilization advances to spaceflight and sends astronauts to the ship that has loomed in their sky for generations, with one even living aboard Voyager for a time."},{"id":"VOY-151","series":"VOY","difficulty":"easy","type":"multiple_choice","category":"Characters & Crew","question":"Which actress plays Seven of Nine on Star Trek: Voyager?","answers":{"A":"Jeri Ryan","B":"Roxann Dawson","C":"Jennifer Lien","D":"Kate Mulgrew"},"correct":"A","explanation":"Jeri Ryan portrays Seven of Nine, joining the cast in the Season 4 premiere 'Scorpion, Part II' and remaining through the end of the series."},{"id":"VOY-152","series":"VOY","difficulty":"easy","type":"true_false","category":"Alien Species & Cultures","question":"In 'Caretaker,' the Caretaker entity communicates with Voyager's crew by appearing as an elderly human man playing a banjo.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"In the pilot 'Caretaker,' the Nacene entity (nicknamed the 'Banjo Man') presents itself to the crew as a grizzled old human strumming a banjo on a recreated farm."},{"id":"VOY-153","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Ships & Technology","question":"What was the name of the Maquis raider, commanded by Chakotay, that was pulled into the Delta Quadrant alongside Voyager?","answers":{"A":"Val Jean","B":"Liberty","C":"Geronimo","D":"Crazy Horse"},"correct":"A","explanation":"In 'Caretaker,' Chakotay's Maquis ship was the Val Jean; he later rammed it into a Kazon vessel, after which his crew joined Voyager."},{"id":"VOY-154","series":"VOY","difficulty":"medium","type":"multiple_choice","category":"Characters & Crew","question":"Why does the Emergency Medical Hologram become Voyager's permanent chief medical officer?","answers":{"A":"The ship's doctor and medical staff are killed in the pilot","B":"Janeway prefers a holographic physician","C":"The Doctor volunteers to replace a retiring CMO","D":"The original doctor defects to the Maquis"},"correct":"A","explanation":"In 'Caretaker,' Voyager's flesh-and-blood medical staff are killed when the ship is hurled to the Delta Quadrant, forcing the EMH (the Doctor) to serve as the permanent CMO."},{"id":"VOY-155","series":"VOY","difficulty":"hard","type":"true_false","category":"Starfleet Ranks & Protocol","question":"In addition to being chief of security and tactical officer, Tuvok also serves as Voyager's second officer.","answers":{"A":"True","B":"False"},"correct":"A","explanation":"Tuvok holds the posts of chief of security and chief tactical officer while also serving as Voyager's second officer, behind Captain Janeway and first officer Chakotay."}];
